window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["artifacts"]={"updatedAt":"2026-07-14","count":216,"artifacts":[{"id":"dan-duoc-truc-co-ky","name":"Hai bình đan dược Trúc Cơ kỳ","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Đỉnh cấp","soHuu":["Mai Ngưng"],"trangThai":"đã tặng","blurb":"Đan dược đỉnh cấp Trúc Cơ kỳ luyện từ yêu đan, Hàn Lập tặng Mai Ngưng trả ân tình Thông Linh Khí.","detail":"Hàn Lập luyện chế từ yêu đan, có tác dụng tăng tiến tu vi Trúc Cơ kỳ. Đối với tu sĩ Kết Đan kỳ như Hàn Lập đã không còn tác dụng. Tặng cho Mai Ngưng để trả nhân tình nàng từng truyền Thông Linh Khí.","congNang":["Tăng tiến tu vi Trúc Cơ kỳ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0594","denChuong":"@c0594","cachCoDuoc":"Tự luyện chế","trangThai":"đã tặng"},{"ten":"Mai Ngưng","tuChuong":"@c0594","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập tặng Mai Ngưng","text":"Hàn Lập tặng hai bình đan dược Trúc Cơ kỳ đỉnh cấp cho Mai Ngưng để trả ân tình Thông Linh Khí.","anchor":"Trong bình là đan dược Trúc Cơ kỳ, hôm nay đối với Hàn Lập mà nói đã không còn"}]},"nguon":["@c0594"]},{"id":"dinh-linh-dan","name":"Định Linh Đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thánh dược","soHuu":[],"trangThai":"chưa luyện","blurb":"Định Linh Đan là thánh dược hỗ trợ ngưng kết Nguyên Anh, có công năng tăng tiến tu vi, định tâm an hồn và giảm bớt tâm ma xâm nhập trong quá trình đột phá. Thuốc dẫn bắt buộc để luyện chế là Thuần dịch chiết từ Linh Nhãn Chi Thụ.","detail":"Đan dược nổi danh trong tu tiên giới, được xem là thánh dược dành cho tu sĩ chuẩn bị ngưng kết Nguyên Anh. Uống trước khi đột phá sẽ khiến toàn bộ quá trình ngưng kết dễ dàng hơn không ít nhờ ba tác dụng chính: tăng tiến tu vi, định tâm an hồn và giảm bớt tâm ma xâm nhập. Điều kiện luyện chế khắt khe bởi thuốc dẫn bắt buộc là Thuần dịch — linh dịch chảy ra từ rễ Linh Nhãn Chi Thụ, loại thần thụ sinh trưởng tại Vân Mộng, mỗi hai trăm năm mới tiết dịch một lần (@c0594).","congNang":["Tăng tiến tu vi, hỗ trợ quá trình ngưng kết Nguyên Anh (@c0594)","Định tâm an hồn, giữ thần thức ổn định khi đột phá (@c0594)","Giảm bớt tâm ma xâm nhập trong lúc ngưng kết Nguyên Anh (@c0594)"],"dacDiem":"Cần Thuần dịch từ Linh Nhãn Chi Thụ làm thuốc dẫn; Thuần dịch chỉ tiết ra từ rễ Linh Nhãn Chi Thụ ở Vân Mộng mỗi hai trăm năm một lần","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ thông tin","text":"Hé lộ Định Linh Đan là thánh dược hỗ trợ ngưng kết Nguyên Anh, cần Thuần dịch từ Linh Nhãn Chi Thụ ở Vân Mộng Sơn làm thuốc dẫn.","anchor":"Nếu là lúc ngưng kết Nguyên Anh trước đó uống vào một viên, tuyệt đối có thể khiến cho tu sĩ ngưng kết Nguyên Anh cảm thấy dễ dàng không ít"}]},"nguon":["@c0594"]},{"id":"linh-nhan-chi-thu","name":"Linh Nhãn Chi Thụ","category":"khac","categoryLabel":"Thần mộc","phamCap":"Đại thần mộc","soHuu":[],"trangThai":"tồn tại","blurb":"Linh Nhãn Chi Thụ là một trong ba đại thần mộc cuối cùng còn tồn tại trong tu tiên giới, tọa lạc sâu trong Vân Mộng Sơn. Giá trị của nó được đánh giá cao hơn cả Thiên Lôi Trúc và Dưỡng Hồn Mộc, do ba tông phái Cổ Kiếm Viện, Lạc Vân Tông và Bách Xảo Viện liên hợp chiếm cứ bảo vệ.","detail":"Linh Nhãn Chi Thụ được xếp vào hàng đại thần mộc, thuộc nhóm ba cây thần mộc cuối cùng còn sót lại trong tu tiên giới. Cây nằm ở vị trí sâu trong Vân Mộng Sơn, nơi ba đại tông phái — Cổ Kiếm Viện, Lạc Vân Tông và Bách Xảo Viện — liên hợp chiếm cứ và canh giữ. Về giá trị, Linh Nhãn Chi Thụ được xem là vượt trội hơn hai đại thần mộc còn lại là Thiên Lôi Trúc và Dưỡng Hồn Mộc. Mỗi hai trăm năm, từ bộ rễ của cây sẽ tiết ra Thuần dịch — một loại nguyên liệu tuyệt hảo, đặc biệt được dùng làm thuốc dẫn cho Định Linh Đan.","congNang":["Sản sinh Thuần dịch mỗi 200 năm từ bộ rễ — nguyên liệu tuyệt hảo, đặc biệt là thuốc dẫn cho Định Linh Đan @c0594"],"dacDiem":"Một trong ba đại thần mộc cuối cùng trong tu tiên giới, giá trị cao hơn Thiên Lôi Trúc và Dưỡng Hồn Mộc, do ba tông phái Cổ Kiếm Viện, Lạc Vân Tông, Bách Xảo Viện liên hợp chiếm cứ bảo vệ tại Vân Mộng Sơn.","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ thông tin","text":"Giới thiệu Linh Nhãn Chi Thụ là một trong ba đại thần mộc cuối cùng, nằm sâu trong Vân Mộng Sơn, mỗi 200 năm chảy Thuần dịch làm thuốc dẫn Định Linh Đan.","anchor":"một trong ba đại thần mộc cuối cùng trong tu tiên giới"}]},"nguon":["@c0594"]},{"id":"thuan-dich","name":"Thuần dịch","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tuyệt hảo","soHuu":[],"trangThai":"tồn tại","blurb":"Linh dịch chảy từ rễ Linh Nhãn Chi Thụ mỗi 200 năm, không thể trực tiếp phục dụng, là thuốc dẫn cho Định Linh Đan.","detail":"Nguyên liệu tuyệt hảo luyện linh dược, đặc biệt là thuốc dẫn bắt buộc cho Định Linh Đan. Không thể trực tiếp phục dụng. Mỗi hai trăm năm Linh Nhãn Chi Thụ mới chảy ra một lần từ bộ rễ.","congNang":["Nguyên liệu luyện linh dược","Thuốc dẫn cho Định Linh Đan"],"tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ thông tin","text":"Giới thiệu Thuần dịch là linh dịch chảy từ rễ Linh Nhãn Chi Thụ mỗi 200 năm, thuốc dẫn cho Định Linh Đan.","anchor":"Linh Nhãn Chi Thụ sẽ từ bộ rễ chảy ra một loại linh dịch gọi là “Thuần dịch”"}]},"nguon":["@c0594"]},{"id":"tran-ky-mau-xanh","name":"Trận kỳ màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Du sư đệ"],"trangThai":"dang-co","blurb":"Trận kỳ dùng để mở thông đạo xuyên qua đại trận hộ phái Lạc Vân Tông, phát ra mũi tên nhọn màu xanh nhạt bắn xuyên sương mù.","detail":"Du sư đệ lấy từ Túi Trữ Vật, đọc khẩu quyết khiến trận kỳ phát mũi tên nhọn màu xanh nhạt bắn xuyên sương mù, mở thông đạo rộng hai ba trượng xuyên qua đại trận hộ phái Lạc Vân Tông. Thông đạo tự khép lại phía sau khi đoàn người đi qua.","congNang":["Mở thông đạo xuyên đại trận hộ phái Lạc Vân Tông @c0597"],"chuSoHuu":[{"ten":"Du sư đệ","tuChuong":"@c0597","denChuong":"","cachCoDuoc":"Sở hữu sẵn (đệ tử Lạc Vân Tông)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0597","loai":"dùng","importance":"normal","giaiDoan":"Mở đại trận hộ phái đưa nhóm tân đệ tử vào","text":"Du sư đệ dùng trận kỳ đọc khẩu quyết, phát mũi tên nhọn xanh nhạt bắn xuyên sương mù, mở thông đạo rộng hai ba trượng để đoàn người xuyên qua đại trận hộ phái Lạc Vân Tông.","anchor":"cái trận kỳ màu xanh trong tay bắt đầu xuất hiện ra một mũi tên nhọn màu xanh nhạt"}]},"nguon":["@c0597"]},{"id":"van-tam-phu","name":"Vấn Tâm Phù","cn":"問心符","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Miêu sư huynh"],"trangThai":"dang-dung","blurb":"Ngân phù chói mắt dài khoảng một gang tay, dùng phối hợp Vấn Tâm Thuật để kiểm tra tâm ý tân đệ tử Lạc Vân Tông.","detail":"Do Miêu sư huynh chuẩn bị đúng bảy cái cho bảy tán tu. Được áp lên vai phải từng người, khi phát tác thì ngân quang đại thịnh rồi lập lòe sáng tối, báo hiệu người đó lên lầu hai chịu kiểm tra.","congNang":["Phối hợp Vấn Tâm Thuật kiểm tra tâm ý người đeo","Phát sáng khi kích hoạt báo hiệu thứ tự kiểm tra"],"dacDiem":"Ngân phù, dài khoảng một gang tay, phát ngân quang khi kích hoạt","tabs":{"tienTrinh":[{"chuong":"@c0598","loai":"dùng","importance":"normal","giaiDoan":"Kiểm tra nhập môn Lạc Vân Tông","text":"Bảy Vấn Tâm Phù được Miêu sư huynh giao cho Du sư đệ áp lên vai phải bảy tán tu mới. Phù của Hàn Lập phát sáng đầu tiên, hắn là người đầu tiên lên lầu hai chịu kiểm tra.","anchor":"Hàn Lập mới nghiêng đầu một cái rồi nhìn cái phù màu bạc dài khoảng một gang tay"}]},"nguon":["@c0598"]},{"id":"dia-hoang-tinh","name":"Địa Hoàng Tinh","cn":"地黄精","aliases":["Hoàng Tinh"],"category":"khac","categoryLabel":"Linh thảo","phamCap":"Trên 50 năm tuổi giá hơn 30 khối linh thạch","soHuu":[],"trangThai":"dang-co","blurb":"Linh dược lâu năm, dị chủng Tuyết Vân Hồ cực kỳ thích ăn. Cần loại trên năm mươi năm tuổi mới đủ dụ nó ra khỏi hang bùn.","detail":"Linh thảo có nhiều loại niên hạn khác nhau. Loại trên mười năm tuổi giá mười mấy khối linh thạch, loại trên năm mươi năm giá hơn ba mươi khối. Dược viên của Hàn Lập tại Thiên Tuyền Phong có hai cây trên năm mươi năm tuổi. Khuê Hoán xin mượn nhưng bị Hàn Lập từ chối vì không có tư cách tự ý sử dụng linh dược trong vườn.","congNang":["Mồi nhử dị chủng Tuyết Vân Hồ"],"tabs":{"tienTrinh":[{"chuong":"@c0603","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến như mồi nhử Tuyết Vân Hồ","text":"Khuê Hoán đến dược viên xin mượn Địa Hoàng Tinh trên năm mươi năm để dụ dị chủng Tuyết Vân Hồ, bị Hàn Lập từ chối cho mượn linh dược nhưng cho mượn linh thạch để tự mua.","anchor":"muốn đem con thú này dẫn dụ ra thì tối thiểu cũng cần Địa Hoàng Tinh ngoài năm mươi năm"}]},"nguon":["@c0603"]},{"id":"linh-nhan-chi-ngoc","name":"Linh Nhãn Chi Ngọc","cn":"灵眼之玉","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Cao cấp nhất trong các loại linh nhãn chi thạch","soHuu":["Hắc y thiếu phụ"],"trangThai":"Đề nghị cho Hàn Lập mượn, chưa chính thức chuyển giao","blurb":"Bảo vật cao cấp nhất trong các loại linh nhãn chi thạch, nằm trong hộp ngọc đen cổ, do hắc y thiếu phụ Nguyên Anh kỳ sở hữu.","detail":"Loại linh nhãn chi thạch cao cấp nhất, được hắc y thiếu phụ cất giữ trong hộp ngọc đen cổ. Công năng: giúp giai đoạn giả anh trước Kết Anh ổn định thêm ba phần, ngưng kết Nguyên Anh dễ dàng hơn, rút ngắn quá trình tu luyện khoảng ba lần. Thiếu phụ đề nghị cho Hàn Lập mượn với điều kiện dùng xong phải trả nguyên vẹn và giúp bà chuyển một tín hàm cho một người nào đó.","nguon":["@c0607"]},{"id":"hap-linh-thach","name":"Hấp Linh thạch","cn":"青金石","aliases":["Thanh Kim thạch"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu luyện khí trân quý, gần thất truyền","soHuu":[],"trangThai":"Cấu thành vách tường thạch thất trong mật cảnh","blurb":"Loại đá cực hiếm còn gọi là Thanh Kim thạch, miễn dịch linh lực và tự phục hồi, được dùng xây cả một thạch thất trong mật cảnh ba phái.","detail":"Tài liệu luyện khí vô cùng trân quý, ngoài tự nhiên cực hiếm, gần như thất truyền và không còn mấy người biết đến. Đặc tính: kiếm mang công kích không để lại vết xước, phi kiếm bắn vào chỉ tạo lỗ nhỏ sâu một tấc rồi tự liền lại, ngoài lực cực mạnh phá hỏng thì không gì tác động được kể cả linh lực. Vách tường thạch thất nơi hắc y thiếu phụ ẩn tu được tạo hoàn toàn từ loại đá này, thô sơ lồi lõm không giống động phủ tu sĩ bình thường.","nguon":["@c0607"]},{"id":"linh-nhan-chi-ngoc-hoa-hinh","name":"Linh Nhãn Chi Ngọc (sắp hóa hình)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Sắp hóa hình, vượt xa Linh nhãn chi thạch thường","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Linh Nhãn Chi Ngọc sắp hóa hình là viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ màu xanh sống động, phẩm chất vượt xa Linh nhãn chi thạch phổ thông. Thiếu phụ áo đen trao cho Hàn Lập làm thù lao đưa tin, giúp rút ngắn thời gian tu luyện tiến vào Giả Anh kỳ từ mười năm còn vài năm.","detail":"Linh Nhãn Chi Ngọc này là một viên ngọc trắng kích thước vài tấc, bên trong ẩn chứa hình con trâu nhỏ màu xanh bằng ngón tay cái, sống động như thật — dấu hiệu cho thấy ngọc sắp hóa hình, đồng nghĩa phẩm chất đã vượt xa loại Linh nhãn chi thạch phổ thông. Vốn do thiếu phụ áo đen sở hữu, bà trao viên ngọc cho Hàn Lập để làm thù lao cho việc đưa tin (@c0608). Hàn Lập nhận định rằng dùng viên ngọc này tu luyện, thời gian cần thiết để tiến vào cảnh giới Giả Anh kỳ sẽ được rút ngắn từ khoảng mười năm xuống chỉ còn vài năm. Ngoài ra, linh khí tỏa ra từ viên ngọc cũng chính là nguyên nhân khiến Tuyết Vân Hồ nhiễm linh khí mà tiến hóa thành yêu hồ.","hinhDang":"Viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ xanh sống động","nguonGoc":"Do thiếu phụ áo đen sở hữu, trao cho Hàn Lập","congNang":["Tu luyện hiệu quả cực cao, rút ngắn thời gian tiến vào Giả Anh kỳ từ khoảng mười năm còn vài năm","Linh khí tỏa ra từ ngọc có thể khiến yêu thú tiến hóa — Tuyết Vân Hồ tiến hóa thành yêu hồ nhờ nhiễm linh khí này"],"chuSoHuu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","denChuong":"@c0608","cachCoDuoc":"","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0608","denChuong":"","cachCoDuoc":"Nhận từ thiếu phụ áo đen làm thù lao","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"đổi chủ","importance":"major","giaiDoan":"Thiếu phụ trao cho Hàn Lập","text":"Thiếu phụ áo đen trao Linh nhãn chi ngọc sắp hóa hình cho Hàn Lập làm thù lao đưa tin. Phẩm chất cực cao, bên trong có hình trâu xanh sống động, giúp rút ngắn thời gian tiến Giả Anh kỳ.","anchor":"tận mắt trông thấy bên trong ngọc có một con trâu nhỏ màu xanh bằng ngón tay cái"}]},"capNhatToi":"@c0608","nguon":["@c0608"],"dacDiem":"Viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ màu xanh bằng ngón tay cái sống động như thật, cho thấy ngọc sắp hóa hình, phẩm chất vượt xa Linh nhãn chi thạch phổ thông."},{"id":"thien-hoa-than-lien","name":"Thiên Hỏa Thần Liên","cn":"","aliases":["Ngân liên","dây xích bạc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hắc y thiếu phụ"],"trangThai":"đang sử dụng (trói buộc thiếu phụ)","blurb":"Thiên Hỏa Thần Liên là dây xích màu trắng do thiếu phụ áo đen tự chế bằng tâm pháp đặc biệt, xuyên qua xương đùi và chôn sâu vào nền đá nhằm tự giam giữ bản thân. Dây xích tương thông nguyên thần người bị trói, không thể cưỡng ép luyện chế bằng chân hỏa, và cần chìa khóa đặc biệt mới có thể tháo mở.","detail":"Thiên Hỏa Thần Liên có hình dạng mấy sợi dây xích trắng, một đầu xuyên xuyên qua xương đùi của thiếu phụ áo đen, đầu còn lại chôn sâu vào nền đá. Đây là pháp bảo do chính thiếu phụ tự chế bằng tâm pháp đặc biệt với mục đích tự giam cầm bản thân. Dây xích tương thông trực tiếp với nguyên thần của người bị trói, khiến việc cưỡng ép phá giải bằng chân hỏa luyện chế trở nên cực kỳ nguy hiểm, có thể khiến người bị trói mất mạng. Muốn tháo gỡ Thiên Hỏa Thần Liên phải dùng chìa khóa đặc biệt đi kèm, chìa khóa này đã được thiếu phụ giao cho bạn thân cất giữ.","hinhDang":"Mấy sợi dây xích màu trắng","nguonGoc":"Do thiếu phụ áo đen tự chế bằng tâm pháp đặc biệt","congNang":["Trói buộc và giam cầm: dây xích xuyên qua xương người bị trói, một đầu chôn sâu vào nền đá, khống chế hoàn toàn hành động @c0608","Tương thông nguyên thần người bị trói, khiến việc cưỡng ép phá giải bằng chân hỏa luyện chế sẽ nguy hiểm đến tính mạng @c0608","Cần chìa khóa đặc biệt chuyên dụng mới có thể mở được @c0608"],"chuSoHuu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","denChuong":"","cachCoDuoc":"Tự chế","trangThai":"đang bị trói bởi chính nó"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi thiếu phụ chứng minh bị giam","text":"Thiếu phụ vén quần lộ hai đùi khô gầy bị mấy sợi dây xích trắng xuyên qua xương chôn sâu vào nền đá. Bà nói tự chế Thiên Hỏa Thần Liên cùng Thanh kim thạch để giam giữ bản thân.","anchor":"Thiên Hỏa Thần Liên cùng gian kim thạch này đem bản thân giam giữ tại đây"}]},"capNhatToi":"@c0608","nguon":["@c0608"],"dacDiem":"Hình dạng dây xích màu trắng, có khả năng xuyên qua xương người bị trói và tương thông nguyên thần, do chính người bị giam tự chế bằng tâm pháp đặc biệt để tự giam giữ bản thân."},{"id":"hop-ngoc-o-vang","name":"Hộp ngọc ố vàng (tín vật)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"Hàn Lập đang giữ","blurb":"Hộp ngọc ố vàng giấu sau đài đá, bên ngoài khắc đồ án ngọn lửa có bóng người gào rít, mặt trước dán đạo phù vàng phát uy áp mạnh có tác dụng trấn áp thiếu phụ.","detail":"Hộp ngọc ố vàng tỏa mùi hương, giấu trong lỗ sâu sau đài đá. Bên ngoài khắc đồ án ngọn lửa, trong hỏa diễm mơ hồ có bóng một người đang nhìn trời gào rít. Mặt trước dán một đạo phù vàng phát ánh sáng chói mắt, tỏa uy áp cực mạnh. Thiếu phụ nói đây là tín vật nhờ Hàn Lập chuyển đi và yêu cầu xé phù, nhưng khi Hàn Lập mang hộp có phù lại gần bà thì bà hoảng sợ thực sự — cho thấy đạo phù/hộp này chính là vật trấn áp thiếu phụ.","hinhDang":"Hộp ngọc ố vàng, khắc đồ án ngọn lửa có bóng người gào rít, có đạo phù vàng chói mắt","congNang":["Đạo phù trên hộp có tác dụng trấn áp thiếu phụ áo đen"],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lấy ra từ sau đài đá","text":"Hàn Lập tìm thấy hộp ngọc ố vàng trong lỗ sâu sau đài đá, bên ngoài khắc đồ án ngọn lửa có bóng người gào rít, mặt trước dán đạo phù phát uy áp mạnh.","anchor":"bên ngoài có khắc một đồ án ngọn lửa, trong hỏa diễm mơ hồ có bóng một người, đang nhìn trời gào rít"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"la-phu-hop-ngoc","name":"Lá phù trong hộp ngọc","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Lá phù chứa trong hộp ngọc ố vàng tìm thấy trong thạch thất, phóng ra phù văn vàng có khả năng khắc chế Thi Tiêu.","detail":"Phóng ra vô số phù văn màu vàng có khả năng khắc chế Thi Tiêu, khiến quái vật đau đớn kêu thảm thiết và bốc khói xanh. Linh khí hữu hạn, sau khi phát huy hết tác dụng thì kim quang tắt.","congNang":["Khắc chế Thi Tiêu/tà vật, phóng phù văn vàng tiêu trừ @c0609"],"tabs":{"tienTrinh":[{"chuong":"@c0609","loai":"dung","importance":"normal","giaiDoan":"Sử dụng khắc chế Thi Tiêu","text":"Hàn Lập khoát tay cho hộp ngọc bay tới thiếu phụ áo đen, lá phù phóng ra vô số phù văn vàng khiến Thi Tiêu đau đớn kêu thảm thiết, bốc khói xanh. Sau khi linh khí hết, kim quang trên lá phù tắt.","anchor":"kim quang trên lá phù cũng không có bị mất đi"}]},"nguon":["@c0609"]},{"id":"hop-ngoc-tinh-hon-thi-tieu","name":"Hộp ngọc chứa tinh hồn thi tiêu","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang được Hàn Lập cất giữ, chưa mở","blurb":"Hộp ngọc bên ngoài dán linh phù kỳ lạ, nghi chứa tinh hồn thi tiêu bị Trừu Hồn thuật phong ấn. Hàn Lập thu vào túi trữ vật, hẹn đại thành Nguyên Anh mới dám mở.","detail":"Hộp ngọc rơi bên cạnh thi tiêu bất động. Bên ngoài dán lá phù có phù văn kỳ lạ khiến Hàn Lập muốn nghiên cứu. Bên trong nghi là tinh hồn thi tiêu bị phong ấn bằng Trừu Hồn thuật. Thi tiêu trước đó vẫn có thể nói chuyện và lừa Hàn Lập mở hộp dù tinh hồn đã bị trừu, khiến Hàn Lập thắc mắc. Hàn Lập dự định khi đại thành Nguyên Anh sẽ dùng Ích tà thần lôi và Đề Hồn Thú đối phó nếu bên trong là linh hồn thi tiêu hay hồn quỷ.","congNang":["Phong ấn tinh hồn thi tiêu, phù văn bên ngoài có tác dụng trấn áp chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0610","denChuong":"","cachCoDuoc":"Nhặt được bên cạnh thi tiêu bất động","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0610","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập thu nhặt sau khi chế trụ thi tiêu","text":"Hàn Lập phân tích hộp ngọc dán linh phù chứa tinh hồn thi tiêu bị Trừu Hồn thuật phong ấn, sờ lá phù rồi thu vào túi trữ vật.","anchor":"hắn sau khi sờ lá phù vài lần sau đó đột nhiên vung tay đem thu nó vào túi trữ vật"}]},"nguon":["@c0610"]},{"id":"noi-giap-xanh","name":"Nội giáp xanh","cn":"","category":"phap-bao","categoryLabel":"Phòng cụ","phamCap":"Không rõ (không kém Hoàng Lân giáp)","soHuu":["Hàn Lập"],"trangThai":"Đang dùng","blurb":"Nội giáp di vật của Ôn Thiên Nhân (truyền nhân Lục Đạo), mềm mại như tơ, lấp lóe ánh sáng xanh. Cứu Hàn Lập khỏi lợi trảo bất ngờ của yêu hồ cấp cao.","detail":"Lộ ra khi áo Hàn Lập bị yêu hồ xé rách, lấp lóe ánh sáng xanh bên trong. Là nội giáp của Lục Đạo truyền nhân Ôn Thiên Nhân, mềm mại như tơ, chất lượng không kém Hoàng Lân giáp. Chặn được lợi trảo khổng lồ trắng như tuyết của yêu hồ cấp cao mà Hàn Lập không bị thương.","congNang":["Phòng ngự vật lý cực mạnh, chặn được lợi trảo yêu hồ cấp cao"],"nguonGoc":"Di vật của Ôn Thiên Nhân, truyền nhân Lục Đạo","dacDiem":"Mềm mại như tơ, ánh sáng xanh, chất lượng không kém Hoàng Lân giáp","chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"","denChuong":"","cachCoDuoc":"Thu được từ Ôn Thiên Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0610","loai":"dùng","importance":"normal","giaiDoan":"Cứu mạng Hàn Lập trước lợi trảo yêu hồ","text":"Áo Hàn Lập bị xé rách lộ nội giáp xanh lấp lóe bên trong, chặn được lợi trảo khổng lồ của yêu hồ biến hình.","anchor":"Đúng là nội giáp của Lục Đạo truyền nhân – Ôn Thiên Nhân"}]},"nguon":["@c0610"]},{"id":"tui-bich-van","name":"Túi Bích vân","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí dạng túi dùng để chứa đồ hoặc nhốt yêu thú, tuy nhiên không đủ sức giam giữ yêu thú tinh thông độn thuật như Tuyết Vân Hồ.","detail":"Túi Bích vân được Khuê Hoán và Vương sư huynh sử dụng để nhốt con Tuyết Vân Hồ khi đem đi bán ở phường thị, nhưng yêu hồ đã dùng kỹ xảo nào đó biến mất khỏi túi một cách vô ảnh vô tung.","congNang":["Chứa đồ vật, nhốt yêu thú"],"tabs":{"tienTrinh":[{"chuong":"@c0615","loai":"dùng","importance":"normal","giaiDoan":"Nhốt Tuyết Vân Hồ thất bại","text":"Được dùng để nhốt Tuyết Vân Hồ nhưng yêu hồ đã trốn thoát khỏi túi trên đường đem bán.","anchor":"lại từ trong túi Bích vân biến mất vô ảnh vô tung"}]},"nguon":["@c0615"]},{"id":"minh-thanh-linh-thuy","name":"Minh Thanh Linh Thuỷ","cn":"明清灵水","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Cực hiếm (tam phái Vân Mộng Sơn điều chế)","soHuu":[],"trangThai":"dang-phoi-che","blurb":"Minh Thanh Linh Thuỷ là linh thuỷ trân quý do tam phái Vân Mộng Sơn điều chế, được trao làm phần thưởng cho mười người đứng đầu Thí Kiếm Đại Hội. Phối chế từ giọt linh dịch đầu tiên của thánh thụ cùng linh dược ngàn năm và các dược tài trân quý, dùng rửa mắt giúp có khả năng xuyên sương mù nhìn thấu đá, chỉ hiệu quả với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ.","detail":"Minh Thanh Linh Thuỷ là phần thưởng dành cho mười người đứng đầu Thí Kiếm Đại Hội, do tam phái Vân Mộng Sơn điều chế @c0616. Nguyên liệu bao gồm giọt linh dịch đầu tiên mà thánh thụ xuất ra cùng các loại dược tài trân quý, trong đó có linh dược ngàn năm @c0616. Quy trình phối chế ở bước cuối cùng cần tích nhập Thuần dịch để hoàn thành @c0625. Hương dược dùng trong phối chế được lưu trữ trong bình ngọc đặt dưới gốc Linh Nhãn Chi Thụ @c0628. Linh thuỷ này dùng để rửa hai mắt, ban cho đôi mắt khả năng xuyên vụ khí thấu thạch, tuy nhiên không gia tăng tu vi và chỉ có tác dụng với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ.","congNang":["Rửa mắt cho đôi mắt khả năng xuyên sương mù, nhìn thấu đá @c0616","Tẩy trừ hai mắt cho đệ tử, liên quan đến Linh Nhãn Chi Thụ @c0628"],"dacDiem":"Chỉ hiệu quả với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ, không gia tăng tu vi; nguyên liệu cực hiếm gồm linh dịch thánh thụ và linh dược ngàn năm; bước cuối quy trình phối chế cần tích nhập Thuần dịch @c0625.","nguonGoc":"Tam phái Vân Mộng Sơn điều chế","tabs":{"tienTrinh":[{"chuong":"@c0616","loai":"xuất hiện","importance":"major","giaiDoan":"Được tiết lộ là phần thưởng top mười","text":"Vương sư huynh tiết lộ Minh Thanh Linh Thuỷ là phần thưởng cho top mười Thí Kiếm Đại Hội, phối chế từ linh dịch thánh thụ cùng dược tài ngàn năm, có khả năng cho mắt xuyên sương thấu đá.","anchor":"dùng giọt linh dịch đầu tiên mà thánh thụ xuất ra cộng thêm các tài liệu trân quý khác có thể phối chế ra Minh Thanh Linh Thuỷ trong truyền thuyết"},{"chuong":"@c0625","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang được điều chế tại sơn cốc bí mật","text":"Nho sinh họ Bạch giải thích quy trình: Minh Thanh Linh Thủy tích nhập Thuần dịch ở bước cuối, hoàn thành xong phải lập tức tẩy mắt cho mười đệ tử. Ba tu sĩ Kết Đan ngày đêm thủ hộ thánh địa.","anchor":"Minh Thanh Linh Thủy tích nhập Thuần dịch, phải tới bước cuối cùng mới tiến hành"},{"chuong":"@c0628","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc tới","text":"Hàn Lập nhận ra bình ngọc dưới gốc Linh Nhãn Chi Thụ chứa hương dược dùng phối chế Minh Thanh Linh Thủy. Vệ sư huynh bắt đầu điều phối.","anchor":"Chẵng lẽ cái này dùng để phối chế ra Minh Thanh Linh Thủy"}]},"capNhatToi":"@c0616","nguon":["@c0616","@c0625","@c0628"]},{"id":"thien-tinh-dai","name":"Thiên Tinh đai","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng giai pháp khí","soHuu":["Mộ Phái Linh"],"trangThai":"dang-co","blurb":"Pháp khí phi hành hồng sắc của Mộ Phái Linh, tốc độ cao và có thể mang thêm người bay cùng.","detail":"Pháp khí phi hành dạng dải lụa hồng sắc, có khả năng bao lấy người khác mang theo bay với tốc độ cao. Mộ Phái Linh dùng nó mang Hàn Lập bay đến Thiên Tuyền Phong vì phi kiếm của hắn không phải loại phi hành chuyên dụng.","congNang":["Phi hành tốc độ cao, có thể mang thêm người bay cùng"],"chuSoHuu":[{"ten":"Mộ Phái Linh","tuChuong":"@c0617","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0617","loai":"dùng","importance":"normal","giaiDoan":"Mộ Phái Linh dùng mang Hàn Lập bay","text":"Mộ Phái Linh dùng Thiên Tinh đai bao lấy Hàn Lập, mang hắn bay cùng đến Thiên Tuyền Phong vì phi kiếm của hắn chậm.","anchor":"chi bằng để ta dùng Thiên Tinh đai mang ngươi theo kẻo trễ mất thời gian"}]},"nguon":["@c0617"]},{"id":"bach-kim-qua","name":"Bạch kim qua","category":"phap-bao","categoryLabel":"Pháp khí","soHuu":["Tu sĩ họ Viên"],"trangThai":"binh-thuong","blurb":"Pháp khí của tu sĩ họ Viên (Thiên Tuyền Phong), có chút uy lực, hóa thành cầu vồng trắng chém xuống nhưng không đủ giúp chủ nhân thắng trận.","detail":"Pháp khí dạng qua (kích) màu trắng kim, khi thi triển hóa thành cầu vồng trắng chém xuống đối thủ. Được tu sĩ họ Viên sử dụng trong tỷ thí Lục Xảo Phong, chiếm ưu thế ban đầu nhưng không đủ chống lại thuật ẩn thân và hồng vụ của Kim Dung.","nguon":["@c0619"]},{"id":"hoa-lang-chau","name":"Hoả Lãng châu","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Tuân Thông"],"trangThai":"đang sử dụng","blurb":"Pháp khí gia truyền Tuân gia, viên hoả châu to bằng quả trứng gà, có thể phát ra hoả diễm công kích. Tuân sư đệ dùng trong trận tỷ thí nhưng chưa kịp phát huy.","detail":"Pháp khí nổi danh của Tuân gia (tu tiên gia tộc ở Khê quốc), viên hoả châu to bằng quả trứng gà, có thể phát ra hoả diễm công kích. Tuân sư đệ cầm trên tay trong trận tỷ thí vòng 1 với Hàn Lập nhưng vòng bảo hộ bị phá trước khi kịp thi triển.","congNang":["Phát ra hoả diễm công kích"],"chuSoHuu":[{"ten":"Tuân Thông","tuChuong":"@c0620","denChuong":"","cachCoDuoc":"Gia truyền Tuân gia","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0620","loai":"xuất hiện","importance":"normal","giaiDoan":"Trận tỷ thí vòng 1","text":"Tuân sư đệ thôi động Hoả Lãng châu trong trận tỷ thí với Hàn Lập nhưng chưa kịp phát huy thì vòng bảo hộ đã bị phá.","anchor":"khoả châu trên tay hắn ta hình như là Hoả Lãng châu đỉnh đỉnh đại danh của Tuân gia"}]},"nguon":["@c0620"]},{"id":"hoa-dan-phu","name":"Hoả Đạn phù","category":"khac","categoryLabel":"Linh phù","phamCap":"Sơ cấp","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Phù sơ cấp giá một linh thạch mỗi tấm, tạo ra hoả cầu to bằng nắm tay. Hàn Lập dùng ba bốn mươi lá đồng loạt phá vỡ vòng bảo hộ Tuân sư đệ.","detail":"Loại phù sơ cấp phổ thông, mỗi tấm giá một khối linh thạch, kích hoạt tạo ra hoả cầu to bằng nắm tay. Đơn lẻ uy lực yếu nhưng Hàn Lập dùng ba bốn mươi lá đồng loạt, hoả cầu như ong vỡ tổ bắn tới đối phương, phá vỡ cả vòng bảo hộ Hỏa thuộc tính tầng 12 Luyện Khí của Tuân sư đệ. Cách đánh xa xỉ khiến các đệ tử gọi Hàn Lập là phá gia chi tử.","congNang":["Tạo hoả cầu to bằng nắm tay công kích"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0620","denChuong":"","cachCoDuoc":"Mua/tự chế","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0620","loai":"dùng","importance":"normal","giaiDoan":"Trận tỷ thí vòng 1","text":"Hàn Lập ném ba bốn mươi lá Hoả Đạn phù đồng loạt, hoả cầu như ong vỡ tổ phá vỡ vòng bảo hộ Tuân sư đệ.","anchor":"cho dù Hoả đạn phù là loại phù sơ cấp nhưng một tấm phù dù sao cũng phải cần một khối linh thạch mới mua được"}]},"nguon":["@c0620"]},{"id":"han-nguyet-luan","name":"Hàn Nguyệt Luân","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Đỗ Đông"],"trangThai":"dang-co","blurb":"Đỉnh cấp pháp khí thuộc tính băng hình luân tử bàn, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng. Trấn tộc chi bảo của Đỗ gia bị diệt hai trăm năm trước, nay thuộc về Đỗ Đông.","detail":"Pháp khí hình luân tử bàn thuộc tính băng, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng. Phát bạch quang tạo vòng bảo hộ băng bao phủ chủ nhân, đồng thời phóng hàn khí hóa thành chim lớn công kích đối thủ. Uy lực cực mạnh, đánh bại mọi đối thủ trong vòng tuyển chọn chỉ sau một chiêu. Vốn là trấn tộc chi bảo của Đỗ gia — gia tộc tu tiên bị tiêu diệt hai trăm năm trước.","congNang":["Phát bạch quang tạo vòng bảo hộ băng bao phủ chủ nhân","Phóng hàn khí hóa thành chim lớn công kích đối thủ"],"phanLoaiPhu":"Luân tử bàn","hinhDang":"Hình luân tử bàn, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng","nguonGoc":"Trấn tộc chi bảo của Đỗ gia (bị diệt 200 năm trước)","uyLuc":"Đỉnh cấp pháp khí thuộc tính băng, một chiêu thắng mọi đối thủ vòng tuyển chọn","dacDiem":"Thuộc tính băng, vừa phòng thủ vừa công kích","chuHienThoi":"Đỗ Đông","chuSoHuu":[{"ten":"Đỗ gia","tuChuong":"","denChuong":"","cachCoDuoc":"Trấn tộc chi bảo","trangThai":"da-mat"},{"ten":"Đỗ Đông","tuChuong":"@c0621","denChuong":"","cachCoDuoc":"Thừa kế từ Đỗ gia","trangThai":"dang-co"}],"dinhDanh":"goc","capNhatToi":"@c0621","tabs":{"tienTrinh":[{"chuong":"@c0621","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện trong vòng tuyển chọn","text":"Đỗ Đông dùng Hàn Nguyệt Luân trong vòng tuyển chọn cuối cùng tông nội tỷ thí, đánh bại mọi đối thủ chỉ sau một chiêu. Các trưởng lão nhận ra đây là trấn tộc chi bảo Đỗ gia bị diệt hai trăm năm trước.","anchor":"Là một pháp khí giống như Luân tử bàn, đường kính hơn trượng, trên bề mặt có khắc biểu tượng vầng trăng"}]},"nguon":["@c0621"]},{"id":"hai-thanh-phi-kiem-do-lam","name":"Hai thanh phi kiếm đỏ lam","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Diêu Phong"],"trangThai":"dang-co","blurb":"Cặp phi kiếm một đỏ một lam của Diêu Phong, đeo trên lưng, dùng khu kiếm tấn công trong trận đấu nhưng chưa kịp phát huy đã thua.","detail":"Hai thanh trường đoản kiếm, một đỏ một lam, Diêu Phong đeo trên lưng. Khi giao đấu với Hàn Lập, hai kiếm bắn ra phiêu phù trên đỉnh đầu chuẩn bị khu kiếm tấn công, nhưng bị hỏa cầu áp đảo nên chưa kịp dùng.","congNang":["Phi kiếm chiến đấu, khu kiếm tấn công từ xa"],"chuSoHuu":[{"ten":"Diêu Phong","tuChuong":"@c0624","denChuong":"","cachCoDuoc":"Bản thân sở hữu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0624","loai":"xuat-hien","importance":"normal","giaiDoan":"Trận đầu Thí Kiếm Đại Hội","text":"Diêu Phong xuất hai phi kiếm từ lưng khi giao đấu Hàn Lập, phiêu phù trên đỉnh đầu chuẩn bị khu kiếm nhưng bị hỏa cầu áp đảo, chưa kịp phát huy.","anchor":"hai thanh phi kiếm đồng thời từ trên lưng bắn nhanh ra, phiêu phù ở khoảng không trên đỉnh đầu"}]},"nguon":["@c0624"]},{"id":"di-chung-thanh-quang-dieu","name":"Dị chủng thanh quang điêu","cn":"","category":"khac","categoryLabel":"Linh thú / Tọa kỵ","phamCap":"Năm cấp yêu thú","soHuu":["Lạc Vân Tông"],"trangThai":"dang-co","blurb":"Quái điểu khổng lồ cấp năm yêu thú của Lạc Vân Tông, có thể biến hóa lớn nhỏ, dùng chở đông đảo tu sĩ đi xa.","detail":"Dị chủng thanh quang điêu, yêu thú cấp năm tạp chủng, có thể biến hóa thân thể lớn nhỏ. Lạc Vân Tông dùng làm phương tiện chở đông đảo tu sĩ đến Bách Xảo Viện dự Thí Kiếm Đại Hội. Hai cánh giang ra che khuất cả sân, tạo cuồng phong khiến đệ tử thấp giai chao đảo.","congNang":["Vận chuyển đoàn tu sĩ đi xa","Biến hóa thân thể lớn nhỏ"],"chuSoHuu":[{"ten":"Lạc Vân Tông","tuChuong":"@c0624","denChuong":"","cachCoDuoc":"Sở hữu của tông môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0624","loai":"xuat-hien","importance":"normal","giaiDoan":"Lạc Vân Tông đến Thí Kiếm Đại Hội","text":"Chở đông đảo tu sĩ Lạc Vân Tông bay đến Bách Xảo Viện, hai cánh giang ra che khuất cả sân tạo cuồng phong.","anchor":"Dị chủng thanh quang điêu này của Lạc Vân Tông chỉ là tạp chủng quái điểu"}]},"nguon":["@c0624"]},{"id":"lenh-bai-vang","name":"Lệnh bài vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tu sĩ áo vàng họ Việt"],"trangThai":"dang-su-dung","blurb":"Vật dụng chuyên dùng của tu sĩ họ Việt để mở cấm chế cấm địa ba phái. Phóng tia vàng và khói vàng làm tan bức vách, tạo thông đạo vài trượng.","detail":"Lệnh bài màu vàng, trên tay tu sĩ họ Việt xuất hiện khi cần mở cấm chế. Phóng tia vàng vào cửa đá dày đặc chú văn, khói vàng lan ra làm tan bức vách cấm chế, tạo thông đạo vài trượng cho người đi qua.","congNang":["Mở cấm chế cấm địa ba phái, tạo thông đạo nhất thời"],"chuSoHuu":[{"ten":"Tu sĩ áo vàng họ Việt","tuChuong":"@c0626","denChuong":"","cachCoDuoc":"Trấn thủ cấm địa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"dung","importance":"normal","giaiDoan":"Mở cấm chế cho đoàn người vào","text":"Tu sĩ họ Việt rút lệnh bài vàng phóng tia vàng vào cửa đá, khói vàng làm tan bức vách cấm chế nhiều tầng, tạo thông đạo vài trượng.","anchor":"trên tay xuất hiện một cái lệnh bài màu vàng"}]},"nguon":["@c0626"]},{"id":"binh-thuan-dich-trang","name":"Bình thuần dịch trắng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Đỗ Đông"],"trangThai":"đang sử dụng","blurb":"Bình nhỏ màu trắng chứa thuần dịch chiết từ Linh Nhãn Chi Thụ, được lão giả tóc rối chuẩn bị giao và Thiên Sát Chân Quân ném cho Đỗ Đông.","detail":"Thuần dịch chiết từ Linh Nhãn Chi Thụ, có thể thay thế chức năng linh thụ ở mức độ nhất định. Lão giả tóc rối lấy ra chuẩn bị giao thì bẫy phản gián sập; sau khi Thiên Sát Chân Quân phụ thân, ném bình cho Đỗ Đông mang đi.","congNang":["Chứa thuần dịch Linh Nhãn Chi Thụ, có thể thay thế chức năng linh thụ ở mức độ nhất định"],"chuSoHuu":[{"ten":"Vệ sư huynh","tuChuong":"@c0631","denChuong":"@c0631","cachCoDuoc":"Chiết từ Linh Nhãn Chi Thụ đang canh giữ","trangThai":"đã chuyển"},{"ten":"Đỗ Đông","tuChuong":"@c0631","denChuong":"","cachCoDuoc":"Thiên Sát Chân Quân ném cho","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0631","loai":"đổi chủ","importance":"normal","giaiDoan":"Lão giả tóc rối giao, Thiên Sát Chân Quân ném cho Đỗ Đông","text":"Lão giả tóc rối lấy bình thuần dịch ra chuẩn bị giao cho Đỗ Đông thì bị ba phái phục kích. Sau khi Thiên Sát Chân Quân phụ thân, cầm bình ném cho Đỗ Đông.","anchor":"trong tay bỗng nhiên cầm bình nhỏ chứa thuần dịch, vứt cho hai người Đỗ Đông"}]},"nguon":["@c0631"]},{"id":"huyen-thien-tien-dang","name":"Huyền Thiên Tiên Đằng","cn":"玄天仙藤","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"khong-ro","blurb":"Vật phẩm được Đỗ Đông coi là mục tiêu quan trọng nhất, lớn hơn cả Linh Nhãn Chi Thụ. Chi tiết chưa được tiết lộ.","detail":"Đỗ Đông tuyên bố Huyền Thiên Tiên Đằng mới là việc lớn, Linh Nhãn Chi Thụ chỉ là việc nhỏ. Chưa rõ hình dạng, vị trí hay công năng cụ thể.","nguon":["@c0631","@c0792"],"tabs":{"tienTrinh":[{"chuong":"@c0792","loai":"nhắc tới","importance":"normal","giaiDoan":"Chưa rõ sống chết","text":"Rễ cây đổi từ vàng sẫm sang xanh lục sau khi dùng vạn năm linh dịch kết hợp thuần dịch, nhưng không phát triển thêm, không có dấu hiệu sống.","anchor":"ngoại trừ việc thay đổi màu sắc thì nó vẫn như trước không có gì thay đổi"}]}},{"id":"tieu-linh-can","name":"Tiểu linh căn Linh Nhãn Chi Thụ","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Tiểu linh căn là một nhánh rễ nhỏ được Hàn Lập cắt từ Linh Nhãn Chi Thụ khi xâm nhập quang tráo, chảy ra linh dịch trắng sữa thơm ngát tại chỗ cắt, được cất giữ trong hộp ngọc điêu khắc bỏ vào Túi trữ vật.","detail":"Trong lần xâm nhập quang tráo, Hàn Lập dùng thanh mang cắt đứt một tiểu linh căn từ Linh Nhãn Chi Thụ. Tại vết cắt, vài giọt linh dịch màu trắng sữa tràn ra, tỏa mùi thơm ngát. Tiểu linh căn sau đó được cất vào một chiếc hộp ngọc có điêu khắc rồi bỏ trong Túi trữ vật. Đây chính là mục tiêu chủ yếu của Hàn Lập trong chuyến xâm nhập này.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0632","denChuong":"","cachCoDuoc":"Tự tay chặt từ Linh Nhãn Chi Thụ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0632","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập đắc linh căn","text":"Hàn Lập cắt đứt tiểu linh căn từ Linh Nhãn Chi Thụ, linh dịch trắng sữa tràn ra, cất vào hộp ngọc.","anchor":"một tiểu linh căn dễ dàng bị chặt đứt, theo sau vài giọt linh dịch màu trắng sữa từ chỗ bị cắt tràn ra"}]},"nguon":["@c0632"],"dacDiem":"Khi bị cắt khỏi thân cây, vết cắt tiết ra vài giọt linh dịch màu trắng sữa tỏa mùi thơm ngát (@c0632)."},{"id":"ngoc-gian-luc-quang","name":"Ngọc giản lục quang","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vệ sư huynh"],"trangThai":"dang-co","blurb":"Ngọc giản tỏa lục quang yếu ớt của lão giả họ Vệ, chứa công pháp tu luyện và phương pháp luyện chế Định Linh Đan cùng Minh Thanh Linh Thủy.","detail":"Đặt trên bồ đoàn vàng bên cạnh Linh Nhãn Chi Thụ trong quang tráo. Ghi lại công pháp tu luyện cùng đan dược tâm đắc của tu sĩ tóc rối (Vệ sư huynh), bao gồm phương pháp luyện chế Định Linh Đan và Minh Thanh Linh Thủy. Hàn Lập sao chép toàn bộ nội dung sang ngọc giản trống rồi đặt bản gốc lại chỗ cũ.","tabs":{"tienTrinh":[{"chuong":"@c0632","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện và sao chép","text":"Hàn Lập phát hiện ngọc giản lục quang bên linh thụ, sao chép nội dung sang ngọc giản trống rồi đặt bản gốc lại.","anchor":"ghi lại công pháp tu luyện cùng một ít đan dược tâm đắc của tu sĩ tóc rối, phương pháp luyện chế Định Linh Đan cùng Minh Thanh Linh Thủy bất ngờ cũng ở trong đó"}]},"nguon":["@c0632"]},{"id":"duong-hon-moc-chau","name":"Dưỡng Hồn Mộc Châu","cn":"养魂木珠","aliases":["Dưỡng Hồn Châu"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Dưỡng Hồn Mộc Châu là một linh bảo có khả năng tự động cường hóa thần thức cho người sở hữu mà không cần tận lực rèn luyện. Khi phối hợp tu luyện công pháp thần thức như Đại Diễn Quyết, châu phóng khí tức vào nguyên thần, tăng hiệu suất tu luyện lên gấp rưỡi, là nguyên nhân chính giúp Hàn Lập đột phá chướng ngại Đại Diễn Quyết.","detail":"Từ khi Hàn Lập sở hữu Dưỡng Hồn Mộc Châu, thần thức của hắn không ngừng cường đại dù bản thân không tận lực rèn luyện. Mỗi khi tu luyện Đại Diễn Quyết, châu tự động phóng một cỗ khí tức nhè nhẹ đưa vào nguyên thần, nâng hiệu suất tu luyện công pháp thần thức tăng thêm khoảng năm mươi phần trăm. Nhờ tác dụng bổ trợ này, Hàn Lập đã đột phá được chướng ngại của Đại Diễn Quyết một cách thuận lợi — điều mà trước đó vốn rất khó khăn.","congNang":["Tự động cường hóa thần thức cho người sở hữu dù không tận lực rèn luyện @c0633","Khi tu luyện công pháp thần thức (Đại Diễn Quyết), phóng khí tức vào nguyên thần, tăng hiệu suất tu luyện gấp rưỡi @c0633"],"tabs":{"tienTrinh":[{"chuong":"@c0633","loai":"he-lo-cong-nang","importance":"major","giaiDoan":"Tiết lộ công năng cốt lõi","text":"Hé lộ Dưỡng Hồn Mộc Châu tự động cường hóa thần thức và bổ trợ tu luyện Đại Diễn Quyết, tăng hiệu suất gấp rưỡi, là nguyên nhân chính giúp Hàn Lập đột phá chướng ngại.","anchor":"từ Dưỡng Hồn Mộc Châu rõ ràng có một cỗ khí tức nhè nhẹ đưa vào trong nguyên thần"}]},"nguon":["@c0633"]},{"id":"cuu-khuc-linh-sam-dan","name":"Cửu Khúc Linh Sâm đan","cn":"九曲灵参丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Cửu Khúc Linh Sâm đan là đan dược kết anh do Hàn Lập luyện chế thành công sau nhiều lần thất bại, dùng nguyên liệu chính là tham dịch Cửu Khúc Linh Sâm cùng Mã Não Giác và Bạn Yêu Thảo. Đan hoàn nhũ bạch cỡ ngón cái, trong suốt, có linh quang chớp động và mùi thơm độc nhất vô nhị, công dụng hỗ trợ ngưng kết Nguyên Anh khi đột phá kết anh.","detail":"Cửu Khúc Linh Sâm đan được Hàn Lập luyện chế từ tham dịch Cửu Khúc Linh Sâm làm dược dẫn chủ đạo, phối hợp cùng Mã Não Giác và Bạn Yêu Thảo (@c0634). Quá trình luyện đan không hề thuận lợi, phải trải qua nhiều lần thất bại trước khi thành công. Đan dược thành phẩm toàn thân nhũ bạch trong suốt, bề mặt có linh vụ trắng sữa di động, tỏa mùi thơm đặc trưng không lẫn vào đâu được. Đây là đan dược phục vụ trực tiếp cho bước đột phá kết Nguyên Anh của Hàn Lập, dược hiệu cụ thể chỉ có thể biết khi thực sự phục dụng trong lúc kết anh.","congNang":["Hỗ trợ ngưng kết Nguyên Anh khi đột phá kết anh"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0634","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0634","loai":"xuất hiện","importance":"major","giaiDoan":"Luyện thành","text":"Hàn Lập luyện thành công Cửu Khúc Linh Sâm đan sau nhiều lần thất bại, nguyên liệu Mã Não Giác và Bạn Yêu Thảo gần cạn kiệt.","anchor":"Cửu Khúc Linh Sâm đan dược này, thật sự đã được luyện chế thành"}]},"nguon":["@c0634"],"dacDiem":"Đan hoàn nhũ bạch cỡ ngón cái, trong suốt, bề mặt có linh vụ trắng sữa di động, linh quang chớp động, tỏa mùi thơm độc nhất vô nhị."},{"id":"vien-chau-nguyen-anh","name":"Viên châu trong suốt","cn":"","category":"khac","categoryLabel":"Sản phẩm kết anh","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quang đoàn ngũ sắc trên bầu trời ngưng tụ thành viên châu trong suốt cỡ nắm tay, ẩn chứa linh khí khổng lồ đáng sợ, là sản phẩm của quá trình kết Nguyên Anh.","detail":"Trong quá trình Hàn Lập kết Nguyên Anh, linh quang ngũ sắc trên bầu trời động phủ ngưng tụ thành quang đoàn, rồi tiếp tục ngưng tụ thành viên châu trong suốt lớn nhỏ cỡ nắm tay. Viên châu ẩn chứa linh khí khổng lồ đáng sợ, khiến tu sĩ xung quanh sắc mặt đại biến không dám vọng động.","hinhDang":"Trong suốt, cỡ nắm tay","dacDiem":"Ẩn chứa linh khí khổng lồ đáng sợ","congNang":["Ngưng tụ từ thiên địa linh khí trong quá trình kết Nguyên Anh"],"tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ thành hình","text":"Quang đoàn ngũ sắc trên bầu trời động phủ Hàn Lập ngưng tụ thành viên châu trong suốt cỡ nắm tay, ẩn chứa linh khí khổng lồ.","anchor":"quang đoàn thật lớn trong ánh mặt mọi người ngưng tụ thành một viên châu trong suốt lớn nhỏ cở nắm tay"}]},"nguon":["@c0635"]},{"id":"truyen-am-phu-ngon-mo","name":"Truyền Âm Phù Ngôn gia – Mộ gia","cn":"","category":"khac","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Hai tấm phù truyền âm một hồng một trắng do tộc trưởng Ngôn gia và Mộ gia gửi tới cáo lỗi Hàn Lập về việc Mộ Phái Linh tự nhận là thị thiếp.","detail":"Hai trương phù một hồng một trắng, khi nhận phù rung lên phát sáng cho thần thức xâm nhập đọc nội dung. Ngân Nguyệt giữ nguyên vẹn chờ Hàn Lập ra khỏi tĩnh thất.","congNang":["Truyền âm khoảng cách xa, cho thần thức xâm nhập đọc nội dung"],"nguon":["@c0640"]},{"id":"lenh-bai-cam-che-mau-tim","name":"Lệnh bài cấm chế màu tím","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"","soHuu":["Mộ Phái Linh"],"trangThai":"dang-dung","blurb":"Lệnh bài do Hàn Lập giao cho Mộ Phái Linh, dùng để tùy ý ra vào pháp trận cấm chế quanh động phủ của hắn.","detail":"Hàn Lập lấy từ trên người đặt lên bàn giao cho Mộ Phái Linh. Mang trên người có thể tùy ý ra vào bên trong pháp trận mà hắn bố trí quanh động phủ.","congNang":["Ra vào cấm chế pháp trận quanh động phủ Hàn Lập"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0642","denChuong":"@c0642","cachCoDuoc":"Tự chế/sở hữu","trangThai":"da-tang"},{"ten":"Mộ Phái Linh","tuChuong":"@c0642","denChuong":"","cachCoDuoc":"Được Hàn Lập giao","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"doi-chu","importance":"normal","giaiDoan":"Giao cho Mộ Phái Linh","text":"Hàn Lập lấy lệnh bài tím đặt lên bàn giao cho Mộ Phái Linh để nàng tùy ý ra vào pháp trận quanh động phủ.","anchor":"lấy từ trên người ra một khối lệnh bài màu tím đặt lên bàn"}]},"nguon":["@c0642"]},{"id":"canh-tinh","name":"Canh Tinh","cn":"庚星","aliases":["Duệ kim chi bảo"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu luyện khí","phamCap":"Cực phẩm (quý hơn Luyện Tinh)","soHuu":[],"trangThai":"Chưa tìm được","blurb":"Tài liệu luyện khí cực hiếm còn gọi là Duệ kim chi bảo, trộn vào pháp bảo khiến độ sắc bén tăng gấp bội. Là điều kiện bắt buộc để bày Đại Canh Kiếm Trận.","detail":"Loại tài liệu cực hiếm ở tu tiên giới, được gọi là Duệ kim chi bảo. Trộn chút vào pháp bảo rồi bồi luyện làm độ sắc bén tăng gấp bội. Giá trị còn trên Luyện Tinh mà Hàn Lập đang sở hữu. Mấy ngàn năm ở cả Loạn Tinh Hải cũng chưa xuất hiện. Hàn Lập cần 72 phần Canh Tinh để trộn vào 72 phi kiếm bày Đại Canh Kiếm Trận nhưng không có chỗ trao đổi.","congNang":["Trộn vào pháp bảo rồi bồi luyện làm độ sắc bén tăng gấp bội","Chưa rõ công dụng cụ thể, chỉ biết là vật phẩm Hàn Lập ráo riết tìm kiếm"],"dacDiem":"Cực hiếm, mấy ngàn năm ở Loạn Tinh Hải chưa xuất hiện, quý hơn Luyện Tinh","capNhatToi":"@c0643","tabs":{"tienTrinh":[{"chuong":"@c0643","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc tới như điều kiện bắt buộc","text":"Hàn Lập nhận ra cần 72 phần Canh Tinh trộn vào phi kiếm để bày Đại Canh Kiếm Trận, nhưng vật này cực hiếm, mấy ngàn năm ở Loạn Tinh Hải chưa xuất hiện, không có chỗ trao đổi.","anchor":"chính là “Duệ kim chi bảo”rất hiếm người thấy"},{"chuong":"@c0677","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập công khai tìm kiếm","text":"Hàn Lập đem yêu đan và linh thảo ra đổi Canh tinh tại trao đổi hội nhưng không ai có. Thiên Tinh Chân Nhân lộ tia chần chờ khi nghe nhắc.","anchor":"Canh tinh? Lời Hàn Lập vừa ra khỏi miệng, ánh mắt tu sĩ bốn phía đều lộ ra vẻ cổ quái"}]},"nguon":["@c0643","@c0677"]},{"id":"cach-am-phu","name":"Cách âm phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["La huynh"],"trangThai":"dang-co","blurb":"Phù lục cách âm, hai tay bắt quyết khiến phù lóe sáng hóa một tầng bạch quang bao bọc toàn phòng, ngăn âm thanh lọt ra ngoài.","detail":"La huynh lấy Cách âm phù từ trong áo, hai tay bắt quyết khiến phù lóe sáng hóa bạch quang bao bọc toàn phòng để cách âm trước khi bàn chuyện nghi ngờ thân phận Hàn Lập.","congNang":["Cách âm, bao phủ toàn phòng bằng bạch quang ngăn âm thanh lọt ra ngoài"],"chuSoHuu":[{"ten":"La huynh","tuChuong":"@c0645","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0645","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"La huynh thi triển Cách âm phù bao phòng bạch quang để bàn riêng với đại hán về thân phận Hàn Lập.","anchor":"hóa thành một tầng bạch quang, đem toàn phòng bao bọc lại"}]},"nguon":["@c0645"]},{"id":"phi-kiem-ngu-khi-han-lap","name":"Phi kiếm ngự khí của Hàn Lập","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phi kiếm ngự khí đỉnh cấp của Hàn Lập, bị Bành Dịch Song Hung nhận ra là vật tốt và trở thành lý do chúng nảy lòng đoạt bảo.","detail":"Kiện pháp khí phi kiếm ngự khí được tu sĩ ục ịch họ La đánh giá là đỉnh cấp pháp khí, vượt xa mức tán tu bình thường có thể sở hữu, trở thành một trong những căn cứ khiến Bành Dịch Song Hung quyết định giết chủ nhân để đoạt.","nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"nhac-toi","importance":"normal","giaiDoan":"Bị nhắm tới","text":"Bị Bành Dịch Song Hung nhận ra là đỉnh cấp pháp khí, trở thành lý do chính chúng muốn đoạt bảo.","anchor":"sử dụng phi kiếm ngự khí nọ, rõ ràng chính là kiện đỉnh cấp pháp khí"}]}},{"id":"tui-linh-thu-han-lap","name":"Túi linh thú của Hàn Lập","category":"phap-bao","categoryLabel":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vài túi linh thú bên người Hàn Lập, bị La huynh dùng làm bằng chứng hắn có xuất thân không tầm thường.","detail":"Mấy túi linh thú mà Hàn Lập mang bên người, bị Bành Dịch Song Hung chú ý vì tán tu bình thường không có khả năng nuôi nhiều linh thú như vậy.","nguon":["@c0646"]},{"id":"kim-don-phu","name":"Kim độn phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Đại hán đầu hói"],"trangThai":"da-dung","blurb":"Phù lục độn thuật cho phép người dùng hóa kim hồng bỏ chạy với tốc độ cao.","detail":"Đại hán đầu bóng lưỡng (Bành Dịch Song Hung) dán phù này lên người, hóa thành kim hồng bỏ chạy khi thấy Hàn Lập lộ tu vi Nguyên Anh. Tuy nhiên vẫn bị phi kiếm Thanh Trúc Phong Vân Kiếm của Hàn Lập đuổi kịp.","congNang":["Kim độn bỏ chạy, hóa kim hồng di chuyển tốc độ cao"],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng và thất bại","text":"Đại hán đầu bóng dán phù lên người hóa kim hồng bỏ chạy nhưng bị phi kiếm Hàn Lập đuổi kịp chém chết.","anchor":"móc ra kim phù, vỗ lên trên người một cái"}]},"nguon":["@c0647"]},{"id":"hop-bach-ngoc-phong-kim-cau","name":"Hộp bạch ngọc phong kim cầu","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Hộp bạch ngọc dùng để chứa kim cầu giam Mộc Linh Anh, được dán phù lục cấm chế để phong cấm hoàn toàn.","detail":"Hàn Lập lấy hộp bạch ngọc từ túi trữ vật, đặt kim cầu chứa Mộc Linh Anh vào rồi đóng lại, dán phù lục cấm chế khiến tiếng la mắng bên trong ngưng hẳn.","nguon":["@c0648"]},{"id":"phu-luc-cam-che","name":"Phù lục cấm chế","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Phù lục cấm chế được Hàn Lập dán lên hộp bạch ngọc chứa kim cầu, khiến âm thanh Mộc Linh Anh bên trong lập tức ngưng lại.","detail":"Lấy từ túi trữ vật, dán lên hộp bạch ngọc để phong cấm kim cầu giam Mộc Linh Anh, hiệu quả tức thì khiến tiếng la mắng ngừng hẳn.","nguon":["@c0648"]},{"id":"tui-linh-thu-dai-han-pho-gia","name":"Túi linh thú của đại hán Phó Gia","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đổi chủ","blurb":"Túi linh thú chứa trấn tộc linh thú Phó Gia, bị Hàn Lập thu sau khi giết đại hán Kết Đan sơ kỳ.","detail":"Bên hông đại hán Phó Gia mang mấy túi linh thú lớn nhỏ, trong đó chứa trấn tộc linh thú. Khi chủ chết, túi phát linh quang màu đen, bên trong truyền ra tiếng hí rống nổi giận rồi tắt. Bị Hàn Lập thu lại.","chuSoHuu":[{"ten":"Đại hán Phó Gia","tuChuong":"@c0650","denChuong":"@c0650","cachCoDuoc":"sở hữu ban đầu","trangThai":"chết"},{"ten":"Hàn Lập","tuChuong":"@c0650","denChuong":"","cachCoDuoc":"thu sau khi giết chủ cũ","trangThai":"đang giữ"}],"congNang":["Chứa linh thú, bao gồm trấn tộc linh thú Phó Gia"],"tabs":{"tienTrinh":[{"chuong":"@c0650","loai":"doi-chu","importance":"normal","giaiDoan":"Đại hán chết, Hàn Lập thu","text":"Đại hán Phó Gia bị Hàn Lập giết, túi linh thú phát linh quang đen rồi ảm đạm, bên trong trấn tộc linh thú hí rống nổi giận. Hàn Lập thu lại túi.","anchor":"Mà Túi linh thú trên tay đại hán vừa mới phát ra linh quang màu đen, trong nháy mắt ngay lúc đại hán chết, một lần nữa lại ảm đạm"}]},"nguon":["@c0650"]},{"id":"dao-cau-vong","name":"Đạo cầu vồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (uy lực cấp Nguyên Anh)","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Pháp bảo tấn công dạng cầu vồng dài hơn mười trượng, phóng thanh mang chém giết. Trong khoảnh khắc giết ba tu sĩ Kết Đan Kỳ cùng hơn mười đệ tử Phó Gia mà không ai kịp phản ứng.","detail":"Đạo cầu vồng là pháp bảo tấn công có hình dạng một đạo cầu vồng dài hơn mười trượng. Khi thi triển, nó bay cuộn vào khu vực mục tiêu, sau đó xoay quanh các đối tượng và phóng ra mười mấy đạo thanh mang chói mắt chém giết. Uy lực cực kỳ kinh khủng: trong trận tập kích đại sảnh Phó Gia bảo, pháp bảo này giết tức thì ba tu sĩ Kết Đan Kỳ — khiến họ tứ phân ngũ liệt — đồng thời chặt đầu hơn mười tu sĩ cấp thấp hơn, tất cả xảy ra trong khoảnh khắc mà không ai kịp nhìn thấy.","hinhDang":"Dạng cầu vồng dài hơn mười trượng","uyLuc":"Giết tức thì ba tu sĩ Kết Đan Kỳ cùng hơn mười tu sĩ cấp thấp trong khoảnh khắc, không ai kịp phản ứng","dacDiem":"Bay cuộn vào mục tiêu dưới hình dạng đạo cầu vồng dài hơn mười trượng, xoay quanh đối tượng rồi phóng ra thanh mang chói mắt","congNang":["Phóng mười mấy đạo thanh mang chói mắt chém giết mục tiêu @c0651","Tứ phân ngũ liệt tu sĩ Kết Đan Kỳ @c0651","Chặt đầu tu sĩ cấp thấp @c0651"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0651","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0651","loai":"dùng","importance":"major","giaiDoan":"Tàn sát đại sảnh Phó Gia bảo","text":"Bay cuộn vào đại sảnh Phó Gia bảo, xoay quanh ba tu sĩ Kết Đan Kỳ phóng thanh mang, giết ba Kết Đan cùng hơn mười đệ tử Phó Gia trong khoảnh khắc.","anchor":"một đạo cầu vồng dài hơn mười trượng giống như thiên ngoại phi tiên từ bên ngoài bay cuộn vào"}]},"nguon":["@c0651"]},{"id":"ngoc-gian-di-vat-tan-nhu-am","name":"Ngọc giản di vật của Tân Như Âm","cn":"","aliases":["Ngọc giản trận pháp thượng cổ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Ngọc giản màu xanh nhạt là di vật của Tân Như Âm, được lưu lại trước khi bà bệnh mất và bảo quản qua nhiều thế hệ nha hoàn. Phong ấn bằng phù lục vàng, nội dung bên trong khiến phàm nhân hoặc tu sĩ yếu xem sẽ bị phản phệ hộc máu hôn mê; Hàn Lập phá phong ấn xem xong xác nhận nội dung trợ giúp rất nhiều rồi thu đi.","detail":"Ngọc giản màu xanh nhạt được Tân Như Âm lưu lại trước khi bệnh mất, cất giấu trong hộp ngọc chôn dưới gốc cây và giao phó cho nha hoàn thân tín giữ gìn qua nhiều đời. Tổ mẫu của phụ nhân hậu duệ nha hoàn từng tò mò liếc xem nội dung bên trong, lập tức hộc máu ba lần và hôn mê suốt một ngày đêm, sau đó phải nhờ người chế tác phù lục vàng phong ấn lại. Khi Hàn Lập đến, phụ nhân hậu duệ nha hoàn đào hộp ngọc dưới gốc cây giao cho ông. Hàn Lập dễ dàng thổi luồng khói xanh phá phù lục phong ấn, xem xong nội dung rồi xác nhận rằng ngọc giản trợ giúp rất nhiều và thu giữ. Nội dung cụ thể của ngọc giản chưa được tiết lộ trong truyện tính đến mốc hiện tại.","hinhDang":"Ngọc giản màu xanh nhạt","nguonGoc":"Di vật Tân Như Âm lưu trước khi bệnh mất, bảo quản qua nhiều thế hệ nha hoàn","dacDiem":"Ngọc giản màu xanh nhạt, được phong ấn bằng phù lục vàng; nội dung bên trong tự phát phản phệ khiến phàm nhân hoặc tu sĩ yếu xem liền hộc máu hôn mê, cần phù lục phong ấn mới ngăn được.","congNang":["Chứa nội dung bí mật mà Hàn Lập xác nhận trợ giúp rất nhiều cho bản thân @c0653","Phàm nhân hoặc tu sĩ yếu xem nội dung sẽ bị phản phệ hộc máu, hôn mê @c0653"],"chuSoHuu":[{"ten":"Tân Như Âm","tuChuong":"","denChuong":"@c0653","cachCoDuoc":"Tự lưu giữ","trangThai":"đã mất (bệnh qua đời)"},{"ten":"Hàn Lập","tuChuong":"@c0653","denChuong":"","cachCoDuoc":"Nhận từ hậu nhân nha hoàn theo di ngôn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0653","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập nhận di vật","text":"Phụ nhân hậu duệ nha hoàn đào hộp ngọc dưới gốc cây giao cho Hàn Lập. Hàn Lập phá phù lục phong ấn, xem nội dung ngọc giản xác nhận trợ giúp rất nhiều rồi thu đi.","anchor":"Thứ trong ngọc giản đích xác đối với ta trợ giúp rất nhiều"}]},"capNhatToi":"@c0653","nguon":["@c0653"]},{"id":"phe-linh-kiem","name":"Phệ Linh Kiếm","cn":"","aliases":["Phệ Kim Kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn gia (lịch đại chưởng quản)"],"trangThai":"phong-an","blurb":"Phệ Linh Kiếm là bảo kiếm ba màu do Hàn Lập luyện hóa hơn 1000 con tam sắc Phệ Kim Trùng hợp thể mà thành, phun linh khí phong ấn làm vỏ kiếm, đặt tại tông đường Hàn gia làm bảo vật trấn gia. Kiếm chỉ dùng được ba lần rồi tan biến, và chỉ người đeo ngọc bội chứa tinh khí của Hàn Lập mới rút được.","detail":"Hàn Lập triệu hơn 1000 con tam sắc Phệ Kim Trùng từ túi linh thú, cho chúng tụ lại hợp thể hóa thành một bảo kiếm ba màu, sau đó phun linh khí xanh bao phủ bên ngoài tạo lớp vỏ kiếm phong ấn. Kiếm được đặt tại tông đường Hàn gia, không thể di chuyển ra khỏi tông đường. Chỉ người mang ngọc bội chứa tinh khí của Hàn Lập mới có thể rút kiếm ra khỏi vỏ. Khi kiếm rút ra, trong phạm vi mười dặm bên ngoài tông đường, mọi sinh vật đều bị tiêu diệt. Kiếm cũng có khả năng tự hành giết địch. Mỗi lần sử dụng, linh khí trên vỏ kiếm giảm dần; sau ba lần dùng, vỏ kiếm tan biến hoàn toàn và linh trùng bay đi, kiếm không còn tồn tại.","phanLoaiPhu":"Bảo vật trấn gia","hinhDang":"Bảo kiếm ba màu (tam sắc)","vatLieu":"Hơn 1000 con tam sắc Phệ Kim Trùng hợp thể + linh khí phong ấn làm vỏ","nguonGoc":"Do Hàn Lập luyện hóa linh trùng Phệ Kim Trùng mà thành","uyLuc":"Rút kiếm ra ngoài tông đường, trong phạm vi mười dặm mọi sinh vật đều bị tiêu diệt.","dacDiem":"Chỉ dùng được ba lần, mỗi lần linh khí giảm, sau ba lần vỏ kiếm tan biến và linh trùng bay đi; không thể di chuyển ra khỏi tông đường; cần ngọc bội chứa tinh khí của Hàn Lập mới rút được kiếm.","chuHienThoi":"Hàn gia (lịch đại chưởng quản)","congNang":["Tự hành giết địch @c0660","Rút kiếm ra khỏi vỏ thì ngoài tông đường trong vòng mười dặm mọi sinh vật đều bị tiêu diệt @c0660"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0660","denChuong":"@c0660","cachCoDuoc":"Tự luyện hóa","trangThai":"da-giao"},{"ten":"Hàn gia (lịch đại chưởng quản)","tuChuong":"@c0660","denChuong":"","cachCoDuoc":"Hàn Lập giao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0660","loai":"xuat-hien","importance":"major","giaiDoan":"Hàn Lập luyện hóa và giao cho Hàn gia","text":"Hàn Lập triệu hơn 1000 con tam sắc Phệ Kim Trùng hợp thể thành bảo kiếm ba màu, phun linh khí phong ấn tạo vỏ kiếm, đặt tên Phệ Linh Kiếm, đặt tại tông đường Hàn gia làm bảo vật trấn gia kèm ngọc bội tinh khí. Kiếm chỉ dùng được 3 lần.","anchor":"Kiếm này là do ta luyện hoá linh trùng mà thành. Nó có khả năng tự hành giết địch"}]},"capNhatToi":"@c0660","nguon":["@c0660"]},{"id":"ngoc-boi-tinh-khi","name":"Ngọc bội tinh khí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn gia (lịch đại chưởng quản)"],"trangThai":"dang-su-dung","blurb":"Khối ngọc trong suốt chứa tinh khí Hàn Lập, chìa khóa duy nhất để rút Phệ Linh Kiếm. Giao cho lịch đại chưởng quản Hàn gia truyền đời.","detail":"Miếng ngọc bội trong suốt chứa tinh khí của Hàn Lập. Chỉ người đeo ngọc bội này mới có thể rút Phệ Linh Kiếm ra khỏi vỏ. Hàn Lập giao cho Vân Thiên Khiếu, dặn truyền cho lịch đại chưởng quản Hàn gia.","congNang":["Cho phép rút Phệ Linh Kiếm ra khỏi vỏ @c0660"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0660","denChuong":"@c0660","cachCoDuoc":"Tự tạo","trangThai":"da-giao"},{"ten":"Vân Thiên Khiếu","tuChuong":"@c0660","denChuong":"","cachCoDuoc":"Hàn Lập giao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0660","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập giao cho hậu nhân","text":"Hàn Lập giao ngọc bội chứa tinh khí cho Vân Thiên Khiếu, dặn truyền cho lịch đại chưởng quản Hàn gia.","anchor":"Còn đây là một miếng ngọc bội có chứa tinh khí của ta, chỉ những ai đeo ngọc bội này thì mới có thể rút kiếm ra khỏi vỏ"}]},"capNhatToi":"@c0660","nguon":["@c0660"]},{"id":"dan-duoc-luyen-vo","name":"Đan dược luyện võ (tặng Lệ gia)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Lệ Phong"],"trangThai":"dang-su-dung","blurb":"Bảy tám bình đan dược có ích cho người luyện võ phàm nhân, Hàn Lập tặng Lệ Phong để cấp cho Lệ gia đề cao thực lực.","detail":"Bảy tám bình nhỏ đan dược, có ích cho người luyện võ phàm nhân, giúp đề cao thực lực mà không cần khổ công tu luyện. Hàn Lập lấy từ túi trữ vật tặng cho Lệ Phong.","congNang":["Đề cao thực lực luyện võ cho phàm nhân @c0660"],"nguon":["@c0660"]},{"id":"dan-duoc-keo-dai-tuoi-tho","name":"Đan dược kéo dài tuổi thọ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Vân Thiên Khiếu","Lệ Phong"],"trangThai":"dang-su-dung","blurb":"Hai bình đan dược màu vàng, đối với phàm nhân có tác dụng kéo dài tuổi thọ, cường thân kiện thể, bảo đảm sống quá trăm tuổi.","detail":"Hai bình đan dược màu vàng do Hàn Lập tặng riêng cho Vân Thiên Khiếu và Lệ Phong. Đối với phàm nhân có thể kéo dài tuổi thọ, cường thân kiện thể, không bị bệnh tật ốm đau, bảo đảm sống quá trăm tuổi.","congNang":["Kéo dài tuổi thọ cho phàm nhân @c0660","Cường thân kiện thể, không bệnh tật @c0660"],"nguon":["@c0660"]},{"id":"moc-linh-anh","name":"Mộc Linh Anh","cn":"木灵婴","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mộc Linh Anh là linh anh duy nhất, hiện nằm trên người Hàn Lập, bên trong chứa cấm chế cho phép cảm ứng đơn phương vị trí từ xa. Cả Hạm Vân Chi và nữ tử họ Liễu của Ngự Linh Tông đều muốn dung hợp nó để một bước lên trời đột phá cảnh giới.","detail":"Mộc Linh Anh là một linh anh độc nhất vô nhị, hiện do Hàn Lập mang trên người. Bên trong linh anh có chứa một cấm chế đặc thù, phát ra đạo linh lực bí mật quanh quẩn bên thân chủ nhân, cho phép người nắm bí công tương ứng cảm ứng đơn phương vị trí của linh anh từ xa. Nhóm tu sĩ Ngự Linh Tông đã lợi dụng đặc tính này để truy tìm Hàn Lập. Hạm Vân Chi cùng nữ tử họ Liễu thuộc Ngự Linh Tông đều khao khát dung hợp Mộc Linh Anh nhằm đột phá cảnh giới, cho thấy giá trị tu luyện cực lớn của linh anh này.","congNang":["Chứa cấm chế cho phép cảm ứng đơn phương vị trí từ xa — nhóm Ngự Linh Tông dùng bí công cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập @c0661","Phát ra đạo linh lực bí mật quanh quẩn bên người mang nó, Hàn Lập phát hiện linh lực này @c0661","Dung hợp có thể giúp đột phá cảnh giới (một bước lên trời)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0661","denChuong":"","cachCoDuoc":"Thu được từ trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0661","loai":"nhắc tới","importance":"major","giaiDoan":"Ngự Linh Tông truy tung vị trí Mộc Linh Anh","text":"Nhóm Ngự Linh Tông dùng bí công cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập. Hàn Lập phát hiện linh lực bí mật quanh người. Mộc Linh Anh chỉ có một, Hạm Vân Chi và Liễu sư muội cạnh tranh kịch liệt để giành cơ hội dung hợp.","anchor":"Mộc Linh Anh chỉ có một, nàng cùng Hạm Vân Chi bình thường biểu hiện ra ngoài là sư tỷ sư muội","phamCap":"Không rõ"}]},"nguon":["@c0661"],"dacDiem":"Là linh anh duy nhất, bên trong chứa cấm chế đặc thù, thường xuyên phát ra đạo linh lực bí mật bao quanh người sở hữu."},{"id":"phieu-linh-dai","name":"Phiêu Linh Đái","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phụ nhân họ Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo phong thuộc tính của phụ nhân họ Lâm, phối hợp Phong hỏa chi độn khiến tốc độ như hổ thêm cánh.","detail":"Pháp bảo phong thuộc tính mà phụ nhân họ Lâm tu luyện. Khi kết hợp với Phong hỏa chi độn, tốc độ tăng vượt bậc, đạt ngang Nguyên Anh Sơ Kỳ dù bản thân nàng chỉ Kết Đan Sơ Kỳ.","congNang":["Tăng tốc độ độn pháp, phối hợp Phong hỏa chi độn"],"dacDiem":"Phong thuộc tính","chuSoHuu":[{"ten":"Phụ nhân họ Lâm","tuChuong":"@c0662","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0662","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trong cuộc đào tẩu","text":"Phụ nhân họ Lâm dùng Phiêu Linh Đái phối hợp Phong hỏa chi độn, đạt tốc độ ngang Nguyên Anh Sơ Kỳ, chạy xa nhất bốn năm mươi dặm.","anchor":"bản thân nàng tu luyện một kiện pháp bảo phong thuộc tính “Phiêu Linh Đái” càng làm cho độn pháp như hổ thêm cánh"}]},"nguon":["@c0662"]},{"id":"dia-ngoc-luc-sac-theo-doi","name":"Đĩa ngọc lục sắc (bảo vật theo dõi)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hạm Vân Chi"],"trangThai":"đang sử dụng","blurb":"Đĩa ngọc lớn bằng bàn tay, trong suốt xanh biếc, vành khắc phù văn thượng cổ vàng bạc, tản linh khí lục sắc. Hiện quang điểm hồng theo dõi sinh tử và vị trí đồng bạn.","detail":"Bảo vật dùng theo dõi đồng bạn, trung tâm bóng loáng như gương, hiện các quang điểm hồng sắc lúc ẩn lúc hiện đại diện vị trí người được đánh dấu. Quang điểm tắt nghĩa là người đó đã chết. Hạm Vân Chi dùng để giám sát tình trạng nhóm đồng hành khi phân tán bỏ chạy.","congNang":["Theo dõi sinh tử và vị trí đồng bạn qua quang điểm hồng"],"chuSoHuu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0663","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0663","loai":"xuất hiện","importance":"normal","giaiDoan":"Hạm Vân Chi dùng theo dõi đồng bạn","text":"Hạm Vân Chi cưỡi linh cầm trắng noãn phi hành, tay cầm đĩa ngọc lục sắc theo dõi vị trí đồng bạn qua quang điểm hồng, phát hiện bốn đệ tử Trúc Cơ gần như cùng lúc bị giết.","anchor":"trên đó bóng loáng trong như gương, có bảy tám quang điểm hồng sắc lúc ẩn lúc hiện lấp lóe không ngừng"}]},"nguon":["@c0663"]},{"id":"luc-duc-suong-cong","name":"Lục Dực Sương Công","cn":"六翼霜蜈","category":"khac","categoryLabel":"Kỳ trùng","phamCap":"Xếp hạng 18 trên bảng kỳ trùng","soHuu":["Liễu sư muội","Hàn Lập"],"trangThai":"dang-co","blurb":"Lục Dực Sương Công là thượng cổ linh trùng thời kỳ hoang dã mang huyết thống chân long thuộc tính băng, xếp hạng 18 trên bảng kỳ trùng. Hình dạng phi thiên ngô công toàn thân đen, lưng mọc cánh trắng, phun băng sương đóng băng vạn vật. Ban đầu thuộc quyền nữ tu Ngự Linh Tông, sau bị Hàn Lập thu phục nhờ đã luyện hóa Kiền Lam Băng Diễm, và dần tiến hóa thêm một bậc.","detail":"Lục Dực Sương Công là giống thượng cổ linh trùng thời kỳ hoang dã cùng loại với Phệ Kim Trùng, mang huyết thống chân long thuộc tính băng. Ở dạng ấu trùng, chúng là đám phi thiên ngô công lớn khoảng một thước, toàn thân đen, lưng mọc hai cánh trắng, có khả năng phun băng sương trắng. Khi trưởng thành sẽ sinh đủ sáu cánh, hàn khí phun ra bao trùm trăm dặm đóng băng vạn vật. Chúng vốn thuộc quyền một nữ tu Ngự Linh Tông (Liễu sư muội), được thả ra phun băng sương chống cự Hàn Lập nhưng vô hiệu vì hắn đã luyện hóa Kiền Lam Băng Diễm, và bị Hàn Lập thu vào tay áo dễ dàng (@c0664). Sau đó Hàn Lập muốn chiếm hữu nhưng cần ép chủ cũ gỡ cấm chế nhận chủ trước, vì trên trùng có cấm chế nhận chủ và cấm chế tự bạo. Tới giai đoạn sau, đám Sương Công đã tiến thêm một bậc nhờ cắn nuốt, hình thể lớn gấp ","phanLoaiPhu":"Kỳ trùng / thượng cổ linh trùng","hinhDang":"Phi thiên ngô công (rét bay) khoảng một thước, toàn thân đen, lưng hai cánh trắng","nguonGoc":"Thượng cổ linh trùng thời kỳ hoang dã, huyết thống chân long thuộc tính băng","congNang":["Phun hàn khí băng sương đóng băng vạn vật (@c0664)","Trưởng thành sinh sáu cánh, hàn khí bao trùm trăm dặm","Uy lực hàn khí đủ đối phó tu sĩ Kết Đan kỳ","Đẻ trứng sinh sản, đã sinh 24 quả trứng đen óng ánh (@c0792)","Tiến hóa thêm một bậc nhờ cắn nuốt, hình thể lớn gấp đôi, phun hàn khí nhiều hơn (@c0792)"],"uyLuc":"Khi trưởng thành sinh sáu cánh, hàn khí phun ra bao trùm trăm dặm đóng băng vạn vật.","dacDiem":"Huyết thống chân long thuộc tính băng, hình dạng phi thiên ngô công toàn thân đen lưng mọc cánh trắng, có cấm chế nhận chủ và cấm chế tự bạo.","chuSoHuu":[{"ten":"Liễu sư muội","tuChuong":"@c0664","denChuong":"@c0664","cachCoDuoc":"Nuôi dưỡng","trangThai":"bi-cuop"},{"ten":"Hàn Lập","tuChuong":"@c0664","denChuong":"","cachCoDuoc":"Thu từ nữ tu Ngự Linh Tông, chưa gỡ cấm chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện, bị Hàn Lập thu phục","phamCap":"Xếp hạng 18 trên bảng kỳ trùng","text":"Nữ tu Ngự Linh Tông thả đám ấu trùng Lục Dực Sương Công phun băng sương chống cự Hàn Lập nhưng vô hiệu vì hắn đã luyện Kiền Lam Băng Diễm. Hàn Lập thu hết vào tay áo, bắt sống nữ tử để ép gỡ cấm chế nhận chủ.","anchor":"chính là kỳ trùng Lục Dực Sương Công xếp hạng thứ mưới tám trên bảng"},{"chuong":"@c0792","loai":"nâng cấp","importance":"normal","giaiDoan":"Tiến hóa + đẻ trứng","text":"Đã tiến thêm một bậc nhờ cắn nuốt, hình thể lớn gấp đôi, biết phun hàn khí nhiều. Đẻ 24 quả trứng đen óng ánh, phun băng bảo vệ.","anchor":"Chẳng những hình thể lớn hơn gấp đôi, ngoài ra nó còn biết phun ra hàn khí rất nhiều"}]},"capNhatToi":"@c0664","nguon":["@c0664","@c0792"]},{"id":"tho-linh-anh","name":"Thổ Linh Anh","cn":"土灵婴","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Linh Anh cấp Nguyên Anh","soHuu":["Ngự Linh Tông"],"trangThai":"đang giữ","blurb":"Một trong Ngũ Hành Linh Anh, được lão giả Kỳ Linh Sơn vô ý luyện chế ra vài năm trước, nhờ đó bí pháp Ngũ Hành Linh Anh mới được khôi phục.","detail":"Thổ Linh Anh được lão giả thạch thất vô ý luyện chế, là thành quả giúp khôi phục đại bí thuật Ngũ Hành Linh Anh đã thất truyền. Hiện do Ngự Linh Tông nắm giữ cùng hai Linh Anh khác.","nguon":["@c0665"]},{"id":"kim-linh-anh","name":"Kim Linh Anh","cn":"金灵婴","category":"khac","categoryLabel":"Linh Anh","phamCap":"Cực hiếm","soHuu":["Ngự Linh Tông"],"trangThai":"Ngự Linh Tông đang nắm giữ","blurb":"Loại Linh Anh thuộc tính kim, hiếm nhất trong năm loại. Ngự Linh Tông mới luyện chế được hơn mười năm trước, là điều kiện then chốt để tiến hành Dung hợp Linh Anh đại pháp.","detail":"Kim Linh Anh là loại Linh Anh thuộc tính kim cực hiếm, hiếm nhất trong năm loại Linh Anh cần thiết cho phép Dung hợp Linh Anh đại pháp. Hơn mười năm trước Ngự Linh Tông mới vô tình luyện chế thành công. Sau khi có Kim Linh Anh, tông môn mới tuyển mười tu sĩ Kết Đan làm ứng viên dung hợp và bắt đầu chuyên tu bí thuật liên quan.","boCha":"dung-hop-linh-anh-dai-phap","congNang":["Một trong 5 Linh Anh thuộc tính cần thiết cho phép Dung hợp Linh Anh đại pháp @c0666"],"chuSoHuu":[{"ten":"Ngự Linh Tông","tuChuong":"@c0666","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"xuat-hien","importance":"normal","giaiDoan":"Liễu Ngọc tiết lộ cho Hàn Lập","text":"Liễu Ngọc khai báo Kim Linh Anh là loại hiếm nhất, mới luyện được hơn mười năm trước, là mấu chốt khiến Ngự Linh Tông bắt đầu tuyển ứng viên dung hợp.","anchor":"Nhất là loại Kim Linh Anh hiếm thấy. Thẳng đến hơn mười năm trước, mới vô tình luyện chế được ra loại Linh Anh có thuộc tính này"}]},"nguon":["@c0666"]},{"id":"thiet-te-thu","name":"Thiết Tê Thú","cn":"铁犀兽","category":"khac","categoryLabel":"Linh thú","phamCap":"Quý hiếm","soHuu":["Hàn Lập"],"trangThai":"Bị Hàn Lập giam trong quang tráo","blurb":"Linh thú hình thanh ngưu, lưng có lân giáp, lực chiến ngang tu sĩ Kết Đan Trung Kỳ. Vốn là linh thú tổ truyền Phó Gia tại Nguyên Vũ Quốc, bị Hàn Lập đoạt sau khi diệt Phó Gia.","detail":"Thiết Tê Thú là linh thú quý hiếm hình dáng tựa thanh ngưu, lưng có lân giáp, sở hữu lực chiến ngang tu sĩ Kết Đan Trung Kỳ mà không hề rơi xuống hạ phong. Bị Hàn Lập nhốt trong quang tráo cấm chế thuộc tính thổ tại đại sảnh Lạc Vân Tông. Liễu Ngọc nhận ra đây là linh thú tổ truyền của Phó Gia tại Nguyên Vũ Quốc — gia tộc đã bị diệt. Hàn Lập dùng một đạo điện hồ cực nhỏ từ ngón tay đánh ngã nó dễ dàng để thị uy.","congNang":["Lực chiến ngang tu sĩ Kết Đan Trung Kỳ @c0666"],"chuSoHuu":[{"ten":"Phó Gia","tuChuong":"@c0666","denChuong":"@c0666","cachCoDuoc":"Tổ truyền","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0666","denChuong":"","cachCoDuoc":"Đoạt sau khi diệt Phó Gia","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập thị uy trước Liễu Ngọc","text":"Hàn Lập dùng một đạo điện hồ cực nhỏ đánh ngã Thiết Tê Thú trong quang tráo để thị uy trước Liễu Ngọc. Liễu Ngọc nhận ra đây là linh thú tổ truyền Phó Gia Nguyên Vũ Quốc.","anchor":"cũng có một linh thú tổ truyền như vậy. Nghe nói có thể lực địch tu sĩ Kết Đan Trung Kỳ mà không hề rơi xuống hạ phong"}]},"nguon":["@c0666"]},{"id":"kiem-lam-bang-diem","name":"Kiềm Lam Băng Diễm","cn":"钳蓝冰焰","category":"khac","categoryLabel":"Dị hỏa","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"dang-luyen-hoa","blurb":"Kiềm Lam Băng Diễm là một loại dị hỏa màu xanh biếc đang được Hàn Lập luyện hóa, quá trình luyện hóa toàn bộ cần khoảng hai trăm năm. Khi dung hợp với hàn khí từ Lục Dực Sương Công, băng diễm có thể biến thành chim lửa màu tím linh hoạt, đồng thời thời gian luyện hóa được rút ngắn đáng kể.","detail":"Kiềm Lam Băng Diễm là dị hỏa có sắc xanh biếc mà Hàn Lập đang trong quá trình luyện hóa. Theo lời Hàn Lập tiết lộ, mỗi tia băng diễm cần một năm để tiêu hóa, toàn bộ quá trình luyện hóa cần tối thiểu khoảng hai trăm năm. Tuy nhiên, hàn khí do Lục Dực Sương Công phun ra có khả năng rút ngắn thời gian luyện hóa rất nhiều, đồng thời mang lại tác dụng tăng phúc kỳ diệu cho băng diễm. Hàn Lập đã trình diễn năng lực của Kiềm Lam Băng Diễm bằng cách dung hợp sương hoa trắng (hàn khí) với băng diễm xanh biếc, tạo thành một con chim lửa màu tím nhỏ cỡ ngón tay bay múa linh hoạt.","congNang":["Dung hợp với sương hoa (hàn khí từ Lục Dực Sương Công) tạo thành chim lửa màu tím nhỏ cỡ ngón tay, bay múa linh hoạt (@c0667)","Hàn khí Lục Dực Sương Công rút ngắn thời gian luyện hóa và có tác dụng tăng phúc cho băng diễm (@c0667)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0667","denChuong":"","cachCoDuoc":"Chưa rõ (đang luyện hóa)","trangThai":"dang-luyen-hoa"}],"tabs":{"tienTrinh":[{"chuong":"@c0667","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tiết lộ tiến độ luyện hóa và dung hợp sương hoa lam diễm","text":"Hàn Lập tiết lộ mỗi tia cần một năm, toàn bộ cần khoảng hai trăm năm luyện hóa. Hàn khí Lục Dực Sương Công rút ngắn thời gian và tăng phúc. Trình diễn dung hợp sương hoa trắng với băng diễm xanh thành chim lửa tím nhỏ bay múa linh hoạt.","anchor":"muốn đem tất cả băng diễm thành sở hữu của mình, tối thiểu cũng cần hai trăm năm thời gian"}]},"capNhatToi":"@c0667","nguon":["@c0667"],"dacDiem":"Dị hỏa có sắc xanh biếc; mỗi tia cần một năm luyện hóa, toàn bộ cần khoảng hai trăm năm; khi dung hợp hàn khí chuyển thành sắc tím."},{"id":"lenh-bai-den","name":"Lệnh bài đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ngân Nguyệt"],"trangThai":"dang-dung","blurb":"Lệnh bài đen dùng để điều khiển linh thú gia tộc, phát ra hoàng quang bao trùm thú để khuất phục.","detail":"Hàn Lập lấy từ Túi trữ vật, vứt cho Ngân Nguyệt dùng để dạy dỗ tê thú. Lệnh bài bắn ra hoàng quang bao tê thú lại, tê thú phát ra tiếng kêu thê lương.","congNang":["Điều khiển, khuất phục linh thú gia tộc, phát hoàng quang bao trùm"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0668","denChuong":"@c0668","cachCoDuoc":"Có sẵn trong Túi trữ vật","trangThai":"da-giao"},{"ten":"Ngân Nguyệt","tuChuong":"@c0668","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập giao cho Ngân Nguyệt dùng dạy dỗ tê thú","text":"Hàn Lập lấy lệnh bài đen từ Túi trữ vật, vứt cho Ngân Nguyệt. Ngân Nguyệt dùng lệnh bài chiếu hoàng quang bao tê thú, truyền ra tiếng kêu thê lương.","anchor":"Hàn Lập từ trong Túi trữ vật móc ra một cái lệnh bài đen thui, vứt cho Ngân Nguyệt"}]},"nguon":["@c0668"]},{"id":"ma-diem-tim","name":"Ma diễm tím (vô danh)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Ma diễm vô danh Hàn Lập phát hiện khi hấp thu hàn khí rết Lục Dực Sương Công, uy lực hơn Kiền Lam Băng Diễm, tiềm năng ngang Tu La Thánh Hỏa.","detail":"Hàn Lập phát hiện ngẫu nhiên trong lúc hấp thu hàn khí từ rết Lục Dực Sương Công, uy lực vượt Kiền Lam Băng Diễm. Theo thời gian hàn khí Lục Dực Sương Công tăng mạnh, uy lực ma diễm cũng tăng theo, cuối cùng không kém Tu La Thánh Hỏa bao nhiêu. Ngân Nguyệt ban đầu ngỡ là Tu La Thánh Hỏa nhưng Hàn Lập phủ nhận.","congNang":["Ma diễm phòng thủ/tấn công, uy lực tăng theo hàn khí Lục Dực Sương Công"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0668","denChuong":"","cachCoDuoc":"Phát hiện ngẫu nhiên khi hấp thu hàn khí rết","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tiết lộ với Ngân Nguyệt","text":"Hàn Lập cho biết ma diễm vô danh phát hiện khi hấp thu hàn khí Lục Dực Sương Công, uy lực hơn Kiền Lam Băng Diễm, tiềm năng ngang Tu La Thánh Hỏa.","anchor":"uy lực so với Kiềm Lam Băng Diễm thì tốt hơn"}]},"nguon":["@c0668"]},{"id":"truyen-tin-phu","name":"Truyền tín phù","cn":"传信符","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Lữ trưởng lão"],"trangThai":"dang-co","blurb":"Phù lục dùng để liên lạc, bắn ra đạo ánh sáng hóa lửa xuyên qua cấm chế báo tin cho người trong động phủ.","detail":"Lữ trưởng lão bắn ra một đạo ánh sáng từ Truyền tín phù, hóa thành lửa xuyên qua cấm chế bên ngoài động phủ Hàn Lập để báo tin có người đến thăm.","nguon":["@c0670"]},{"id":"ngoc-gian-ban-do-nam-lung-hau","name":"Ngọc giản bản đồ của Nam Lũng Hầu","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản chứa bản đồ chỉ đường đến địa điểm tụ hội bí mật tại giao dịch hội, do Nam Lũng Hầu bí mật trao cho Hàn Lập.","detail":"Nam Lũng Hầu sau tỷ thí thần thức đã bắn ngọc giản này cho Hàn Lập, bên trong chứa bản đồ dẫn đến nơi tụ hội bí mật vào ngày thứ tư khi giao dịch hội bắt đầu. Hàn Lập thu nhận nhưng không xem ngay, cất vào túi trữ vật.","congNang":["Chứa bản đồ dẫn đến nơi tụ hội bí mật"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0673","denChuong":"@c0673","cachCoDuoc":"Tự chuẩn bị","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0673","denChuong":"","cachCoDuoc":"Được Nam Lũng Hầu trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0673","loai":"xuất hiện","importance":"normal","giaiDoan":"Được trao cho Hàn Lập","text":"Nam Lũng Hầu bắn ngọc giản chứa bản đồ cho Hàn Lập, mời tụ hội ngày thứ tư giao dịch hội.","anchor":"Ngọc giản này có một bản đồ, giao dịch hội bắt đầu vào thứ tư, đạo hữu theo bản đồ đó đến tụ hội"}]},"capNhatToi":"@c0673","dinhDanh":"goc","nguon":["@c0673"]},{"id":"mat-na-o-linh","name":"Mặt nạ ô linh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiên Tinh Chân Nhân"],"trangThai":"đang sử dụng","blurb":"Mặt nạ gỗ điêu khắc có phù văn ẩn hiện, do Thiên Tinh Chân Nhân phát cho tu sĩ tham dự Giao hoán hội để che giấu thân phận.","detail":"Ô mộc điêu khắc thành mặt nạ, mặt ngoài phù văn ẩn hiện. Dán sát da thịt, cảm giác lành lạnh mềm nhuyễn nhẹ như không. Ngay cả thần thức cường đại cũng không thể nhìn xuyên qua. Thiên Tinh Chân Nhân phát cho Hàn Lập và Lữ Lạc tại Giao hoán hội Nguyên Anh kỳ.","phanLoaiPhu":"Mặt nạ ngụy trang","hinhDang":"Mặt nạ gỗ ô mộc điêu khắc, phù văn ẩn hiện trên bề mặt","vatLieu":"Ô mộc","congNang":["Che giấu dung mạo","Chặn thần thức dò xét"],"dacDiem":"Dán sát da thịt, lành lạnh mềm nhuyễn nhẹ như không, thần thức cường đại không nhìn xuyên qua","chuHienThoi":"Thiên Tinh Chân Nhân (phát cho khách dự hội)","chuSoHuu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Tự chế/sở hữu sẵn","trangThai":"dang-co"},{"ten":"Hàn Lập","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Được Thiên Tinh Chân Nhân phát","trangThai":"dang-co"},{"ten":"Lữ Lạc","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Được Thiên Tinh Chân Nhân phát","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0675","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát tại Giao hoán hội","text":"Thiên Tinh Chân Nhân phát mặt nạ ô linh cho Hàn Lập và Lữ Lạc để che giấu thân phận tại Giao hoán hội Nguyên Anh kỳ. Hỏa Long Đồng Tử từ chối vì vóc người đặc biệt.","anchor":"hai luồng bạch quang hiện lên xuất hiện một cái ô mộc điêu khắc thành mặt nạ. Mặt ngoài phù văn ẩn hiện"}]},"capNhatToi":"@c0675","nguon":["@c0675"]},{"id":"xich-tinh-chi","name":"Xích tinh chi","cn":"赤星芝","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Đỉnh bật tài liệu luyện đan hỏa thuộc tính","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập sở hữu","blurb":"Xích tinh chi là linh chi ba ngàn năm thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, chỉ sinh trưởng quanh dung nham. Cẩm bào tu sĩ mất năm sáu năm khổ công thu được, đem ra hội trao đổi tu sĩ Nguyên Anh với giá mười vạn linh thạch; Hàn Lập dùng một khỏa thất cấp yêu đan thổ thuộc tính đổi thành công.","detail":"Xích tinh chi là linh chi ba ngàn năm, thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, có khói đỏ xoay quanh. Loại linh chi này chỉ sinh trưởng xung quanh dung nham, được xếp vào hàng tài liệu luyện đan hỏa thuộc tính đỉnh bật. Cẩm bào tu sĩ mất năm sáu năm khổ công mới thu hoạch được, sau đó mang tới hội trao đổi dành cho tu sĩ Nguyên Anh, ra giá mười vạn linh thạch hoặc chấp nhận tài liệu thổ thuộc tính cùng cấp. Hàn Lập dùng một khỏa thất cấp yêu đan thổ thuộc tính để đổi thành công. Hàn Lập nhận định linh chi này có thể dùng lục dịch thúc giục tăng trưởng niên hạn.","phanLoaiPhu":"Băng hỏa tinh chi","hinhDang":"Linh chi màu đỏ rực, toàn thân hỏa hồng, có khói đỏ xoay quanh","nguonGoc":"Sinh trưởng xung quanh dung nham, cẩm bào tu sĩ mất năm sáu năm khổ công thu được","dacDiem":"Linh chi ba ngàn năm thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, có khói đỏ xoay quanh, chỉ sinh trưởng xung quanh dung nham","chuHienThoi":"Hàn Lập","congNang":["Tài liệu luyện đan hỏa thuộc tính đỉnh bật @c0676","Có thể dùng lục dịch thúc giục tăng trưởng niên hạn @c0676"],"chuSoHuu":[{"ten":"Cẩm bào tu sĩ","tuChuong":"@c0676","denChuong":"@c0676","cachCoDuoc":"Năm sáu năm khổ công tìm được","trangThai":"da-ban"},{"ten":"Hàn Lập","tuChuong":"@c0676","denChuong":"","cachCoDuoc":"Đổi bằng thất cấp yêu đan thổ thuộc tính","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0676","loai":"đổi chủ","importance":"major","giaiDoan":"Cẩm bào tu sĩ trưng ra → Hàn Lập đổi được","text":"Cẩm bào tu sĩ trưng Xích tinh chi ba ngàn năm tại hội trao đổi Nguyên Anh, ra giá mười vạn linh thạch. Hàn Lập dùng một khỏa thất cấp yêu đan thổ thuộc tính đổi thành công.","anchor":"Hàn Lập đi vài bước đến trước mặt cẩm bào tu sĩ, bàn tay vừa lộn, một cái hộp ngọc liền xuất hiện"}]},"capNhatToi":"@c0676","dinhDanh":"goc","nguon":["@c0676"]},{"id":"khon-tien-hoan","name":"Khốn Tiên Hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nữ tu sĩ áo xanh nhạt"],"trangThai":"Chưa nhận chủ, đang được trao đổi","blurb":"Pháp bảo do nữ tu sĩ áo xanh nhạt tự luyện chế bằng kim tinh, kiêm công thủ, có thể vây địch hoặc hộ thân. Chưa nhận chủ, đem ra hội trao đổi Nguyên Anh.","detail":"Khốn Tiên Hoàn là pháp bảo do nữ tu sĩ áo xanh nhạt tinh thông luyện khí thuật tự luyện chế. Dùng kim tinh luyện thành, hình dạng tinh hoàn màu trắng cỡ một tấc, có thể biến lớn thành một trượng, trên bề mặt hiện ngân bạch sắc phù văn tản linh khí kinh người. Pháp bảo kiêm công thủ, dùng để vây địch hoặc hộ thân đều hiệu quả.","hinhDang":"Tinh hoàn màu trắng cỡ một tấc, biến lớn thành một trượng, trên bề mặt hiện ngân bạch sắc phù văn","vatLieu":"Kim tinh","dacDiem":"Kiêm công thủ, biến hóa lớn nhỏ, ngân bạch sắc phù văn tản linh khí","chuHienThoi":"Nữ tu sĩ áo xanh nhạt","congNang":["Kiêm công thủ, dùng vây địch hoặc hộ thân"],"chuSoHuu":[{"ten":"Nữ tu sĩ áo xanh nhạt","tuChuong":"@c0676","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-ban"}],"tabs":{"tienTrinh":[{"chuong":"@c0676","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu trưng bày tại hội trao đổi","text":"Nữ tu sĩ áo xanh nhạt giới thiệu Khốn Tiên Hoàn do chính mình luyện chế bằng kim tinh, kiêm công thủ, chưa nhận chủ, biểu diễn tinh hoàn biến lớn thành một trượng.","anchor":"Dùng để vây địch hoặc hộ thân, cũng cực kỳ hiệu quả, là pháp bảo kiêm công thủ"}]},"capNhatToi":"@c0676","dinhDanh":"goc","nguon":["@c0676"]},{"id":"hon-thach","name":"Hồn Thạch","cn":"魂石","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Linh vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang sử dụng (đổi một phần)","aliases":["Âm minh thú tinh"],"blurb":"Tên thượng cổ của Âm minh thú tinh, tinh thạch xanh ngọc phát ba động âm hàn kỳ lạ, được Thiên Tinh Chân Nhân ráo riết thu mua.","detail":"Hồn Thạch chính là Âm minh thú tinh mà Hàn Lập lấy được từ chỗ âm minh, chỉ khác cách gọi giữa cổ tu sĩ thượng cổ và người ở âm minh. Dạng tinh thạch xanh ngọc, phát ra ba động âm hàn, không thuộc thuộc tính mộc cũng không phải hồn khí thông thường. Viên mẫu Thiên Tinh Chân Nhân đưa ra chỉ cỡ ngón tay cái, còn viên Hàn Lập đưa ra đổi lớn cỡ trứng gà — cực kỳ hiếm. Khôi lỗi trong Hư Thiên Điện đều ngậm Hồn Thạch, cho thấy loại nguyên liệu này liên quan mật thiết đến việc vận hành khôi lỗi thượng cổ. Thiên Tinh Chân Nhân muốn thu thập nhiều Hồn Thạch, mưu đồ cụ thể chưa rõ.","nguon":["@c0678"]},{"id":"hang-linh-phu","name":"Hàng Linh Phù","cn":"降灵符","category":"khac","categoryLabel":"Phù lục / Mật phù","phamCap":"Cao cấp (mật phù ngũ hành)","soHuu":["Hàn Lập"],"trangThai":"Chưa luyện chế","blurb":"Mật phù ngũ hành uy lực cực lớn mà Hàn Lập dự định luyện chế, có thể cứu mạng ở thời điểm mấu chốt.","detail":"Hàng Linh Phù là phù lục cao cấp loại mật phù ngũ hành đặc thù, uy lực rất lớn theo ghi chép trên cốt phiến. Hàn Lập đã mua được nguyên liệu phụ trợ (giấy phù, mực cao cấp) tại phường thị phía tây Thành Điền Thiên, nhưng chưa tìm được bút chế phù đủ cấp — loại bút đỉnh cấp trong phường thị chỉ đủ chế phù lục cao cấp thông thường, không đủ cho mật phù này. Phù lục cao cấp tại tu tiên giới có khi còn quý hơn đỉnh cấp pháp khí. Chế phù sư Kết Đan kỳ cả Thiên Nam chỉ có mấy người, Nguyên Anh kỳ chuyên chế phù thì không có.","nguon":["@c0678"]},{"id":"tan-phu-mau-vang","name":"Tàn phù màu vàng","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Chưa rõ (nghi trân phẩm)","soHuu":["Tôn Hỏa"],"trangThai":"hu-hai","blurb":"Tờ phù lục màu vàng đã bị tàn phá gần một nửa, được Tôn Hỏa phát hiện lẫn trong đám phù lục cấp thấp và lập tức biến sắc giữ lại bằng mọi giá, ngụ ý giá trị vượt xa các phù lục thông thường xung quanh.","detail":"Tàn phù màu vàng xuất hiện khi Tôn Hỏa chuẩn bị giao đám phù lục cấp thấp làm vật bồi thường cho chưởng quỹ. Trong lúc kiểm tra, y phát hiện tờ phù lục màu vàng đã hư tổn gần một nửa liền lập tức biến sắc, vội vàng giữ lại không chịu giao đi. Phản ứng khẩn trương của Tôn Hỏa cho thấy tờ tàn phù này có giá trị đặc biệt, vượt hẳn phù lục cấp thấp thông thường. Tuy nhiên, cấp bậc chính xác, nguồn gốc và công năng cụ thể của tờ phù chưa được tiết lộ tại thời điểm hiện tại trong tiến trình.","congNang":[],"chuSoHuu":[{"ten":"Tôn Hỏa","tuChuong":"@c0679","denChuong":"","cachCoDuoc":"Có sẵn trong đám phù lục cấp thấp mang theo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"xuat-hien","importance":"major","giaiDoan":"Tôn Hỏa phát hiện trong đám phù bồi thường","phamCap":"Chưa rõ","text":"Tôn Hỏa khi chuẩn bị giao phù lục cấp thấp bồi thường, nhìn thấy tờ phù vàng tàn phá gần nửa liền biến sắc giữ lại không giao, phản ứng khẩn trương cho thấy giá trị đặc biệt.","anchor":"lập tức từ trong đám phù lấy ra một cái phù lục màu vàng đã bị tàn phá gần một nữa giữ lại"}]},"nguon":["@c0679"],"dacDiem":"Hình dạng tờ phù lục màu vàng đã bị tàn phá gần một nửa, lẫn trong đám phù lục cấp thấp nhưng được nhận ra ngay nhờ đặc điểm khác biệt @c0679."},{"id":"phu-luc-hai-nua","name":"Phù lục (hai nửa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập","Tôn Hỏa"],"trangThai":"da-huy","blurb":"Tín vật hai nửa do Tôn Nhị Cẩu và Hàn Lập mỗi người giữ một phiến, dùng để nhận diện hậu nhân Tôn gia với chủ nhân.","detail":"Hàn Lập ghép nửa phù lục của Tôn Hỏa với nửa của mình, hai phiến hoàn toàn ăn khớp không một khe hở, xác nhận Tôn Hỏa là hậu nhân chính thống. Sau đó Hàn Lập phát hồng quang thiêu hủy cả hai phiến thành tro bụi.","congNang":["Tín vật nhận chủ giữa Hàn Lập và dòng tộc Tôn gia, ghép hai nửa xác nhận thân phận"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0680","denChuong":"@c0680","cachCoDuoc":"Giữ từ trước","trangThai":"da-huy"},{"ten":"Tôn Hỏa","tuChuong":"@c0680","denChuong":"@c0680","cachCoDuoc":"Thừa kế từ Tôn Nhị Cẩu","trangThai":"da-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0680","loai":"dùng","importance":"normal","giaiDoan":"Ghép khớp rồi thiêu hủy","text":"Hàn Lập ghép hai nửa phù lục ăn khớp hoàn toàn, xác nhận Tôn Hỏa là hậu nhân Tôn Nhị Cẩu, rồi phát hồng quang thiêu hủy cả hai phiến thành tro bụi.","anchor":"đem hai phiến phù lục đến cùng nhau, chỗ hé ra hoàn toàn ăn khớp, một khe hở cũng không có"}]},"nguon":["@c0680"]},{"id":"bich-lam-ngoc-boi","name":"Bích lam ngọc bội (tương xứng tâm linh)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập","Mộ Phái Linh"],"trangThai":"đang dùng","blurb":"Một đôi ngọc bội bích lam tương xứng tâm linh. Hàn Lập giữ một chiếc, tặng Mộ Phái Linh chiếc còn lại. Rót linh lực vào tạo tầng phòng hộ và cảm ứng dù cách ngàn dặm.","detail":"Đôi ngọc bội bích lam tương xứng tâm linh. Hàn Lập tặng Mộ Phái Linh một chiếc, tự giữ chiếc còn lại. Khi rót linh lực vào sẽ tạo một tầng phòng hộ, đồng thời cho phép Hàn Lập cảm ứng được ngay dù cách xa ngàn dặm.","congNang":["Tạo tầng phòng hộ khi rót linh lực","Cảm ứng cự ly ngàn dặm giữa hai chiếc trong đôi"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0681","denChuong":"","cachCoDuoc":"Tự có sẵn, giữ một chiếc","trangThai":"dang-co"},{"ten":"Mộ Phái Linh","tuChuong":"@c0681","denChuong":"","cachCoDuoc":"Hàn Lập tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0681","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tặng Mộ Phái Linh một chiếc","text":"Hàn Lập trao cho Mộ Phái Linh một chiếc bích lam ngọc bội tương xứng tâm linh, dặn rót linh lực khi gặp nguy để hắn cảm ứng được dù cách ngàn dặm.","anchor":"chỉ cần rót linh lực vào đấy thì ta sẽ có mặt ngay lập tức"}]},"dinhDanh":"goc","nguon":["@c0681"]},{"id":"ngoc-gian-thuong-co-khoi-loi-thuat","name":"Ngọc giản Thượng cổ Khôi Lỗi Thuật","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Bạch ngọc giản bản gốc từ thượng cổ, ghi chép toàn bộ phương pháp luyện chế Khôi Lỗi nhiều cấp bậc. Thiên Tinh Chân Nhân trao cho Hàn Lập để đổi lấy Hồn Thạch tại @c0682.","detail":"Ngọc giản Thượng cổ Khôi Lỗi Thuật là một bạch ngọc giản bản gốc chứ không phải bản sao chép, ghi chép phương pháp luyện chế Khôi Lỗi từ thời thượng cổ. Nội dung bao gồm cách luyện chế Khôi Lỗi cao cấp (uy lực ngang tu sĩ Nguyên Anh Trung Kỳ) và Khôi Lỗi cấp thấp (uy lực ngang tu sĩ Kết Đan Kỳ), kèm theo hình vẽ các loại tài liệu cần thiết cho việc luyện chế. Tài liệu chính bao gồm vạn năm thiết mộc cùng nhiều phụ liệu cực kỳ hiếm có. Ngọc giản được Thiên Tinh Chân Nhân dùng để đổi lấy Hồn Thạch từ Hàn Lập.","congNang":["Ghi chép phương pháp luyện chế Khôi Lỗi cao cấp, uy lực ngang tu sĩ Nguyên Anh Trung Kỳ @c0682","Ghi chép phương pháp luyện chế Khôi Lỗi cấp thấp, uy lực ngang tu sĩ Kết Đan Kỳ @c0682","Kèm hình vẽ các loại tài liệu cần thiết cho việc luyện chế @c0682"],"chuSoHuu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"","denChuong":"@c0682","cachCoDuoc":"Tìm được","trangThai":"đã trao đi"},{"ten":"Hàn Lập","tuChuong":"@c0682","denChuong":"","cachCoDuoc":"Đổi bằng Hồn Thạch từ Thiên Tinh Chân Nhân","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0682","loai":"đổi chủ","importance":"major","giaiDoan":"Thiên Tinh Chân Nhân trao cho Hàn Lập","text":"Thiên Tinh Chân Nhân trao bạch ngọc giản gốc ghi Thượng cổ Khôi Lỗi Thuật cho Hàn Lập để đổi lấy hai ba mươi khối Hồn Thạch. Ngọc giản là bản gốc, có hình vẽ tài liệu cần thiết.","anchor":"Đây là cái ngọc giản có ghi chép lại cách luyện chế Khôi Lỗi, không phải là những cái sao chép"}]},"nguon":["@c0682"],"dacDiem":"Là bạch ngọc giản bản gốc từ thượng cổ, không phải bản sao chép; tài liệu chính cần dùng gồm vạn năm thiết mộc cùng nhiều phụ liệu cực hiếm."},{"id":"canh-tinh-dau-gia-c682","name":"Canh Tinh (khối đấu giá)","category":"nguyen-lieu","categoryLabel":"Khoáng thạch","phamCap":"Không rõ","soHuu":["Tu sĩ ngân bào"],"trangThai":"đã bán","blurb":"Khối khoáng thạch Canh Tinh nhỏ bằng hạt hạch đào màu vàng, hào quang chớp động, được đấu giá với giá 76 vạn linh thạch tại Điền Thiên Thành. Hàn Lập bỏ cuộc ở mốc 50 vạn.","detail":"Khối Canh Tinh nhỏ bằng hạt hạch đào, màu vàng với hào quang chớp động. Được bán tại phiên đấu giá Điền Thiên Thành với giá cuối cùng 76 vạn linh thạch, vượt quá khả năng tài chính của Hàn Lập.","congNang":["Tài liệu cho Đại Canh Kiếm Trận"],"tabs":{"tienTrinh":[{"chuong":"@c0682","loai":"xuất hiện","importance":"normal","giaiDoan":"Đấu giá tại Điền Thiên Thành","text":"Khối Canh Tinh được đấu giá, Hàn Lập bỏ cuộc ở mốc 50 vạn, cuối cùng bán với giá 76 vạn linh thạch cho tu sĩ ngân bào.","anchor":"Bảy mươi sáu vạn linh thạch, khối Canh Tinh này là của đạo hữu"}]},"nguon":["@c0682"]},{"id":"tinh-ban-di-bao","name":"Tinh bàn dị bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Đạm hồng sắc ngọc bàn hình tròn của Nam Lũng Hầu, kích hoạt bằng chú ngữ và kim quang, hiện đồ án nhật nguyệt thiên tượng xác định phương hướng trong bão cát khi thần thức bị phong tỏa.","detail":"Viên bàn ngọc hình tròn màu hồng nhạt. Khi kích hoạt bằng niệm chú bắt quyết và bắn kim quang, trên bề mặt xuất hiện kim tinh điểm điểm cùng đồ án kỳ quái ám ngậm tinh thần nhật nguyệt thiên tượng, dùng để xác định phương hướng trong môi trường bão cát phong tỏa thần thức.","hinhDang":"Ngọc bàn hình tròn, đạm hồng sắc","congNang":["Xác định phương hướng khi thần thức bị phong tỏa"],"dacDiem":"Kim hồng lưỡng sắc dị quang, phù văn lưu động","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng xác định phương hướng","text":"Nam Lũng Hầu lấy ra trong bão cát, niệm chú bắt quyết bắn kim quang kích hoạt, trên viên bàn hiện đồ án nhật nguyệt thiên tượng, xác định phương hướng dẫn đoàn bay đi.","anchor":"trên viên bàn kim tinh điểm điểm, xuất hiện ra một cái đồ án kỳ quái ám ngậm tinh thần nhật nguyệt thiên tượng"}]},"nguon":["@c0687"]},{"id":"ma-tran-phien","name":"Ma Trần Phiên","cn":"魔塵幡","category":"than-khi","categoryLabel":"Trấn tộc thánh khí","phamCap":"Trấn tộc thánh khí","soHuu":["Hoàng Sa Bộ"],"trangThai":"phong-an","blurb":"Ma Trần Phiên là trấn tộc thánh khí của Hoàng Sa Bộ, gồm 36 can phiên. Có khả năng vây khốn tu sĩ Nguyên Anh Kỳ trong nửa khắc, nhưng tổ huấn lịch đại quy định tuyệt đối không được sử dụng nếu chưa đến lúc nguy cơ diệt tộc.","detail":"Ma Trần Phiên là bộ 36 can phiên (cờ/phướn), giữ vai trò trấn tộc thánh khí của Hoàng Sa Bộ. Uy lực của bộ phiên đủ để vây khốn tu sĩ Nguyên Anh Kỳ trong khoảng nửa khắc, song không đủ gây thương tổn nặng. Tổ tiên lịch đại của Hoàng Sa Bộ để lại tổ huấn nghiêm ngặt: chỉ khi bộ tộc đối mặt nguy cơ bị diệt tộc mới được phép sử dụng. Lý do là nếu Ma Trần Phiên bị hư hao dù chỉ vài can, Hoàng Sa Bộ sẽ mất tư cách dẫn đầu liên quân mười đại bộ tộc, thậm chí đứng trước nguy cơ bị diệt tộc. Tại @c0687, khi pháp sĩ bạch quang đề nghị dùng Ma Trần Phiên để vây khốn nhóm tu sĩ, Đại Thượng Sư đã khiển trách nghiêm khắc, cho thấy điều kiện sử dụng được chấp hành cực kỳ chặt chẽ.","congNang":["Vây khốn tu sĩ cao giai (Nguyên Anh Kỳ) trong nửa khắc @c0687"],"dacDiem":"Gồm 36 can phiên; điều kiện sử dụng cực kỳ nghiêm ngặt — chỉ khi đối mặt nguy cơ diệt tộc mới được phép dùng, nếu hư hao sẽ khiến Hoàng Sa Bộ mất tư cách dẫn đầu liên quân mười đại bộ tộc.","chuSoHuu":[{"ten":"Hoàng Sa Bộ","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Trấn tộc truyền thừa","trangThai":"phong-an"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"major","giaiDoan":"Hé lộ tồn tại và tổ huấn","text":"Pháp sĩ bạch quang đề nghị dùng Ma Trần Phiên vây nhóm tu sĩ. Đại Thượng Sư khiển trách nghiêm khắc, nhấn mạnh tổ huấn: không tới lúc diệt tộc tuyệt đối không sử dụng, hư hao sẽ mất tư cách dẫn đầu liên quân mười đại bộ tộc.","anchor":"Ba mươi sáu can Ma Trần Phiên đâu có thể tùy ý vận dụng"}]},"nguon":["@c0687"],"uyLuc":"Đủ sức vây khốn tu sĩ Nguyên Anh Kỳ trong nửa khắc, nhưng không đủ gây thương tổn nặng."},{"id":"ngu-phong-xa","name":"Ngự Phong Xa","cn":"御風車","category":"phap-bao","categoryLabel":"Trấn tộc bảo vật","phamCap":"Trấn tộc bảo vật","soHuu":["Thiên Phong Bộ","Pháp sĩ Mộ Lan","Hàn Lập"],"trangThai":"dang-co","blurb":"Ngự Phong Xa là trấn tộc bảo vật của Thiên Phong Bộ thuộc bộ tộc Mộ Lan, một cỗ xe bay bốn cánh có tốc độ di chuyển cực cao, vượt xa độn quang thường, có thể chở nhiều tu sĩ Nguyên Anh Kỳ đường dài. Sau này pháp bảo rơi vào tay Hàn Lập và được sử dụng để chở người bay về phía cực tây.","detail":"Ngự Phong Xa là pháp bảo trấn tộc của Thiên Phong Bộ, một trong các bộ lạc thuộc tộc Mộ Lan. Tốc độ của nó được đánh giá là kinh khủng, đủ sức đuổi theo tu sĩ đang độn quang, điều này khiến nó trở thành mối đe dọa đáng kể khi truy kích. Khi bay, Ngự Phong Xa hóa thành bạch hồng lao đi, phát ra ma âm xé gió, đồng thời bạch quang bảo hộ bao bọc che chắn cho những người bên trong. Pháp bảo này từng chở năm pháp sĩ Nguyên Anh Kỳ Mộ Lan truy đuổi nhóm Nam Lũng Hầu sau khi rời Hoàng Sa Phong Trận. Có điều kiện là cần tụ tập đủ nhân thủ mới có thể xuất phát sử dụng. Về sau Hàn Lập có được Ngự Phong Xa, dùng nó cùng Mộ Phái Linh và Ngân Nguyệt hóa bạch hồng bay đi cực tây.","congNang":["Di chuyển tốc độ cực cao, vượt xa độn quang thường, đủ sức truy đuổi tu sĩ đang chạy @c0687","Chở nhiều người cùng lúc, ít nhất năm tu sĩ Nguyên Anh Kỳ @c0688","Bạch quang bảo hộ bao bọc che chắn bên trong khi bay @c0792","Phát ma âm xé gió khi bay","Hóa bạch hồng khi phóng đi, dùng di chuyển đường dài @c0792"],"dacDiem":"Trấn tộc bảo vật của Thiên Phong Bộ thuộc bộ tộc Mộ Lan, là cỗ xe bay bốn cánh, khi phóng hóa bạch hồng, cần tụ tập đủ nhân thủ mới xuất phát sử dụng","chuSoHuu":[{"ten":"Thiên Phong Bộ","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Trấn tộc truyền thừa","trangThai":"dang-co"},{"ten":"Pháp sĩ Mộ Lan (không rõ ai)","tuChuong":"@c0688","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ tồn tại","text":"Được pháp sĩ điện hồ nhắc tới khi phân tích: Thiên Phong Bộ có Ngự Phong Xa tốc độ kinh khủng có thể đuổi theo nhưng cần tụ nhân thủ mới xuất phát.","anchor":"lấy Thiên Phong Bộ pháp bảo “Ngự Phong Xa” có tốc độ kinh khủng cũng chưa chắc không phải là không thể đuổi theo mấy người này"},{"chuong":"@c0688","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện truy đuổi nhóm tu sĩ Thiên Nam","text":"Ngự Phong Xa chở năm pháp sĩ Nguyên Anh Kỳ Mộ Lan truy đuổi nhóm Nam Lũng Hầu sau khi rời Hoàng Sa Phong Trận. Bốn pháp sĩ xuống xe chia bốn hướng đuổi, Ngự Phong Xa quay sang nhắm riêng Hàn Lập truy đuổi vào sâu thảo nguyên.","anchor":"Ngự Phong Xa phần thân nhẵn nhụi trắng tinh, chẳng biết do xương thú nào luyện chế thành, mà lại ẩn chứa một cổ sát khí hung bạo"},{"chuong":"@c0792","loai":"dùng","importance":"normal","giaiDoan":"Dùng đi Cực Tây","text":"Hàn Lập phóng ra Ngự Phong Xa, cùng Mộ Phái Linh và Ngân Nguyệt lên xe hóa bạch hồng bay đi cực tây.","anchor":"một đạo bạch quang từ trong đó bay ra hoá thành một cổ xe bốn cánh thì ra đúng là Ngự Phong Xa"}]},"nguon":["@c0687","@c0688","@c0792"],"uyLuc":"Tốc độ kinh khủng đủ sức truy đuổi tu sĩ đang độn quang, chở năm pháp sĩ Nguyên Anh Kỳ truy kích sau khi xuất phát @c0688"},{"id":"bao-chau-lam-muc-lao-gia","name":"Bảo châu lam (của Mục lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Mục lão giả"],"trangThai":"dang-dung","blurb":"Hạt châu to bằng nắm tay của Mục lão giả, có thể tạo quang mạc phòng thủ và kết quang võng chống đỡ cự kiếm.","detail":"Mục lão giả dùng một quyền tung bảo châu ra tạo lam quang mạc phòng thủ chặn kiếm quang. Sau đó phun tinh khí lên châu, châu phóng lam sắc tế ti kết thành quang võng chống đỡ được cự kiếm hợp nhất từ hơn 200 kiếm quang của Hàn Lập.","congNang":["Tạo lam quang mạc phòng thủ chặn kiếm quang","Phóng lam sắc tế ti kết quang võng chống đỡ cự kiếm"],"hinhDang":"Hạt châu to bằng nắm tay, phóng lam quang","chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0689","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0689","loai":"dùng","importance":"normal","giaiDoan":"Giao đấu với Hàn Lập","text":"Mục lão giả tung bảo châu tạo quang mạc chặn kiếm quang, sau phun tinh khí kết quang võng chống đỡ cự kiếm hợp nhất.","anchor":"xuất ra một khỏa hạt châu to bằng nắm tay"}]},"nguon":["@c0689"]},{"id":"hoa-lam-co-bao","name":"Hoa lam cổ bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (không rõ cấp)","soHuu":["Hàn Lập","Nhạc thượng sư"],"trangThai":"Nhạc thượng sư nhận lại từ Trọng Thần Sư","blurb":"Cổ bảo băng thuộc tính của Hàn Lập, rời tay hóa bạch khí hút thu băng tinh, phát băng hàn linh lực cảm ứng kinh người khiến pháp sĩ tu luyện băng thuộc tính hơn trăm năm cũng phải lo sợ. Sau bị Ngân Nguyệt đoạt, rồi lại bị Trọng Thần Sư cướp lại và trao cho Nhạc thượng sư.","detail":"Hoa lam cổ bảo có hình dáng long lanh trong suốt, xinh đẹp dị thường. Khi Hàn Lập đối địch, xuất cổ bảo hóa bạch khí hút thu toàn bộ băng tinh của Băng Tinh Thuật, hóa giải hoàn toàn công kích băng thuộc tính, đồng thời phát ra băng hàn linh lực cảm ứng cực mạnh, khiến Mạc lão giả — người tu luyện băng thuộc tính hơn trăm năm — cũng kinh sợ (@c0690). Về sau, cổ bảo bị Ngân Nguyệt đoạt được, nhưng lập tức bị Trọng Thần Sư dùng ngân sắc đại thủ cướp lại và trao cho Nhạc thượng sư (@c0743). Từ thời điểm đó, pháp bảo không còn thuộc về Hàn Lập.","hinhDang":"Long lanh trong suốt, hình hoa lam, xinh đẹp dị thường","congNang":["Hóa bạch khí hút thu toàn bộ băng tinh, hóa giải hoàn toàn công kích băng thuộc tính (@c0690)","Phát băng hàn linh lực cảm ứng cực mạnh từ xa, khiến pháp sĩ tu luyện băng thuộc tính lâu năm cũng kinh sợ (@c0690)"],"dacDiem":"Hoạt động từ xa, cảm ứng linh lực băng hàn vượt trội; hình dáng long lanh trong suốt, xinh đẹp dị thường.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0690","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"},{"ten":"Ngân Nguyệt","tuChuong":"@c0743","denChuong":"@c0743","cachCoDuoc":"Đoạt trong chiến đấu","trangThai":"bi-cuop"},{"ten":"Nhạc thượng sư","tuChuong":"@c0743","denChuong":"","cachCoDuoc":"Trọng Thần Sư trả lại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"dùng","importance":"major","giaiDoan":"Lần đầu xuất hiện trong trận đấu","text":"Hàn Lập xuất hoa lam cổ bảo hóa bạch khí hút thu toàn bộ băng tinh của Băng Tinh Thuật. Mạc lão giả tu luyện băng thuộc tính hơn trăm năm kiêng dè lo sợ trước băng hàn linh lực kinh người của bảo vật này.","anchor":"vẫn cảm ứng băng hàn linh lực kinh người mặc dù có chút lạ lẫm làm cho lão giả kinh sợ"},{"chuong":"@c0743","loai":"doi-chu","importance":"major","giaiDoan":"Bị đoạt rồi cướp lại","text":"Ngân Nguyệt đoạt được nhưng bị Trọng Thần Sư cướp lại bằng ngân sắc đại thủ, trả cho Nhạc thượng sư.","anchor":"một tay cầm Tử Thành Đâu, một tay dẫn theo Hoa Lam Cổ Bảo"}]},"nguon":["@c0690","@c0743"],"uyLuc":"Phát ra băng hàn linh lực cảm ứng kinh người, khiến Mạc lão giả tu luyện băng thuộc tính hơn trăm năm cũng phải lo sợ; hóa bạch khí hút thu toàn bộ băng tinh của Băng Tinh Thuật (@c0690)."},{"id":"vien-chau-phap-bao-muc-lao-gia","name":"Viên châu pháp bảo (Mục lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Mục lão giả"],"trangThai":"dang-dung","blurb":"Pháp bảo phòng ngự của Mục lão giả, triệu hồi về đỉnh đầu phun linh khí xuất quang mạc bảo hộ.","detail":"Được Mục lão giả triệu hồi sau khi bị Kinh Long chung chấn và cự kiếm truy kích, bay đến trên đỉnh đầu phun linh khí tạo quang mạc hộ thể.","congNang":["Xuất quang mạc hộ thể phòng ngự"],"chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0690","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"dùng","importance":"normal","giaiDoan":"Triệu hồi phòng ngự trong trận đấu với Hàn Lập","text":"Mục lão giả triệu hồi viên châu pháp bảo về đỉnh đầu, phun linh khí xuất quang mạc bảo hộ sau khi bị Kinh Long chung chấn và cự kiếm truy kích.","anchor":"pháp bảo này bay đến trên đỉnh đầu, trong miệng phun ra một tia linh khí"}]},"nguon":["@c0690"]},{"id":"thien-trong-phong","name":"Thiên Trọng Phong","cn":null,"aliases":["Hắc phong","ngọn hắc sơn","hắc sắc tiểu sơn","ngọn núi đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo thượng cổ","soHuu":["Mục lão giả"],"trangThai":"không rõ","blurb":"Thiên Trọng Phong là cổ bảo thượng cổ hình ngọn núi đen, có uy lực kinh người đến mức tu sĩ Nguyên Anh Hậu Kỳ cũng khó cường ngạnh đỡ, được Hàn Lập nhận định là di vật của tu sĩ thượng cổ lưu lại chứ không phải vật tự luyện chế.","detail":"Thiên Trọng Phong là một cổ bảo có nguồn gốc từ thời thượng cổ, do tu sĩ viễn cổ lưu lại, được Mục lão giả sử dụng trong trận chiến với Hàn Lập. Pháp bảo mang hình dáng ngọn núi đen, khi kích phát phóng ra quang hoa cực lớn có thể áp chế pháp bảo đối thủ, khiến kiếm quang và ngân chung của Hàn Lập bị giảm uy lực đại bộ phận. Hàn Lập đánh giá cao cổ bảo này, muốn thu lấy để bù đắp khuyết điểm về mặt công kích. Sau trận đấu, Nguyên Anh của Mục lão giả chỉ kịp thu bảo châu, hắc sơn có khả năng bị bỏ lại tại chiến trường (@c0691).","congNang":["Phóng quang hoa lớn áp chế pháp bảo cấp Nguyên Anh, khiến uy lực bị giảm đại bộ phận (@c0691)"],"chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0691","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"thân xác bị hủy, hắc sơn có thể bị bỏ lại"}],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"dùng","importance":"major","giaiDoan":"Trận chiến Mục lão giả vs Hàn Lập","text":"Hắc sơn phóng quang hoa lớn áp chế kiếm quang và ngân chung của Hàn Lập, giảm uy lực đại bộ phận. Hàn Lập nhận định là cổ bảo thượng cổ, Nguyên Anh Hậu Kỳ khó đỡ, muốn thu để bù khuyết điểm công kích. Sau trận Nguyên Anh chỉ thu bảo châu, hắc sơn có khả năng bị bỏ lại.","anchor":"Bảo vật kỳ lạ có uy lực kinh người kia, vừa nhìn cũng biết không phải vật mà lão già này có thể luyện chế"}]},"uyLuc":"Khi kích phát, quang hoa áp chế cả kiếm quang lẫn ngân chung của tu sĩ Nguyên Anh, giảm uy lực đại bộ phận, đến mức Nguyên Anh Hậu Kỳ cũng khó cường ngạnh đỡ (@c0691).","dacDiem":"Hình dáng ngọn núi đen, là cổ bảo thượng cổ do tu sĩ viễn cổ lưu lại, không phải vật tự luyện chế."},{"id":"thanh-minh-cham-phu-bao","name":"Thanh Minh Châm","category":"phap-bao","categoryLabel":"Phù bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"dùng","importance":"normal","giaiDoan":"Tấn công Mục lão giả ở cự ly mười trượng","text":"Hàn Lập phóng Thanh Minh Châm, vô số thanh ti xuyên thủng quang mạc lam nhưng gặp Tinh Băng Thuẫn bị hóa thành băng châm rơi xuống, hoàn toàn thất hiệu.","anchor":"vô số thanh ti liền xuyên thủng quang mạc màu lam, trực tiếp kích khắp tứ phía băng thuẫn"}]},"blurb":"Thanh Minh Châm phù bảo là phù bảo màu xanh do tu sĩ Nguyên Anh kỳ luyện chế, được Nho Sam lão giả tặng cho Hàn Lập trước khi vào thông đạo. Có uy lực vượt xa pháp bảo bình thường nhưng chỉ sử dụng được một lần, Hàn Lập đã phóng ra trong thực chiến với biểu hiện vô số thanh ti xuyên thủng quang mạc.","detail":"Thanh Minh Châm phù bảo là một phù bảo màu xanh được Nho Sam lão giả lấy ra và mỉm cười tặng cho Hàn Lập nhằm phòng thân. Theo lời Nho Sam lão giả, phù bảo này do tu sĩ Nguyên Anh kỳ luyện chế, có uy lực mạnh hơn nhiều so với pháp bảo bình thường, thuộc loại vật phẩm chỉ dùng được một lần. Việc tặng phù bảo này thể hiện sự quan tâm của Nho Sam lão giả đối với sự an nguy của Hàn Lập. Về sau, Hàn Lập đã thực sự sử dụng Thanh Minh Châm trong chiến đấu: khi phóng ra, phù bảo hóa thành vô số thanh ti xuyên thủng quang mạc lam sắc, tuy nhiên khi đối mặt với Tinh Băng Thuẫn thì bị hóa giải.","uyLuc":"Theo lời Nho Sam lão giả, uy lực mạnh hơn nhiều so với pháp bảo bình thường; khi phóng ra hóa vô số thanh ti xuyên thủng quang mạc lam, nhưng gặp Tinh Băng Thuẫn thì bị hóa giải @c0466 @c0691","dacDiem":"Phù bảo màu xanh, do tu sĩ Nguyên Anh kỳ luyện chế, chỉ sử dụng được một lần","congNang":["Uy lực cực mạnh, vượt xa pháp bảo bình thường, do tu sĩ Nguyên Anh kỳ luyện chế @c0466","Khi phóng ra hóa thành vô số thanh ti có khả năng xuyên thủng quang mạc @c0691"]},{"id":"tui-tru-vat-muc-lao-gia","name":"Túi Trữ Vật màu bạc (của Mục lão giả)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Túi Trữ Vật màu bạc của Mục lão giả, bị Hàn Lập thu sau trận chiến. Bên trong nghèo nàn bất thường đối với tu sĩ Nguyên Anh Kỳ.","detail":"Chỉ chứa mười mấy khối Linh Thạch Bậc Trung, nguyên liệu luyện khí tầm thường, vài bình đan dược tàm thường, không có ngọc giản pháp quyết nào. Hàn Lập thất vọng vì không tìm được bí quyết phóng pháp thuật uy lực lớn trong nháy mắt.","chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0689","denChuong":"@c0692","cachCoDuoc":"","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0692","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm sau khi Mục lão giả bại trận","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0692","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu chiến lợi phẩm","text":"Hàn Lập thu Túi Trữ Vật màu bạc nhưng thất vọng vì bên trong chỉ có đồ tầm thường, không có ngọc giản pháp quyết.","anchor":"Đường đường là một gã tu sĩ Nguyên Anh Kỳ mà trên người chẳng có bao nhiêu thứ tốt"}]},"nguon":["@c0692"]},{"id":"ngan-sac-bao-vat-bach-sam-lao-gia","name":"Ngân sắc bảo vật (của Bạch sam lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Vật thể cỡ nắm tay phát ngân sắc tinh quang, Bạch sam lão giả há miệng phun ra, phiêu phù trước ngực. Uy lực đủ khiến hai pháp sĩ Nguyên Anh Sơ Kỳ kiêng dè lùi lại đề phòng.","detail":"Bạch sam lão giả há miệng phun ra vật thể ngân sắc cỡ nắm tay, tinh quang bắn bốn phía, phiêu phù trước ngực. Hai pháp sĩ Nguyên Anh Sơ Kỳ đối diện lập tức lui về phía sau đề phòng khi thấy bảo vật này xuất hiện.","congNang":["Khiến đối thủ Nguyên Anh Sơ Kỳ kiêng dè"],"hinhDang":"Cỡ nắm tay, ngân sắc, phun từ miệng","chuSoHuu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Bạch sam lão giả há miệng phun ra vật ngân sắc cỡ nắm tay trước khi giao chiến với hai pháp sĩ Mộ Lan, khiến đối phương kiêng dè lùi lại.","anchor":"nhất điểm ngân sắc từ trong miệng phun ra"}]},"nguon":["@c0693"]},{"id":"kim-sac-phi-kiem-nam-lung-hau","name":"Kim sắc phi kiếm (của Nam Lũng Hầu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Phi kiếm kim sắc của Nam Lũng Hầu, được phóng ra từ tay áo khi chuẩn bị giao chiến với hai pháp sĩ Mộ Lan Nguyên Anh Sơ Kỳ.","detail":"Nam Lũng Hầu vung tay áo phóng ra kim sắc phi kiếm khi đối đầu hai pháp sĩ Mộ Lan, chuẩn bị giao chiến.","congNang":["Phi kiếm tấn công"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nam Lũng Hầu vung tay áo phóng ra kim sắc phi kiếm chuẩn bị giao chiến với hai pháp sĩ Mộ Lan.","anchor":"một cái kim sắc phi kiếm từ trong tay áo bay ra"}]},"nguon":["@c0693"]},{"id":"hai-la-tieu-ky-pha-cam-che","name":"Hai lá tiểu kỳ (phá cấm chế)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu","Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Hai lá tiểu kỳ rộng cỡ vài thốn, một lá lục quang trong suốt, một lá màu vàng ẩn hiện phù văn. Nam Lũng Hầu và Bạch sam lão giả dùng để phá cấm chế ngoại tầng động phủ thượng nhân tại thạch sơn.","detail":"Nam Lũng Hầu và Bạch sam lão giả mỗi người rút ra một lá tiểu kỳ rộng cỡ vài thốn: một lá phát lục quang trong suốt, một lá màu vàng ẩn hiện phù văn di chuyển. Hai người niệm chú khiến tiểu kỳ run rẩy rồi phóng vào núi đá, kích hoạt cấm chế khiến mặt đất rung động dữ dội.","congNang":["Phá cấm chế ngoại tầng động phủ"],"hinhDang":"Rộng cỡ vài thốn, một lá lục quang trong suốt, một lá vàng có phù văn","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"},{"ten":"Bạch sam lão giả","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"dung","importance":"normal","giaiDoan":"Phá cấm chế ngoại tầng thạch sơn","text":"Nam Lũng Hầu và Bạch sam lão giả niệm chú phóng hai lá tiểu kỳ vào núi đá, kích hoạt cấm chế ngoại tầng động phủ thượng nhân, mặt đất rung động dữ dội.","anchor":"tiểu kỳ nhanh như chớp chui vào núi đá mất tung mất tích"}]},"nguon":["@c0693"]},{"id":"loi-hoa-truy","name":"Lôi Hỏa Trùy","cn":"雷火锥","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo","soHuu":["Thai phu nhân"],"trangThai":"dang-co","blurb":"Lôi Hỏa Trùy là Cổ Bảo cổ đại song thuộc tính lôi hỏa, hình tiêm trùy, sở hữu tốc độ tự thân cực nhanh khiến tu sĩ Nguyên Anh Kỳ cũng khó tránh né. Chuyên dùng để phá cấm chế và vòng bảo hộ, khi kích hoạt tỏa hỏa lãng cực nóng tràn ngập không gian xung quanh.","detail":"Lôi Hỏa Trùy là bảo vật hình tiêm trùy (mũi nhọn) thuộc hàng Cổ Bảo cổ đại. Khi kích hoạt, toàn thân trùy phủ hỏa quang hồng sắc, bên trong hỏa quang có tia điện bạch sắc nhảy múa, thể hiện rõ song thuộc tính lôi hỏa đặc trưng. Thai phu nhân rút Lôi Hỏa Trùy ra nhằm phá Thái Diệu Thần Cấm; khi phun tinh quang, hỏa lãng cực nóng tràn khắp sảnh đường, tu sĩ Kết Đan Hậu Kỳ tại trường không chịu nổi sức nóng, buộc phải dùng pháp bảo bảo hộ. Trùy bay theo quỹ đạo xoắn ốc trong đại sảnh với tốc độ cực nhanh; Hàn Lập đánh giá rằng tu sĩ Nguyên Anh Kỳ cũng không trốn nổi, chỉ có Phong Lôi Sí mới có thể phòng bị được tốc độ này.","phanLoaiPhu":"Cổ Bảo song thuộc tính","hinhDang":"Hình tiêm trùy (mũi nhọn)","uyLuc":"Hỏa lãng cực nóng tràn khắp sảnh đường, tu sĩ Kết Đan Hậu Kỳ không chịu nổi; tốc độ tự thân cực nhanh khiến tu sĩ Nguyên Anh Kỳ cũng khó tránh né, chỉ Phong Lôi Sí mới phòng bị được.","dacDiem":"Cổ Bảo cổ đại hình tiêm trùy, song thuộc tính lôi hỏa; khi kích hoạt toàn thân phủ hỏa quang hồng sắc xen lẫn tia điện bạch sắc nhảy múa.","congNang":["Phá cấm chế và vòng bảo hộ — Thai phu nhân dùng để phá Thái Diệu Thần Cấm @c0694","Tấn công tốc độ cao, bay theo quỹ đạo xoắn ốc với tốc độ khiến tu sĩ Nguyên Anh Kỳ cũng khó tránh @c0694","Phun tinh quang tạo hỏa lãng cực nóng tràn khắp không gian, bức tu sĩ Kết Đan Hậu Kỳ phải dùng pháp bảo tự vệ @c0694"],"chuSoHuu":[{"ten":"Thai phu nhân","tuChuong":"@c0694","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"chuHienThoi":"Thai phu nhân","tabs":{"tienTrinh":[{"chuong":"@c0694","loai":"xuat-hien","importance":"major","giaiDoan":"Thai phu nhân rút ra thi triển","text":"Thai phu nhân rút Lôi Hỏa Trùy ra để phá Thái Diệu Thần Cấm. Bảo vật lộ song thuộc tính lôi hỏa, hỏa lãng cực nóng tràn sảnh khiến tu sĩ Kết Đan Hậu Kỳ không chịu nổi. Tốc độ bay tự thân cực nhanh, Hàn Lập đánh giá Nguyên Anh Kỳ cũng trốn không nổi.","anchor":"một đạo sắc đạm đạm hồng bạch quang ảnh cấp tốc bay trong đại sảnh, tốc độ cực nhanh, như có như không"}]},"capNhatToi":"@c0694","nguon":["@c0694"]},{"id":"quyen-truc-ngan-bach","name":"Quyển trục ngân bạch","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Bạch sam lão giả"],"trangThai":"đang được giữ tạm","blurb":"Quyển trục bao bọc ngân quang lập lòe, được thờ ở vị trí trang trọng nhất trên bàn thờ đen trước Ngọc Ki Các trong động phủ Thương Khôn Thượng Nhân. Mở ra lộ bức tranh vẽ nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời, nghi là chân dung Thương Khôn Thượng Nhân; tuy nhiên thử kích hoạt không có phản ứng, công năng thực sự vẫn chưa được xác định.","detail":"Quyển trục dài chừng vài thước, bề ngoài bao bọc ngân quang lập lòe, được đặt trên bàn thờ đen cổ kính ở vị trí trang trọng nhất trước Ngọc Ki Các — nơi trung tâm trong động phủ của Thương Khôn Thượng Nhân. Lão giả họ Vân dùng bạch hà phiến mở quyển trục, bên trong lộ bức tranh vẽ một nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời, được suy đoán là chân dung Thương Khôn Thượng Nhân. Lão giả họ Vân thử đánh pháp quyết vào bức tranh nhưng không có bất kỳ phản ứng dị thường nào, tạm nhận định đây chỉ là một bức tranh bình thường. Quyển trục sau đó được thu vào Túi Trữ Vật chờ phân chia. Vị trí thờ phụng trang trọng gợi ý vật phẩm có thể ẩn chứa nội tình đặc biệt, song tính tới mốc hiện có trong tiến trình, công năng thực sự vẫn chưa được khai phá.","congNang":["Chưa rõ — thử kích hoạt không có phản ứng, có thể cần điều kiện đặc biệt"],"dacDiem":"Ngân quang bao bọc lập lòe, bên trong là bức tranh vẽ nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời, nghi là chân dung Thương Khôn Thượng Nhân; được thờ ở vị trí trang trọng nhất trước Ngọc Ki Các nhưng thử kích hoạt không có phản ứng, có thể cần điều kiện đặc biệt.","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0696","denChuong":"","cachCoDuoc":"chủ nhân gốc (thờ trong động phủ)","trangThai":"đã mất"},{"ten":"Bạch sam lão giả","tuChuong":"@c0696","denChuong":"","cachCoDuoc":"thu tạm giữ","trangThai":"đang giữ tạm"}],"tabs":{"tienTrinh":[{"chuong":"@c0696","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện trên bàn thờ trước Ngọc Ki Các","text":"Quyển trục ngân quang được phát hiện trên bàn thờ đen trước Ngọc Ki Các. Lão giả họ Vân dùng bạch hà phiến mở ra, lộ bức tranh nho sinh đeo kiếm ngửa mặt nhìn trời. Thử đánh pháp quyết không phản ứng, tạm thu vào Túi Trữ Vật.","anchor":"trên đó thờ phụng một bộ ngân bạch quyển trục dài chừng vài thước, ngân quang lập lòe"}]},"nguon":["@c0696"]},{"id":"co-bao-hinh-ong-truc","name":"Cổ Bảo hình ống trúc","category":"phap-bao","categoryLabel":"Cổ Bảo","phamCap":"Cổ Bảo (chưa rõ cấp)","soHuu":["Hàn Lập"],"trangThai":"đang sở hữu","blurb":"Cổ Bảo hình ống trúc mà Hàn Lập chọn lấy khi phân chia bảo vật tầng một Hư Thiên điện, chưa rõ uy lực và thần thông.","detail":"Một trong sáu Cổ Bảo tại tầng một Hư Thiên điện (động phủ Thương Khôn Thượng Nhân). Không cần tế luyện, có thể phát huy toàn bộ uy lực. Hàn Lập chọn lấy, thu vào túi trữ vật cùng phần tài liệu và đan dược được chia.","dacDiem":"Hình ống trúc","congNang":["Chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0697","denChuong":"","cachCoDuoc":"Chọn lấy khi phân chia bảo vật tầng một","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Phân chia bảo vật tầng một","text":"Hàn Lập chọn lấy Cổ Bảo hình ống trúc khi phân chia bảo vật, chưa rõ uy lực.","anchor":"Món cổ bảo tới tay Hàn Lập là một kiện Cổ Bảo hình ống trúc, cũng không biết uy lực của nó như thế nào"}]},"nguon":["@c0697"]},{"id":"tuong-vang-yeu-than","name":"Tượng vàng yêu thần ba đầu sáu tay","category":"khac","categoryLabel":"Tượng thờ","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"đặt tại điện thờ","blurb":"Tượng yêu thần một sừng ba đầu sáu tay, mặt dữ tợn, đặt trên điện thờ tầng hai Hư Thiên điện. Bộ dáng giống hệt yêu thú trên Phạm Thánh Chân Phiến.","detail":"Tượng vàng yêu thần một sừng ba đầu sáu tay trên điện thờ phòng ngủ Thương Khôn Thượng Nhân tại tầng hai Hư Thiên điện. Mắt trợn tròn, sáu tay giơ lên trời, mặt dữ tợn. Hàn Lập nhận ra bộ dáng giống như đúc yêu thú trên đồng phiến Phạm Thánh Chân Phiến, tim đập gấp. Trước tượng có hỏa hồng tiểu lô đỉnh phát khí trắng mang mùi đàn hương.","dacDiem":"Một sừng ba đầu sáu tay, mắt trợn tròn, giống yêu thú trên Phạm Thánh Chân Phiến","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện tại tầng hai","text":"Hàn Lập nhận ra tượng yêu thần giống hệt yêu thú trên Phạm Thánh Chân Phiến, gợi mối liên hệ sâu xa.","anchor":"Bộ dáng thần tượng này cùng Phạm Thánh Chân Phiến yêu thú trên đồng phiến giống nhau như đúc"}]},"nguon":["@c0697"]},{"id":"giuong-han-ngoc-xanh","name":"Giường hàn ngọc xanh","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"đặt tại tầng hai Hư Thiên điện","blurb":"Giường bằng hàn ngọc xanh phát âm hàn khí, đặt tại phòng ngủ tầng hai Hư Thiên điện. Đầu giường có ba hộp ngọc lớn nhỏ gây tranh chấp.","detail":"Giường ngọc màu xanh bằng hàn ngọc điêu khắc, phát âm hàn khí, đặt đối diện điện thờ yêu thần tại tầng hai. Đầu giường có ba hộp ngọc lớn nhỏ không đồng nhất, chưa mở, khiến Bạch sam lão giả lao tới chụp nhưng bị chặn.","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Khám phá tầng hai","text":"Giường hàn ngọc xanh phát âm hàn khí lộ diện tại phòng ngủ Thương Khôn Thượng Nhân, đầu giường có ba hộp ngọc gây tranh chấp.","anchor":"Đối diện một hướng khác của điện thờ có đặt một giường ngọc màu xanh"}]},"nguon":["@c0697"]},{"id":"ba-hop-ngoc-dau-giuong","name":"Ba hộp ngọc đầu giường","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"chưa mở","blurb":"Ba hộp ngọc lớn nhỏ không đồng nhất đặt ở đầu giường hàn ngọc tầng hai Hư Thiên điện, chưa mở, gây tranh chấp tức thì.","detail":"Ba hộp ngọc lớn nhỏ không đồng nhất phi thường đáng chú ý đặt tại đầu giường hàn ngọc xanh phòng ngủ Thương Khôn Thượng Nhân. Bạch sam lão giả lao tới chụp nhưng bị một nhân ảnh bắn hắc mang ngăn cản, mở đầu xung đột.","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Tranh chấp khi vừa lên tầng hai","text":"Bạch sam lão giả lao tới chụp hộp ngọc nhưng bị hắc mang ngăn cản, mở đầu xung đột tầng hai.","anchor":"Tại một đầu giường ngọc, có ba cái hộp ngọc lớn nhỏ không đồng nhất phi thường đáng chú ý"}]},"nguon":["@c0697"]},{"id":"thanh-te-giap","name":"Thanh Tê Giáp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Thanh Tê Giáp là áo giáp phòng hộ màu xanh, được Nam Lũng Hầu mặc bên trong y phục. Giáp chịu được đòn ám toán ngân luân của tu sĩ Nguyên Anh trung kỳ, cứu mạng chủ nhân trong trận chiến tại @c0698.","detail":"Thanh Tê Giáp là một bảo giáp phòng ngự được Nam Lũng Hầu mặc kín bên trong y phục. Khi lão giả họ Vân phóng ngân luân đánh trúng ngực Nam Lũng Hầu, đòn tấn công phá vỡ hộ thể kim quang nhưng Thanh Tê Giáp phát huy tác dụng: giáp tỏa ánh sáng xanh, bị lõm sâu nhưng không bị thủng, chặn đứng sát thương trí mạng từ đòn đánh cấp Nguyên Anh trung kỳ. Lão giả họ Vân tỏ ra đã biết trước Nam Lũng Hầu sở hữu bảo vật này.","congNang":["Phòng ngự vật lý mạnh, mặc kín bên trong y phục để bảo hộ toàn thân @c0698","Chịu được đòn ám toán ngân luân cấp Nguyên Anh trung kỳ — giáp bị lõm sâu nhưng không bị xuyên thủng, chặn đứng sát thương sau khi hộ thể kim quang đã bị phá @c0698"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0698","denChuong":"","cachCoDuoc":"Không rõ, mặc sẵn bên trong","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0698","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi Nam Lũng Hầu bị ám toán","text":"Nam Lũng Hầu bị lão giả họ Vân phóng ngân luân đánh trúng ngực, phá hộ thể kim quang. Thanh Tê Giáp mặc bên trong lộ ra, bị lõm sâu nhưng không thủng, cứu mạng chủ nhân. Lão giả họ Vân nhận ra bảo vật, ra lệnh đồng bọn không để Nam Lũng chạy thoát.","anchor":"lộ ra một khối giáp có ánh sáng màu xanh. Mặc dù bị lõm sâu vào, nhưng cũng không có bị thủng"}]},"dinhDanh":"goc","nguon":["@c0698"],"uyLuc":"Đỡ trọn đòn ngân luân của tu sĩ Nguyên Anh trung kỳ (lão giả họ Vân) sau khi hộ thể kim quang đã bị phá, giáp lõm sâu nhưng không thủng, cứu mạng Nam Lũng Hầu.","dacDiem":"Giáp tỏa ánh sáng màu xanh, mặc bên trong y phục, khi chịu đòn bị lõm sâu nhưng không bị xuyên thủng."},{"id":"ngan-luan-bach-sam-lao-gia","name":"Ngân luân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Ngân luân là pháp bảo tấn công dạng vòng bạc của lão giả họ Vân, được phun ra từ miệng với tốc độ nhanh như tia chớp, có khả năng phá vỡ hộ thể kim quang của tu sĩ Nguyên Anh trung kỳ trong một đòn ám toán.","detail":"Ngân luân là một chiếc vòng bạc được lão giả họ Vân giấu trong miệng và phun ra bất ngờ nhắm vào đối thủ. Trong trận chiến với Nam Lũng Hầu, lão giả họ Vân đã sử dụng ngân luân theo cách ám toán, phun vòng bạc ra với tốc độ cực nhanh, trong gang tấc đánh trúng ngực Nam Lũng Hầu, phá được lớp hộ thể kim quang của vị tu sĩ Nguyên Anh trung kỳ này chỉ trong một đòn.","congNang":["Tấn công tốc độ cao, nhanh như tia chớp, thích hợp cho ám toán trong cận chiến @c0698","Phá vỡ hộ thể kim quang của tu sĩ Nguyên Anh trung kỳ @c0698"],"chuSoHuu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0698","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0698","loai":"dùng","importance":"major","giaiDoan":"Ám toán Nam Lũng Hầu","text":"Lão giả họ Vân phun ngân luân từ miệng ám toán Nam Lũng Hầu, nhanh như tia chớp đánh trúng ngực, phá hộ thể kim quang, gây trọng thương.","anchor":"một cái vòng bạc bắn ra, nhanh như tia chớp đánh tới trên người Nam Lũng Hầu trong gang tấc"}]},"dinhDanh":"goc","nguon":["@c0698"],"uyLuc":"Trong một đòn bất ngờ, phá được hộ thể kim quang của tu sĩ bậc Nguyên Anh trung kỳ, đánh trúng ngực đối phương.","dacDiem":"Pháp bảo dạng vòng bạc, có thể ngậm giấu trong miệng và phun ra bất ngờ, tốc độ cực nhanh."},{"id":"ho-lu-xanh-tu-si-ho-vuu","name":"Hồ lô màu xanh (của tu sĩ họ Vưu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ họ Vưu","Hàn Lập"],"trangThai":"doi-chu","blurb":"Hồ lô màu xanh của tu sĩ họ Vưu, bắn ra điện hồ màu xanh chói mắt để tấn công.","detail":"Tu sĩ họ Vưu rút hồ lô xanh từ Túi trữ vật, bắn ra một đạo điện hồ màu xanh chói mắt nhắm vào Hàn Lập nhưng không ngăn được đối phương áp sát.","congNang":["Bắn điện hồ màu xanh chói mắt tấn công @c0699","Phóng điện hồ màu lam tấn công"],"chuSoHuu":[{"ten":"Tu sĩ họ Vưu","tuChuong":"@c0699","denChuong":"@c0700","cachCoDuoc":"Pháp bảo gốc","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0700","denChuong":"","cachCoDuoc":"Đoạt từ tu sĩ họ Vưu sau khi đóng băng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0699","loai":"dùng","importance":"normal","giaiDoan":"Chiến đấu với Hàn Lập","text":"Tu sĩ họ Vưu rút hồ lô xanh bắn điện hồ màu xanh chói mắt nhưng không ngăn được Hàn Lập áp sát.","anchor":"một đạo điện hồ màu xanh từ trong hồ lô bắn nhanh ra, rất chói mắt"},{"chuong":"@c0700","loai":"doi-chu","importance":"normal","giaiDoan":"Bị đoạt","text":"Tu sĩ họ Vưu dùng hồ lô phóng điện hồ lam tấn công Hàn Lập nhưng bị điện võng hấp thu. Sau khi chủ nhân bị đóng băng, Hàn Lập đoạt lấy.","anchor":"từ trong hồ lô đồng thời cũng bắn ra điện hồ màu lam, thế như sét đánh bay tới trước mắt Hàn Lập"}]},"nguon":["@c0699","@c0700"]},{"id":"tieu-thuan-tho-hoang-sac","name":"Tiểu thuẫn thổ hoàng sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thai phu nhân"],"trangThai":"binh-thuong","blurb":"Tiểu thuẫn phòng thủ màu hoàng thổ của Thai phu nhân, dùng chắn đỡ kim quang của Nam Lũng Hầu.","detail":"Thai phu nhân hoảng hốt triệu ra tiểu thuẫn thổ hoàng sắc trước người để chống đỡ kim quang tấn công của Nam Lũng Hầu.","nguon":["@c0700"]},{"id":"khai-son-ky","name":"Khai Sơn Kỳ","cn":"开山旗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Tiểu kỳ màu vàng của Nam Lũng Hầu, dùng phá cấm chế thạch bích mở đường thoát.","detail":"Tiểu kỳ màu vàng xoay tròn trên tay, phóng ra hoàng mang chui vào thạch bích để phá cấm chế mở đường. Chỉ có một cây nên cần thời gian phá. Nam Lũng Hầu dùng khi đào thoát khỏi Hư Thiên điện.","nguon":["@c0701"],"congNang":["Phá cấm chế thạch bích, mở đường thoát"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"dùng","importance":"normal","giaiDoan":"Nam Lũng Hầu dùng phá thạch bích","text":"Nam Lũng Hầu dùng Khai Sơn Kỳ phá cấm chế thạch bích trong Hư Thiên điện để mở đường thoát, chỉ có một cây nên cần thời gian.","anchor":"chỉ có một cây Khai Sơn Kỳ, cho nên cần một chút thời gian"}]}},{"id":"co-bao-bat-vang-nam-lung-hau","name":"Cổ bảo bát vàng (của Nam Lũng Hầu)","cn":"","category":"phap-bao","categoryLabel":"Cổ bảo","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Bát vàng lớn cổ bảo của Nam Lũng Hầu, tạo lồng sáng vây nhốt tu sĩ Nguyên Anh tạm thời.","detail":"Bát màu vàng thật lớn phiêu phù không trung, phía dưới tạo lồng sáng mờ vây nhốt đối thủ. Bên trong hắc quang bạch khí chớp động kèm tiếng sấm bạo liệt. Uy lực đủ vây tu sĩ Nguyên Anh (lão giả họ Vân và Vương Thiên Cổ) nhưng không bền, chỉ tạm thời.","nguon":["@c0701"],"congNang":["Vây nhốt đối thủ tạm thời bằng lồng sáng"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"dùng","importance":"normal","giaiDoan":"Vây nhốt lão giả họ Vân và Vương Thiên Cổ","text":"Nam Lũng Hầu dùng cổ bảo bát vàng tạo lồng sáng vây nhốt lão giả họ Vân và Vương Thiên Cổ tạm thời để tranh thủ đào thoát.","anchor":"một cái bát màu vàng thật lớn phiêu phù ở không trung, phìa dưới có cái lồng sáng mờ"}]}},{"id":"sau-hop-ngoc-thuong-khon-thuong-nhan","name":"Sáu hộp ngọc Thương Khôn Thượng Nhân","cn":"","category":"khac","categoryLabel":"Vật chứa / Cổ bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"4/6 trong tay Hàn Lập","blurb":"Sáu hộp ngọc trong suốt do Thương Khôn Thượng Nhân lưu lại ở Cổ Bảo tầng hai, có đặc tính che dấu linh khí của bảo vật bên trong, khiến ngay cả thần thức tu sĩ Nguyên Anh cũng không thể thăm dò. Tính tới mốc gần nhất, bốn trong sáu hộp ngọc nằm trong tay Hàn Lập.","detail":"Thương Khôn Thượng Nhân lưu lại tổng cộng sáu hộp ngọc trong suốt ở Cổ Bảo tầng hai. Bên ngoài mỗi hộp có phong ấn bạch sắc linh quang; Hàn Lập dễ dàng phá lớp phong ấn này bằng thanh sắc linh quang. Hộp ngọc sở hữu công năng đặc biệt là che dấu hoàn toàn linh khí của bảo vật chứa bên trong, nhờ đó Ngân Nguyệt đã lợi dụng độn thuật kết hợp tính năng này để lén lấy đi ba hộp ngọc mà không bị các tu sĩ Nguyên Anh có mặt phát hiện. Hàn Lập đã có sẵn một hộp từ trước, cộng thêm ba hộp Ngân Nguyệt mang về, tổng cộng bốn trong sáu hộp ngọc giờ thuộc về hắn.","congNang":["Che dấu linh khí của bảo vật chứa bên trong, khiến thần thức tu sĩ Nguyên Anh cũng không thể thăm dò được @c0703"],"chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc lưu lại trong Cổ Bảo","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Ngân Nguyệt lén lấy 3 + đã có 1 từ trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"đổi chủ","importance":"major","giaiDoan":"4/6 hộp rơi vào tay Hàn Lập","text":"Ngân Nguyệt lén lấy ba hộp ngọc ở Cổ Bảo tầng hai nhờ độn thuật kết hợp tính năng che linh khí. Cộng một hộp Hàn Lập đã có, tổng cộng bốn trong sáu hộp ngọc Thương Khôn Thượng Nhân giờ thuộc về Hàn Lập.","anchor":"Thương Khôn Thượng Nhân tổng cộng lưu lại sáu cái hộp ngọc, nhưng trong đó bốn cái đã ở trong tay ta"}]},"nguon":["@c0703"],"dacDiem":"Hộp ngọc trong suốt, bên ngoài có phong ấn bạch sắc linh quang, có thể bị phá bằng thanh sắc linh quang."},{"id":"ngoc-gian-lam-nhat","name":"Ngọc giản lam nhạt","cn":"","category":"khac","categoryLabel":"Bảo vật / Thông tin","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản màu lam nhạt nằm trong hộp ngọc thứ nhất của Thương Khôn Thượng Nhân, nội dung bí ẩn chưa tiết lộ.","detail":"Nằm trong hộp ngọc thứ nhất. Hàn Lập đắm thần thức vào đọc, biểu cảm không thay đổi suốt quá trình, cuối cùng cau mày trầm ngâm rồi cất đi mà không tiết lộ nội dung cho Ngân Nguyệt, cho thấy nội dung quan trọng hoặc nhạy cảm.","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc thứ nhất","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở hộp ngọc thứ nhất","text":"Hàn Lập phá phong ấn bạch sắc mở hộp ngọc thứ nhất, lấy ngọc giản lam nhạt ra đọc bằng thần thức, cau mày trầm ngâm rồi cất đi mà không tiết lộ nội dung.","anchor":"cuối cùng Hàn Lập thần sắc vừa động đem thần thức thu hồi, cau mày trầm ngâm đứng lên"}]},"nguon":["@c0703"]},{"id":"nhan-den","name":"Nhẫn đen","cn":"","category":"phap-bao","categoryLabel":"Pháp khí / Bảo vật bí ẩn","phamCap":"Không rõ (bề ngoài là pháp khí bình thường)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiếc nhẫn đen thui vô quang nằm trong hộp ngọc thứ hai của Thương Khôn Thượng Nhân, tài liệu cổ quái, công dụng chưa rõ.","detail":"Nằm trong hộp ngọc thứ hai. Tinh xảo lung linh nhưng đen thui vô quang, tài liệu cổ quái, linh khí rất ít. Hàn Lập phán đoán bề ngoài chỉ là pháp khí bình thường, nhưng tin rằng Thương Khôn Thượng Nhân đặc ý cất giữ trong hộp ngọc phong ấn thì chắc chắn phải có công dụng, có thể là công dụng lớn sau này.","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc thứ hai","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở hộp ngọc thứ hai","text":"Hàn Lập mở hộp ngọc thứ hai, bên trong là chiếc nhẫn đen thui vô quang, tài liệu cổ quái nhưng linh khí ít, phán đoán là pháp khí bình thường nhưng tin rằng có công dụng đặc biệt.","anchor":"Tài liệu có chút cổ quái, nhưng hẳn chỉ là nhất kiện pháp khí bình thường, có tác dụng cụ thể gì cũng khó mà nói"}]},"nguon":["@c0703"]},{"id":"tu-van-dau","name":"Tử Vân Đấu","cn":"紫云斗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo đỉnh bậc (kém Thông thiên linh bảo)","soHuu":["Hàn Lập","Ngân Nguyệt"],"trangThai":"dang-co","blurb":"Tử Vân Đấu là Hồng hoang Cổ Bảo phòng ngự phạm vi lớn bậc nhất, hình dáng tử sắc tinh võng mềm mại trong suốt, được Hàn Lập thu từ chiến lợi phẩm và do Ngân Nguyệt nhận diện danh tính. Ngoài khả năng che kín trăm trượng đến ngàn trượng bảo hộ sinh linh trăm dặm, bảo vật còn có thể vây địch, phóng Ngọc Dương Chân Hỏa diệt sát cường địch, và chụp bắt đối phương bằng tử võng thoắt ẩn thoắt hiện.","detail":"Hàn Lập phát hiện Tử Vân Đấu bên trong hộp ngọc chiến lợi phẩm, ban đầu chỉ thấy một kiện tử sắc tinh võng trong suốt mềm mại; khi kích hoạt, bảo vật hóa thành tử vụ xoay quanh đỉnh đầu rồi hiện nguyên hình ti võng (@c0704). Ngân Nguyệt nhờ ký ức trước khi bị luyện hóa thành khí linh đã nhận ra đây là Hồng hoang Cổ Bảo danh khí không nhỏ, đoán nguồn gốc từ Trụy Ma Cốc, đồng thời thừa nhận hình như từng sở hữu kiện tương tự trước kiếp. Về phòng ngự, Tử Vân Đấu có thể che kín phạm vi từ trăm trượng đến ngàn trượng, bảo hộ sinh linh trong trăm dặm — thuộc hàng Cổ Bảo phòng ngự phạm vi lớn bậc nhất. Về tấn công, bảo vật có thể vây khốn đối phương rồi phóng thích Ngọc Dương Chân Hỏa để diệt sát cường địch. Ngân Nguyệt từng trực tiếp điều khiển Tử Vân Đấu phóng tử võng chụp bắt nữ tu sĩ Nguyên A","hinhDang":"Tử sắc tinh võng trong suốt mềm mại, khi kích hoạt hóa thành tử vụ xoay quanh đỉnh đầu","nguonGoc":"Hồng hoang Cổ Bảo, đoán đến từ Trụy Ma Cốc","congNang":["Phòng ngự phạm vi lớn: che kín từ trăm trượng đến ngàn trượng, bảo hộ sinh linh trong trăm dặm (@c0704)","Vây khốn đối phương và phóng thích Ngọc Dương Chân Hỏa để diệt sát cường địch (@c0704)","Phóng tử võng thoắt ẩn thoắt hiện chụp bắt đối phương, có thể cầm cố tu sĩ Nguyên Anh trung kỳ (@c0717)","Tạo tử sắc hỏa võng làm tầng phòng hộ (@c0785)","Miễn nhiễm kiếm khí và lục hỏa"],"chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"@c0704","cachCoDuoc":"Không rõ (có trong hộp ngọc của vị này)","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0704","denChuong":"","cachCoDuoc":"Thu từ hộp ngọc chiến lợi phẩm","trangThai":"dang-co"},{"ten":"Ngân Nguyệt","tuChuong":"@c0717","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"capNhatToi":"@c0704","tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"xuat-hien","importance":"major","giaiDoan":"Hàn Lập phát hiện và thu được","phamCap":"Cổ Bảo đỉnh bậc","text":"Hàn Lập mở hộp ngọc chiến lợi phẩm, phát hiện kiện tử sắc tinh võng mềm mại, kích hoạt hóa thành tử vụ. Ngân Nguyệt nhận ra là Tử Vân Đấu, hồng hoang Cổ Bảo phòng ngự đỉnh bậc, phạm vi trăm-ngàn trượng, phóng Ngọc Dương Chân Hỏa diệt địch.","anchor":"Vật này không phải là Tử Vân Đấu sao chứ? Đây chính là hồng hoang Cổ Bảo danh khí không nhỏ"},{"chuong":"@c0717","loai":"dùng","importance":"normal","giaiDoan":"Bắt sống đại trưởng lão","text":"Ngân Nguyệt dùng Tử Vân Đâu phóng tử võng chụp bắt nữ tử băng lãnh đang xuyên đỉnh trốn thoát, cầm cố đối phương dù bị hắc bạch kiếm khí và lục hỏa tấn công cũng không hao tổn.","anchor":"vô luận là hắc bạch kiếm khí hay lục hỏa đều được tử võng tiếp được mà không chút hao tổn"},{"chuong":"@c0785","loai":"dùng","importance":"normal","giaiDoan":"Phòng hộ trong trận chiến","text":"Ngân Nguyệt tung Tử Vân Đâu tạo tử sắc hỏa võng làm tầng phòng hộ thứ ba, nhưng bị ngân quang Thất long thung đánh thủng.","anchor":"Đúng là kiện Tử Vân Đâu nọ"}]},"nguon":["@c0704","@c0717","@c0785"],"dacDiem":"Hình dáng là kiện tử sắc tinh võng trong suốt mềm mại; khi kích hoạt hóa thành tử vụ xoay quanh đỉnh đầu rồi hiện nguyên hình ti võng."},{"id":"binh-su-xanh-biec","name":"Bình sứ nhỏ xanh biếc","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bình sứ nhỏ xanh biếc chứa chất cay độc dị thường, Hàn Lập sắc mặt đại biến vội đậy nắp thu cất. Công dụng cụ thể chưa rõ.","detail":"Thu được từ hộp ngọc chiến lợi phẩm. Khi mở nắp, một luồng hơi thở cay độc dị thường xông vào mũi khiến Hàn Lập sắc mặt đại biến, vội đậy nắp cẩn thận thu vào Túi Trữ Vật. Phản ứng mạnh cho thấy không phải vật tầm thường.","nguon":["@c0704"]},{"id":"hoang-sac-vu-phien","name":"Hoàng sắc vũ phiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng bào pháp sĩ"],"trangThai":"dang-co","blurb":"Pháp bảo của pháp sĩ hoàng bào Nguyên Anh Sơ Kỳ, phun ra từ miệng, phẩy một cái tạo cuồng phong vàng đậm cao hơn mười trượng, cuốn gọn năm Kết Đan tu sĩ.","detail":"Pháp sĩ hoàng bào mất kiên nhẫn khi chiến đấu kéo dài, phun pháp bảo này ra từ miệng, chỉ phẩy một cái tạo cuồng phong vàng đậm quy mô lớn cao hơn mười trượng, cuốn toàn bộ năm Kết Đan tu sĩ vào trong.","congNang":["Tạo cuồng phong quy mô lớn, cuốn gọn nhiều tu sĩ Kết Đan"],"chuSoHuu":[{"ten":"Hoàng bào pháp sĩ","tuChuong":"@c0704","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"capNhatToi":"@c0704","tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"dung","importance":"normal","giaiDoan":"Cuốn năm Kết Đan tu sĩ vào cuồng phong","text":"Pháp sĩ hoàng bào phun ra hoàng sắc vũ phiến, phẩy một cái tạo cuồng phong hơn mười trượng cuốn gọn năm Kết Đan tu sĩ.","anchor":"một cổ cuồng phong màu vàng đậm từ vũ phiến phát ra, trong nháy mắt cuồng trướng thật lớn"}]},"nguon":["@c0704"]},{"id":"vu-phien-phap-si-ho-dam","name":"Vũ phiến (của pháp sĩ họ Đàm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Pháp sĩ họ Đàm"],"trangThai":"mat","blurb":"Pháp bảo của pháp sĩ họ Đàm, phát ra cuồng phong cấm chế khống chế năm tu sĩ, bị Hàn Lập bắn Thanh Nguyên kiếm khí đánh bay.","detail":"Vũ phiến phát ra cuồng phong mãnh liệt khống chế pháp bảo và thân thể năm tu sĩ. Bị Hàn Lập từ xa bắn một đạo Thanh Nguyên kiếm khí đánh bay.","congNang":["Phát cuồng phong cấm chế, khống chế pháp bảo và thân thể đối phương"],"chuSoHuu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","denChuong":"@c0705","cachCoDuoc":"","trangThai":"mat"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"dùng","importance":"normal","giaiDoan":"Xuất hiện và mất","text":"Pháp sĩ họ Đàm dùng vũ phiến phát cuồng phong khống chế năm tu sĩ, bị Hàn Lập bắn Thanh Nguyên kiếm khí đánh bay.","anchor":"lập tức đem vũ phiến nọ đánh bay"}]},"nguon":["@c0705"]},{"id":"dan-hoan-vang-cau-linh","name":"Hai khỏa đạn hoàn vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai khỏa đạn hoàn màu vàng của pháp sĩ họ Đàm, dùng làm linh hạch điều khiển Câu Linh Thổ Long, bị Hàn Lập thu sau khi phá hủy thổ long.","detail":"Pháp sĩ họ Đàm bắn xuống đất để triệu hoán thổ long, nằm trên trán thổ long làm linh hạch cung cấp linh khí. Sau khi thổ long bị Hàn Lập phá hủy, hai khỏa đạn hoàn bị Hàn Lập thu vào Túi Trữ Vật.","congNang":["Linh hạch điều khiển Câu Linh Thổ Long, cung cấp linh khí cho thổ long"],"chuSoHuu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","denChuong":"@c0705","cachCoDuoc":"","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0705","denChuong":"","cachCoDuoc":"Thu được sau khi phá hủy thổ long","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"đổi chủ","importance":"normal","giaiDoan":"Đổi từ pháp sĩ họ Đàm sang Hàn Lập","text":"Pháp sĩ họ Đàm dùng đạn hoàn triệu hoán thổ long, bị Hàn Lập phá hủy rồi thu hai khỏa đạn hoàn vào Túi Trữ Vật.","anchor":"Hai khỏa đạn hoàn màu vàng bị hắn thong dong hút đến trong tay"}]},"nguon":["@c0705"]},{"id":"hoa-hong-phi-kiem-niep-doanh","name":"Hỏa hồng phi kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Niếp Doanh"],"trangThai":"dang-co","blurb":"Pháp bảo phi kiếm của Niếp Doanh, bị cuồng phong pháp sĩ họ Đàm làm mất khống chế.","detail":"Phi kiếm hỏa hồng do Niếp Doanh khu sử, bị cuồng phong từ vũ phiến của pháp sĩ họ Đàm làm mất quyền khống chế.","nguon":["@c0705"]},{"id":"lenh-bai-quan-su-vien-khon","name":"Lệnh bài quản sự Viên Khôn","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lệnh bài chứng nhận thân phận quản sự trong Yểm Nguyệt Tông, Hàn Lập lấy từ Viên Khôn để trà trộn vào tông môn.","detail":"Lệnh bài quản sự trên người Viên Khôn, dùng để chứng nhận thân phận khi ra vào tông môn và xử lý công việc thương điếm. Hàn Lập lấy được sau khi bắt giữ Viên Khôn, nhờ đó dễ dàng trà trộn vào Yểm Nguyệt Tông.","congNang":["Chứng nhận thân phận quản sự trong Yểm Nguyệt Tông"],"chuSoHuu":[{"ten":"Viên Khôn","tuChuong":"@c0709","denChuong":"@c0709","cachCoDuoc":"Sở hữu ban đầu","trangThai":"bị lấy"},{"ten":"Hàn Lập","tuChuong":"@c0709","denChuong":"","cachCoDuoc":"Lấy từ Viên Khôn sau khi bắt giữ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0709","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập dùng trà trộn vào tông","text":"Hàn Lập lấy lệnh bài quản sự từ Viên Khôn, dùng để trà trộn vào Yểm Nguyệt Tông dễ dàng.","anchor":"Thông qua lệnh bài quản sự trên người Viên Khôn, lấy được tin xong hắn dễ dàng trà trộn vào bên trong Yểm Nguyệt Tông"}]},"nguon":["@c0709"]},{"id":"thanh-kiem-ngan-quang","name":"Thanh kiếm ngân quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập","Nam Cung Uyển"],"trangThai":"Đang được Nam Cung Uyển xem","blurb":"Cây kiếm to lóe ngân quang, được Hàn Lập đặt trong hộp gỗ dài dán phù cấm chế bạc làm lễ vật gửi lên cho Nam Cung Uyển. Có ý nghĩa đặc biệt giữa hai người, là tín vật khiến Nam Cung Uyển đồng ý triệu kiến.","detail":"Hàn Lập dùng thanh kiếm này làm tín vật, đặt trong hộp gỗ dài dán phù cấm chế bạc, giả làm lễ vật của bạn cũ gửi Nam Cung Uyển. Khi Nam Cung Uyển nhìn thấy thanh kiếm liền xác nhận người gửi là bạn cũ và triệu kiến Hàn Lập. Cuối chương Nam Cung Uyển đang cúi đầu nhìn thanh kiếm, hộp gỗ đã mở và trống không.","congNang":["Tín vật giữa Hàn Lập và Nam Cung Uyển, công năng chiến đấu chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0710","denChuong":"","cachCoDuoc":"Mang theo làm tín vật","trangThai":"giao cho Nam Cung Uyển xem"}],"tabs":{"tienTrinh":[{"chuong":"@c0710","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập dùng làm tín vật gửi Nam Cung Uyển","text":"Hàn Lập đặt thanh kiếm trong hộp gỗ dán phù cấm chế bạc, giả làm lễ vật gửi lên cho Nam Cung Uyển. Nam Cung Uyển mở hộp thấy kiếm, xác nhận bạn cũ và triệu kiến.","anchor":"Đó chính là một cây kiếm to lóe lên ngân quang"}]},"nguon":["@c0710"]},{"id":"lenh-bai-khon-tam-thuat","name":"Lệnh bài Khốn Tâm Thuật","cn":"","category":"phap-bao","categoryLabel":"Pháp khí / Cấm chế vật","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Lệnh bài Khốn Tâm Thuật là vật then chốt duy trì cấm chế Khốn Tâm Thuật, hiện nằm trong tay đại trưởng lão Yểm Nguyệt Tông. Phá hủy lệnh bài sẽ giải được cấm chế đang khống chế Nam Cung Uyển, và Hàn Lập đã nhận lời đi lấy lại nó.","detail":"Lệnh bài là mấu chốt duy nhất duy trì Khốn Tâm Thuật — một loại cấm chế đang trói buộc Nam Cung Uyển. Theo lời Nam Cung Uyển tiết lộ, lệnh bài hiện do vị sư tỷ của nàng, tức đại trưởng lão Yểm Nguyệt Tông, nắm giữ. Chỉ cần phá hủy lệnh bài thì cấm chế trên người Nam Cung Uyển sẽ được giải trừ. Hàn Lập đã hào khí nhận lời đi lấy lệnh bài nhằm giải phóng nàng khỏi sự khống chế này.","congNang":["Duy trì Khốn Tâm Thuật, khống chế đối tượng bị hạ chú trong phạm vi trăm dặm @c0712"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0712","denChuong":"","cachCoDuoc":"Tự tạo bằng máu huyết khi hạ Khốn Tâm Thuật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0712","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Nam Cung Uyển tiết lộ mấu chốt cấm chế nằm ở lệnh bài trong tay sư tỷ. Hàn Lập hào khí nhận lời đi lấy.","anchor":"mấu chốt của cấm chế này là ở trên một khối lệnh bài"}]},"nguon":["@c0712"]},{"id":"linh-an-phu","name":"Linh Ẩn Phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Cao cấp","soHuu":["Cô gái áo vàng"],"trangThai":"da-dung","blurb":"Phù cấp cao hiếm thấy có tác dụng ẩn nặc thân hình. Cô gái áo vàng Trúc Cơ kỳ dán trên người để do thám, khiến Hàn Lập nghi ngờ tại sao tiểu tu sĩ lại sở hữu vật này.","detail":"Phù cao cấp hiếm thấy, dán lên người có thể ẩn nặc thân hình. Cô gái áo vàng (đệ tử Trúc Cơ kỳ Yểm Nguyệt Tông) dùng để rình bên ngoài đại sảnh, bị Hàn Lập phát hiện và chất vấn vì một tiểu tu sĩ Trúc Cơ không nên có vật này.","nguon":["@c0713"]},{"id":"cam-che-lenh-bai-do","name":"Cấm chế lệnh bài màu đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Lệnh bài màu đỏ do đại trưởng lão Yểm Nguyệt Tông sở hữu, có thể dẫn phát Khốn Tâm thuật cấm chế trên người Nam Cung Uyển khi niệm chú.","detail":"Đại trưởng lão vỗ hông lấy ra lệnh bài màu đỏ, linh quang chớp động khi niệm chú, hồng quang yêu dị dần xuất hiện. Hàn Lập lập tức nhận ra đó là cấm chế lệnh bài và phản ứng tung Kinh Long chung ngăn cản.","congNang":["Kích hoạt Khốn Tâm thuật từ xa để khống chế đối tượng bị cấm chế"],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"dùng","importance":"normal","giaiDoan":"Đại trưởng lão cố phát động","text":"Đại trưởng lão rút lệnh bài màu đỏ niệm chú cố kích hoạt Khốn Tâm thuật, nhưng bị Hàn Lập dùng Kinh Long chung tấn công thần thức ngăn cản.","anchor":"ngọc thủ nhẹ nhàng nắm lệnh bài màu đỏ rung lên, cúi đầu niệm chú, nhất thời linh quang trên lệnh bài chớp động"}]},"nguon":["@c0714"]},{"id":"am-duong-bang-hoa-kiem","name":"Âm Dương Băng Hỏa kiếm","cn":"阴阳冰火剑","aliases":["hắc bạch phi kiếm","đôi phi kiếm một trắng một đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Đôi phi kiếm một trắng một đen của đại trưởng lão Yểm Nguyệt Tông, bạch kiếm tản hàn khí lạnh thấu xương, hắc kiếm cực nóng ngọn lửa đen chập chờn.","detail":"Đôi pháp bảo hiếm thấy. Bạch sắc phi kiếm trắng tinh như tuyết, tản ra hàn khí lạnh thấu xương. Hắc sắc phi kiếm cực nóng, ngọn lửa đen chập chờn. Khi thi triển, hình thể tăng vọt thành cự kiếm dài một trượng, song công băng hỏa.","congNang":["Song công băng hỏa, hình thể có thể tăng vọt thành cự kiếm"],"hinhDang":"Đôi phi kiếm, một trắng tinh một đen, hình thể có thể tăng vọt","tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"dùng","importance":"normal","giaiDoan":"Đại trưởng lão phản kích","text":"Đại trưởng lão phất tay áo thả đôi phi kiếm trắng đen, hình thể tăng vọt thành cự kiếm dài một trượng, phản kích trong cuộc phục kích.","anchor":"Bạch sắc phi kiếm trắng tinh như tuyết, tản ra hàn khí lạnh thấu xương, hắc sắc phi kiếm thì cực nóng"}]},"nguon":["@c0714"]},{"id":"ngan-kiem-tho-lau","name":"Ngân kiếm thô lậu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thấp","soHuu":["Hàn Lập","Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Cây ngân kiếm luyện chế thô lậu do Hàn Lập gửi tặng Nam Cung Uyển qua quản sự giả dạng, khiến nàng kích động ngắm nghía trân trọng — có ý nghĩa tình cảm đặc biệt.","detail":"Lễ vật Hàn Lập gửi cho Nam Cung Uyển, luyện chế thô lậu nhưng khiến nàng kích động đến mức thay đổi chủ ý, chủ động phát Truyền Âm phù muốn gặp sư tỷ. Nam Cung Uyển ngồi ngắm nghía, thưởng thức trân trọng — rất có thể là tín vật gắn liền tình cảm giữa nàng và Hàn Lập.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0714","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"da-tang"},{"ten":"Nam Cung Uyển","tuChuong":"@c0714","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập gửi tặng Nam Cung Uyển","text":"Hàn Lập giả dạng quản sự cấp thấp gửi ngân kiếm thô lậu cho Nam Cung Uyển. Nàng nhận kiếm kích động, ngắm nghía trân trọng, rồi chủ động phát Truyền Âm phù gặp sư tỷ.","anchor":"trong tay cầm một ngân kiếm luyện chế thô lậu, đặt ngang trước người, đôi mắt xinh đẹp đang ngắm nghía, thưởng thức"}]},"nguon":["@c0714"]},{"id":"ngung-quang-bao-kinh","name":"Ngưng Quang Bảo Kính","cn":"凝光宝镜","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"đang sử dụng","blurb":"Ngưng Quang Bảo Kính là cổ bảo thành danh của Nam Cung Uyển, Đại trưởng lão Yểm Nguyệt Tông, nổi danh trong giới tu sĩ Nguyên Anh kỳ. Toàn thân đen bóng, có thể phóng ngũ sắc quang trụ uy lực cực lớn, phá cấm chế và vây khốn pháp bảo đối phương. Thanh Ngưng Kính mà Hàn Lập từng thu được trong Huyết Sắc Thí Luyện chỉ là phỏng chế đơn giản, uy lực không bằng một phần trăm nguyên bản.","detail":"Ngưng Quang Bảo Kính là bảo vật thành danh của Nam Cung Uyển, vị Đại trưởng lão của Yểm Nguyệt Tông, có danh tiếng lớn trong hàng tu sĩ Nguyên Anh kỳ. Bảo kính toàn thân đen bóng, mặt gương đen tối âm u, khi thi triển phóng ra ngũ sắc quang trụ mang uy lực cực mạnh. Trong lần xuất hiện tại chương @c0715, băng lãnh nữ tử đã sử dụng Ngưng Quang Bảo Kính phun ngũ sắc quang trụ phá sạch cấm chế quang hà cùng hỏa diễm. Ngoài khả năng phá cấm chế, bảo kính còn có thể dùng cột sáng vây khốn pháp bảo của đối phương, hoặc phân thành nhiều cột sáng nhỏ hơn để chế trụ các bảo vật khác. Thanh Ngưng Kính mà Hàn Lập từng tìm được trong Huyết Sắc Thí Luyện chỉ là bản phỏng chế đơn giản, uy lực không sánh được một phần trăm so với nguyên bản.","hinhDang":"Toàn thân đen bóng, mặt gương đen tối âm u","congNang":["Phóng ngũ sắc quang trụ phá sạch cấm chế quang hà và hỏa diễm @c0715","Vây khốn pháp bảo đối phương trong cột sáng","Phân cột sáng thành nhiều cột nhỏ hơn để chế trụ bảo vật khác"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất thế trong trận chiến","text":"Băng lãnh nữ tử thi triển Ngưng Quang Bảo Kính, phun ngũ sắc quang trụ phá sạch cấm chế quang hà và hỏa diễm, vây khốn Chu Tước Hoàn. Hàn Lập nhận ra đây là nguyên bản của Thanh Ngưng Kính.","anchor":"Ngưng Quang Bảo Kính kia chính là một kiện cổ bảo mà Nam Cung Uyển nhắc tới nhiều nhất, cũng là một trong những bảo vật thành danh của sư tỷ nàng"}]},"nguon":["@c0715"],"uyLuc":"Ngũ sắc quang trụ phá sạch cấm chế quang hà và hỏa diễm trong nháy mắt, uy lực khiến bản phỏng chế không bằng một phần trăm nguyên bản.","dacDiem":"Toàn thân đen bóng, mặt gương đen tối âm u, phóng ra ngũ sắc quang trụ khi thi triển."},{"id":"huyet-ma-kiem","name":"Huyết Ma Kiếm","cn":"血魔剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ma kiếm","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"đang sử dụng","blurb":"Huyết Ma Kiếm là một ma kiếm chỉ cỡ một tấc, toàn thân đỏ trong suốt, bên trong có hắc khí lượn lờ, được băng lãnh nữ tử phun ra từ miệng để leo thang chiến đấu. Ma kiếm có uy lực cực lớn, tự động rung lên không cần thúc giục, khiến Nguyên Anh tu sĩ phải lo ngại, nhưng tiềm ẩn nguy cơ ma khí cắn trả chủ nhân nếu sử dụng quá lâu.","detail":"Huyết Ma Kiếm xuất hiện khi băng lãnh nữ tử phun nó ra từ miệng trong lúc leo thang chiến đấu tại đại sảnh. Kiếm chỉ cỡ một tấc, toàn thân đỏ trong suốt, bên trong mơ hồ có hắc khí lượn lờ. Ngay khi xuất hiện, ma kiếm tự động rung lên không cần chủ nhân thúc giục, máu tanh nhất thời tràn ngập đại sảnh, thể hiện ma tính cực mạnh. Uy lực của kiếm đủ để khiến Nguyên Anh tu sĩ lo ngại. Tuy nhiên, Huyết Ma Kiếm mang bản chất nguy hiểm cho chính chủ nhân: nếu dùng quá lâu, ma khí sẽ cắn trả người sử dụng. Nữ tử sở hữu kiếm tự tin có thể đánh bại đối thủ nhanh chóng trước khi bị ma khí phản phệ.","hinhDang":"Một tấc, toàn thân đỏ trong suốt, hắc khí bên trong, tự rung","congNang":["Ma kiếm tự động rung lên phát uy lực mà không cần chủ nhân thúc giục @c0715","Uy lực cực lớn, đủ khiến Nguyên Anh tu sĩ lo ngại @c0715"],"dacDiem":"Ma khí cắn trả chủ nhân nếu dùng lâu","chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất thế","text":"Băng lãnh nữ tử phun ra Huyết Ma Kiếm leo thang chiến đấu, ma kiếm tự rung, máu tanh tràn ngập đại sảnh. Nam Cung Uyển nhận ra và lo ngại ma khí cắn trả.","anchor":"một cổ máu tanh nhất thời tràn ngập đại sảnh"}]},"nguon":["@c0715"],"uyLuc":"Uy lực cực lớn, đủ khiến Nguyên Anh tu sĩ phải lo ngại; vừa xuất hiện đã khiến máu tanh tràn ngập cả đại sảnh."},{"id":"tru-ta-thu","name":"Tru Tà Thứ","cn":"诛邪刺","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam Cung Uyển"],"trangThai":"đã dùng hết","blurb":"Vật phẩm tiêu hao dạng ám khí của Nam Cung Uyển, phóng xích hồng ám mang đả thương đối phương, phá vỡ việc cầm lệnh bài. Số lượng hữu hạn.","detail":"Nam Cung Uyển lén phóng xích hồng ám mang đả thương tay sư tỷ, phá vỡ việc cầm lệnh bài cấm chế. Sư tỷ tưởng Nam Cung Uyển đã dùng hết từ trước, không ngờ còn lưu lại một quả. Vật phẩm tiêu hao, số lượng hữu hạn.","congNang":["Ám kích, thương tích đủ cắt đứt thao khống pháp bảo"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"dùng","importance":"normal","giaiDoan":"Ám kích sư tỷ","text":"Nam Cung Uyển lén phóng Tru Tà Thứ đả thương tay sư tỷ, phá vỡ việc cầm lệnh bài cấm chế.","anchor":"Tru Tà Thứ! Ngươi dĩ nhiên dùng vật ấy đả thương ta"}]},"nguon":["@c0715"]},{"id":"tieu-kiem-bac","name":"Tiểu kiếm bạc","cn":"","aliases":["ngân kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-dung","blurb":"Phi kiếm bạc của băng lãnh nữ tử, có thể thi triển Hóa kiếm vi ti biến thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng.","detail":"Băng lãnh nữ tử phun ra từ miệng, bắt quyết thi triển Hóa kiếm vi ti. Kiếm hóa thành ngàn đạo hào quang nhỏ như tơ bạc bén nhọn, liên tục chém rơi Phệ Kim Trùng nhiều lần, tuy trùng sau đó phục sinh.","congNang":["Thi triển Hóa kiếm vi ti — biến thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0716","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0716","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Băng lãnh nữ tử phun ra tiểu kiếm bạc, thi triển Hóa kiếm vi ti chém rơi Phệ Kim Trùng nhiều lần nhưng trùng phục sinh.","anchor":"phun ra một tiểu kiếm màu bạc, hai tay nhanh chóng bắt quyết"}]},"nguon":["@c0716"]},{"id":"chi-hoan","name":"Chỉ Hoàn","cn":"指环","aliases":["chiếc nhẫn đen","chỉ hoàn"],"category":"khac","categoryLabel":"Vật bí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng (âm hoàn)","blurb":"Chỉ Hoàn, danh xưng chính thức là Lưỡng Nghi Hoàn, là đôi nhẫn đen bóng tinh xảo giống hệt nhau, không chứa linh khí, gồm một âm hoàn và một dương hoàn. Hàn Lập đã sở hữu sẵn một chiếc, và tìm được chiếc thứ hai trong đồ vật của đại trưởng lão Yểm Nguyệt Tông. Khi ghép đôi, chúng có khả năng chi phối Bắc Cực nguyên quang — một lực lượng cực kỳ nguy hiểm.","detail":"Đôi nhẫn toàn thân đen bóng, chế tác tinh xảo khéo léo nhưng hoàn toàn không chứa linh khí, bề ngoài trông như pháp khí phổ thông. Hàn Lập phát hiện chiếc thứ hai trong đống đồ từ túi trữ vật của sư tỷ Nam Cung Uyển (vốn thuộc đại trưởng lão Yểm Nguyệt Tông), nhận ra nó giống hệt chiếc nhẫn đen mình đã sở hữu từ trước (@c0717). Sau đó, Tuyền Kì Tử và Nam Lũng Hầu xác nhận danh tính chính thức của đôi nhẫn là Lưỡng Nghi Hoàn, do Huyền Hoàng Lão chế tạo, gồm hai phần âm hoàn và dương hoàn, có công năng liên quan trực tiếp đến Bắc Cực nguyên quang (@c0723). So sánh hai chiếc không thấy bất kỳ khác biệt nào về ngoại hình.","hinhDang":"Nhẫn toàn thân đen bóng, tinh xảo khéo léo","dacDiem":"Không chứa linh khí, có hai chiếc giống hệt nhau, bề ngoài đen bóng tinh xảo nhưng trông như pháp khí phổ thông; gồm một âm hoàn và một dương hoàn hợp thành bộ Lưỡng Nghi Hoàn, do Huyền Hoàng Lão chế tạo.","chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0717","denChuong":"@c0717","cachCoDuoc":"Không rõ (nằm trong túi trữ vật)","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0717","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc (trước đó)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0717","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện đôi nhẫn","text":"Hàn Lập phát hiện chiếc nhẫn đen tinh xảo trong đống đồ sư tỷ Nam Cung Uyển, lấy chiếc nhẫn đen giống hệt mình đã có ra so sánh, cả hai không có linh khí, cất chung vào hộp ngọc.","anchor":"Đấy là một chiếc nhẫn tinh xảo khéo léo, toàn thân đen bóng"},{"chuong":"@c0723","loai":"khai phong","importance":"major","giaiDoan":"Xác nhận danh tính và công năng","text":"Chiếc nhẫn đen được Tuyền Kì Tử và Nam Lũng Hầu xác nhận là Lưỡng Nghi Hoàn (phần âm hoàn), do Huyền Hoàng Lão Nhân luyện chế từ thiên ngoại vẫn thiết. Hé lộ toàn bộ công năng: âm hoàn hộ thể khỏi Bắc Cực nguyên quang, dương hoàn thao túng nguyên quang tấn công. Là vật phẩm then chốt để vào Trụy Ma Cốc.","anchor":"Lưỡng Nghi hoàn này chia làm âm dương nhị hoàn, có âm hoàn trong người cũng không sợ nguyên quang làm tổn thương thân thể"}]},"nguon":["@c0717","@c0723"],"congNang":["Âm hoàn: bảo vệ thân thể người đeo khỏi Bắc Cực nguyên quang xâm phạm (@c0723)","Dương hoàn: thao túng Bắc Cực nguyên quang tấn công giết người vô hình (@c0723)"],"thanhVien":[]},{"id":"khan-lua-co-bao-vo-danh","name":"Khăn lụa cổ bảo vô danh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Cổ bảo vô danh Nam Cung Uyển vô tình có được khi du ngoạn, chỉ cần ý niệm tự động bay lên phòng thân, linh khí dị thường.","detail":"Chiếc khăn lụa mỏng phát ra linh khí dị thường. Chỉ cần một ý niệm là tự động bay lên phòng thân, sử dụng cực kỳ thuận tiện. Nam Cung Uyển tặng cho Hàn Lập trước khi chia tay.","congNang":["Tự động bay lên phòng thân chỉ bằng ý niệm"],"nguon":["@c0718"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"","denChuong":"@c0718","cachCoDuoc":"Vô tình có được khi du ngoạn","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0718","denChuong":"","cachCoDuoc":"Nam Cung Uyển tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"đổi chủ","importance":"normal","giaiDoan":"Nam Cung Uyển trao tặng Hàn Lập","text":"Nam Cung Uyển tặng Hàn Lập khăn lụa cổ bảo vô danh để phòng thân trước khi chia tay tại biên giới Bắc Lương Quốc.","anchor":"cơ hồ chỉ cần một ý niệm là có thể tự động bay lên phòng thân"}]}},{"id":"ich-hoa-boi","name":"Ích Hỏa bội","cn":"益火佩","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tín vật","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Tín vật Nam Cung Uyển thường mang trên người, hồng quang lập lòe. Dùng để sai khiến đệ tử ký danh của nàng tại Điền Thiên Thành.","detail":"Ngọc bội phát hồng quang lập lòe, là tín vật cá nhân Nam Cung Uyển thường xuyên mang theo. Có công năng làm tín vật chỉ huy đệ tử ký danh (không phải đệ tử Yểm Nguyệt Tông) của nàng. Được trao cho Hàn Lập trước khi chia tay.","congNang":["Tín vật chỉ huy/sai khiến đệ tử ký danh của Nam Cung Uyển"],"nguon":["@c0718"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"","denChuong":"@c0718","cachCoDuoc":"Vật sở hữu cá nhân","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0718","denChuong":"","cachCoDuoc":"Nam Cung Uyển tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"đổi chủ","importance":"normal","giaiDoan":"Nam Cung Uyển trao cho Hàn Lập","text":"Nam Cung Uyển trao Ích Hỏa bội cho Hàn Lập để hắn có thể sai khiến đệ tử ký danh của nàng đang mở hàng tại Điền Thiên Thành.","anchor":"Đây là Ích Hỏa bội, là một kiện tín vật mà thiếp thường xuyên mang theo trên người"}]}},{"id":"ngoc-gian-luc-sac","name":"Ngọc giản lục sắc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khối ngọc giản lục sắc do Lỗ Vệ Anh trưởng lão Thiên Cực Môn trao cho Hàn Lập, bên trong ghi địa chỉ hẹn gặp riêng đêm nay.","detail":"Lỗ Vệ Anh chuẩn bị sẵn ngọc giản này, ném cho Hàn Lập khi lộ diện giải vây cho đệ tử Bạch Thư Quân. Bên trong ghi một địa chỉ tại Điền Thiên Thành để mời Hàn Lập đêm nay đến gặp mặt bàn chuyện riêng.","congNang":["Chứa địa chỉ hẹn gặp riêng"],"chuSoHuu":[{"ten":"Lỗ Vệ Anh","tuChuong":"@c0719","denChuong":"@c0719","cachCoDuoc":"Tự chuẩn bị","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0719","denChuong":"","cachCoDuoc":"Lỗ Vệ Anh trao cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0719","loai":"xuất hiện","importance":"normal","giaiDoan":"Lỗ Vệ Anh trao cho Hàn Lập","text":"Lỗ Vệ Anh ném ngọc giản lục sắc cho Hàn Lập, bên trong ghi địa chỉ hẹn gặp đêm nay tại Điền Thiên Thành.","anchor":"theo đó một khối lục sắc ngọc giản sớm chuẩn bị bay vụt đến"}]},"nguon":["@c0719"]},{"id":"bao-vat-hac-hong-quang","name":"Bảo vật hắc hồng quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cổ quái)","soHuu":[],"trangThai":"dang-co","blurb":"Bảo vật cổ quái do hai pháp sĩ Nguyên Anh Sơ Kỳ dị loại sử dụng trong chiến tranh Mộ Lan, phóng hắc hồng quang vô ảnh vô tung phong tỏa Nguyên Anh sau khi xuất khiếu, chặn đứng thuấn di thần thông và trực tiếp dẫn tới tử vong của Nguyên Anh tu sĩ.","detail":"Bảo vật này xuất hiện trong trận chiến giữa tu sĩ Thiên Nam và thảo nguyên dị tộc thời kỳ chiến tranh Mộ Lan. Hai pháp sĩ Nguyên Anh Sơ Kỳ cổ quái giương tay phóng ra hắc hồng quang vô ảnh vô tung, vây khốn Nguyên Anh của đối thủ sau khi xuất khiếu khiến không thể thuấn di trốn thoát. Đây là nguyên nhân trực tiếp khiến hai Nguyên Anh tu sĩ phía Thiên Nam tử trận trong cuộc chiến này.","congNang":["Phóng hắc hồng quang vô ảnh vô tung phong tỏa Nguyên Anh sau khi xuất khiếu, khiến Nguyên Anh bị vây khốn không thể thoát đi @c0720","Chặn đứng thuấn di thần thông, ngăn Nguyên Anh tu sĩ dùng thuấn di trốn thoát @c0720"],"dacDiem":"Hắc hồng quang vô ảnh vô tung, rất khó phòng bị.","tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện trong chiến tranh Mộ Lan","text":"Hai pháp sĩ Nguyên Anh Sơ Kỳ cổ quái dùng bảo vật này phóng hắc hồng quang phong tỏa Nguyên Anh, trực tiếp dẫn tới tử vong hai Nguyên Anh tu sĩ Thiên Nam.","anchor":"giương tay thì có một đạo hắc hồng quang đến vô ảnh, đi vô tung, rất khó lòng phòng bị"}]},"nguon":["@c0720"],"uyLuc":"Trực tiếp dẫn tới tử vong hai Nguyên Anh tu sĩ Thiên Nam trong chiến tranh Mộ Lan, phong tỏa hoàn toàn đường sống của Nguyên Anh đã xuất khiếu."},{"id":"lam-quang-thuan","name":"Lam Quang Thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lam Quang Thuẫn là cổ bảo phòng ngự hình tiểu thuẫn phát ánh sáng lam, được Lệnh Hồ Lão Tổ tặng Hàn Lập như một trong ba trọng bảo đổi ba lần tương trợ Hoàng Phong Cốc. Pháp bảo này có thần thông phòng ngự đặc biệt thần diệu khi đối mặt công kích thuộc tính hỏa, đồng thời đủ sức chặn đứng các đòn tấn công nguy hiểm trên chiến trường.","detail":"Lam Quang Thuẫn là cổ bảo hình tiểu thuẫn, khi cầm trong tay phát ra ánh sáng lam, mang cảm giác mềm mại nhẹ nhàng như không tồn tại, chất liệu bất minh. Lệnh Hồ Lão Tổ trao nó cho Hàn Lập trong giao dịch dùng ba trọng bảo đổi lấy ba lần tương trợ Hoàng Phong Cốc (@c0722). Về công năng, thuẫn sở hữu thần thông phòng ngự không nhỏ, đặc biệt thần diệu khi đối mặt với công kích thuộc tính hỏa. Trên chiến trường, Hàn Lập đã khoát tay phóng Lam Quang Thuẫn ra chặn đứng cự nhận tử quang của Hắc bào nữ tử, cho thấy khả năng phòng ngự thực chiến đáng tin cậy (@c0775).","congNang":["Phòng ngự toàn diện, đặc biệt thần diệu khi đối mặt công kích thuộc tính hỏa (@c0722)","Chặn đứng cự nhận tử quang trên chiến trường, có thể phóng ra phòng ngự từ xa (@c0775)"],"chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"major","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập","text":"Lệnh Hồ Lão Tổ tặng Lam Quang Thuẫn cho Hàn Lập như một trong ba trọng bảo đổi ba lần tương trợ Hoàng Phong Cốc.","anchor":"Thần thông của bảo vật này không nhỏ, hơn nữa khi đối mặt với công kích thuộc tính hỏa càng vô cùng thần diệu"},{"chuong":"@c0775","loai":"dùng","importance":"normal","giaiDoan":"Chặn cự nhận Hắc bào nữ tử","text":"Hàn Lập khoát tay phóng lam quang thuẫn chặn đứng cự nhận tử quang của Hắc bào nữ tử trên chiến trường.","anchor":"khoát tay rồi một cái quang thuẩn màu lam rời tay phóng ra"}]},"nguon":["@c0722","@c0775"],"uyLuc":"Chặn đứng được cự nhận tử quang của Hắc bào nữ tử trong thực chiến (@c0775).","dacDiem":"Hình tiểu thuẫn phát ánh sáng lam, cảm giác mềm mại nhẹ nhàng như không tồn tại, chất liệu bất minh; khắc chế đặc biệt công kích hỏa tính."},{"id":"that-cap-yeu-dan-thiet-si-dieu","name":"Thất cấp yêu đan Thiết Sí Điêu","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thất cấp yêu đan","soHuu":["Hàn Lập"],"trangThai":"đang giữ","blurb":"Yêu đan thất cấp từ Thiết Sí Điêu tại Mộ Lan thảo nguyên, dùng luyện đan hoặc mục đích khác. Tại Thiên Nam vô cùng quý hiếm.","detail":"Nằm trong bình ngọc đỏ, do Lệnh Hồ Lão Tổ một mình tiến sâu vào Mộ Lan thảo nguyên diệt Thiết Sí Điêu thất cấp mà lấy được. Tại Thiên Nam xem là vô cùng quý hiếm, nhưng Hàn Lập thầm coi là vô tác dụng với mình.","congNang":["Tài liệu luyện đan hoặc sử dụng khác"],"chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Diệt Thiết Sí Điêu thất cấp tại Mộ Lan thảo nguyên","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"normal","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập","text":"Lệnh Hồ Lão Tổ tặng thất cấp yêu đan Thiết Sí Điêu cho Hàn Lập, Hàn Lập thầm coi là vô tác dụng với mình.","anchor":"Mặc dù thất cấp yêu đan tại Thiên Nam xem như vô cùng quý hiếm nhưng đối với hắn thật sự chỉ là thứ vô tác dụng"}]},"nguon":["@c0722"]},{"id":"ngoc-phu-thuong-co","name":"Ngọc phù thượng cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng cổ phù bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Ngọc phù thượng cổ là một ngọc bội đen do cổ tu sĩ tinh thông đạo phù luyện chế từ thời thượng cổ, loại phù bảo đã thất truyền tại Thiên Nam. Lệnh Hồ Lão Tổ cửu tử nhất sinh mới lấy được, nghiên cứu hơn mấy trăm năm chỉ khai thác được một thần thông, sau đó tặng lại cho Hàn Lập.","detail":"Ngọc phù thượng cổ là một ngọc bội màu đen, do cổ tu sĩ tinh thông đạo phù luyện chế thời thượng cổ. Loại phù bảo này đã thất truyền tại Thiên Nam, Lệnh Hồ Lão Tổ phải trải qua cửu tử nhất sinh mới thu được. Dù nghiên cứu hơn mấy trăm năm, Lão Tổ chỉ khai thác được một thần thông duy nhất: huyễn hóa thành hắc hồng đại thủ (quỷ thủ) sử dụng hắc sắc âm hỏa để bắt giữ hoặc hủy diệt mục tiêu. Khi biểu diễn cho Hàn Lập, quỷ thủ hủy một chiếc bàn gỗ không để lại dấu vết. Bảo vật bị quỷ thủ bắt giữ sẽ mất thần thông hoặc giảm linh tính. Tuy nhiên, ngọc phù có yếu điểm rõ ràng: vô hiệu trước bảo vật chí cương chí dương. Uy lực của ngọc phù đã tiêu hao hơn phân nửa, cần cẩn thận sử dụng. Ngoài thần thông quỷ thủ, ngọc phù còn chỗ thần diệu khác chưa được khai thác. Sau đó, Lệnh Hồ Lão Tổ tặng ngọc ","congNang":["Huyễn hóa thành hắc hồng đại thủ (quỷ thủ) sử dụng hắc sắc âm hỏa để bắt giữ hoặc hủy diệt mục tiêu — quỷ thủ có thể hủy vật không để lại dấu vết (@c0722)","Bảo vật bị quỷ thủ bắt giữ sẽ mất thần thông hoặc giảm linh tính"],"dacDiem":"Thượng cổ phù bảo hình ngọc bội đen, đã thất truyền tại Thiên Nam. Yếu điểm: vô hiệu trước bảo vật chí cương chí dương. Uy lực đã tiêu hao hơn phân nửa, còn chỗ thần diệu khác chưa được khai thác.","chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Cửu tử nhất sinh tìm được","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"major","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập, biểu diễn quỷ thủ","text":"Lệnh Hồ Lão Tổ tặng ngọc phù thượng cổ cho Hàn Lập và biểu diễn thần thông quỷ thủ hủy bàn gỗ không dấu vết. Tiết lộ nghiên cứu hơn mấy trăm năm chỉ khai thác được một thần thông, uy lực đã dùng hơn phân nửa. Hàn Lập rất hứng thú, muốn nghiên cứu đạo phù cổ nhân.","anchor":"Dùng nó huyễn hóa thành quỷ thủ, trừ khi gặp bảo vật chí cương chí dương, cơ hồ không vật gì không bắt được"}]},"nguon":["@c0722"],"uyLuc":"Quỷ thủ hắc sắc âm hỏa hủy hoàn toàn một chiếc bàn gỗ mà không để lại bất kỳ dấu vết nào (@c0722)."},{"id":"ba-tran-ban-tin-vat","name":"Ba trận bàn trắng trong suốt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí","soHuu":["Lệnh Hồ Lão Tổ"],"trangThai":"đang giữ","blurb":"Ba trận bàn trắng trong suốt do Hàn Lập đích thân luyện chế, trao cho Lệnh Hồ Lão Tổ làm tín vật ba lần tương trợ Hoàng Phong Cốc.","detail":"Pháp khí do Hàn Lập đích thân luyện chế, người khác không thể bắt chước. Dùng làm tín vật cho cam kết ba lần xuất thủ tương trợ Hoàng Phong Cốc. Mỗi lần dùng một trận bàn.","congNang":["Tín vật triệu hồi tương trợ, mỗi trận bàn đại diện một lần"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Tự luyện chế","trangThai":"da-tang"},{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Hàn Lập trao làm tín vật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"normal","giaiDoan":"Hàn Lập trao cho Lệnh Hồ Lão Tổ","text":"Hàn Lập trao ba trận bàn trắng trong suốt do mình luyện chế cho Lệnh Hồ Lão Tổ làm tín vật ba lần tương trợ Hoàng Phong Cốc.","anchor":"Ba trận bàn này đều là pháp khí mà đích thân ta luyện chế ra, người khác không thể bắt chước"}]},"nguon":["@c0722"]},{"id":"lenh-bai-thien-cuc-mon","name":"Lệnh bài Thiên Cực Môn","category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Lệnh bài do Tuyền Ki Tử giao cho Hàn Lập, có thể điều động bất kỳ đệ tử Thiên Cực Môn nào để liên lạc với Tuyền Ki Tử.","detail":"Một khối lệnh bài thuộc Thiên Cực Môn, do Tuyền Ki Tử trao cho Hàn Lập. Người cầm lệnh bài này có thể điều động bất kỳ một đệ tử Thiên Cực Môn nào để liên lạc với Tuyền Ki Tử.","congNang":["Điều động đệ tử Thiên Cực Môn liên lạc với Tuyền Ki Tử"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0724","denChuong":"","cachCoDuoc":"Tuyền Ki Tử trao tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"đổi chủ","importance":"normal","giaiDoan":"Tuyền Ki Tử giao cho Hàn Lập","text":"Tuyền Ki Tử giao lệnh bài cho Hàn Lập để liên lạc qua đệ tử Thiên Cực Môn.","anchor":"có lệnh bài này, Hàn Lập có thể điều động bất kỳ một gã đệ tử Thiên Cực Môn nào liên lạc với lão"}]},"nguon":["@c0724"]},{"id":"thien-thai-coc-di-bao-ma","name":"Dị bảo của lão giả họ Mã","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-co","blurb":"Kiện dị bảo mà lão giả họ Mã mới có được, muốn thử uy lực trong trận tiếp ứng, chưa lộ hình dạng cụ thể.","detail":"Lão giả họ Mã nói mới có được nhất kiện dị bảo, xung phong đi tiếp ứng tu sĩ chiến bại từ Thiên Thai Cốc để thử uy lực.","nguon":["@c0727","@c0729"],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"dùng","importance":"normal","giaiDoan":"Trận đấu với Quật Diệu","text":"Lão giả họ Mã dốc toàn lực lấy ra quyển trục ngũ sắc hà quang vẽ bát quái đồ, phát ba động kinh người. Bị hỏa giao phun xích diễm bao phủ cùng chủ nhân trong biển lửa.","anchor":"ngũ sắc hà quang chợt đại phóng, một cổ ba động phi thường kinh người từ trong phát ra"}]},"aliases":["Quyển trục bát quái đồ ngũ sắc","quyển trục"],"congNang":["Phát ba động công kích kinh người"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}]},{"id":"ngan-bach-gioi-xich","name":"Ngân bạch giới xích","loai":"phap-bao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-co","blurb":"Pháp bảo của lão giả họ Mã, từ miệng phun ra đón gió hóa thành, rung lên phát tiếng phượng minh cửu thiên.","detail":"Từ trong miệng phun ra dưới dạng ngân quang cỡ hạt đào, đón gió hóa thành thanh giới xích ngân bạch. Khẽ rung phát tiếng phượng minh cửu thiên, ngân quang như thiên huyễn.","hinhDang":"Giới xích ngân bạch","congNang":["Phát thanh âm phượng minh cửu thiên"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"dùng","importance":"normal","giaiDoan":"Trận đấu với Quật Diệu","text":"Lão giả họ Mã phun ngân quang từ miệng hóa thành ngân bạch giới xích, phát tiếng phượng minh đối đầu Quật Diệu.","anchor":"một đạo ngân quang cỡ hạt đào từ trong miệng phun ra, đón gió hóa thành một thanh ngân bạch giới xích"}]},"nguon":["@c0729"]},{"id":"phi-dao-do-trong-suot","name":"Phi đao đỏ trong suốt","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-co","blurb":"Pháp bảo phi đao của Quật Diệu, trong suốt đỏ đậm, quang mang chói mắt. Từ lòng bàn tay bắn ra hóa hồng quang nghênh chiến tầm xa.","detail":"Pháp bảo hình phi đao màu đỏ trong suốt của Quật Diệu. Bắn ra từ lòng bàn tay hóa thành hồng quang giao đấu ngang ngửa với ngân hồng phóng ra từ Thái Huyền Bát Quái Đồ của tu sĩ họ Mã.","congNang":["Bắn ra hóa hồng quang giao chiến tầm xa"],"tabs":{"tienTrinh":[{"chuong":"@c0730","loai":"dung","importance":"normal","giaiDoan":"Trận chiến với tu sĩ họ Mã","text":"Quật Diệu bắn phi đao đỏ trong suốt nghênh chiến ngân hồng từ Thái Huyền Bát Quái Đồ, hai bên giao đấu ngang ngửa.","anchor":"Một thanh phi đao màu đỏ từ lòng bàn tay bắn ra, hóa thành một đạo hồng quang nghênh đón ngân hồng"}]},"nguon":["@c0730"]},{"id":"luong-dien-hong-tieu-phien","name":"Lưỡng diện hồng tiểu phiên","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-co","blurb":"Pháp bảo phiên kỳ của Quật Diệu, phất lên đón gió phồng to hơn một trượng, phóng ra hai đạo hỏa trụ hỗ trợ hỏa giao tụ hỏa vân.","detail":"Pháp bảo dạng phiên kỳ (cờ nhỏ) hai mặt đỏ của Quật Diệu. Phất lên đón gió phồng to hơn một trượng, bắn ra hai đạo hỏa trụ thô to hội hợp với hỏa giao tạo thành hỏa vân khổng lồ.","congNang":["Phóng hỏa trụ","Hỗ trợ hỏa giao tụ hỏa vân"],"tabs":{"tienTrinh":[{"chuong":"@c0730","loai":"dung","importance":"normal","giaiDoan":"Tăng cường hỏa giao","text":"Quật Diệu phất lưỡng diện hồng tiểu phiên phóng hai hỏa trụ hội hợp hỏa giao tạo hỏa vân khổng lồ.","anchor":"trong tay quang hoa sáng ngời xuất hiện lưỡng diện hồng tiểu phiên"}]},"nguon":["@c0730"]},{"id":"song-vi-phi-thuy-xa","name":"Song Vĩ Phỉ Thúy Xà","cn":"","category":"khac","categoryLabel":"Độc vật / Linh thú","phamCap":"Ngang thập đại tuyệt độc truyền thuyết","soHuu":["Kẻ ám sát đại điện"],"trangThai":"đang sử dụng","blurb":"Song Vĩ Phỉ Thúy Xà là loài rắn hai đuôi màu bích lục có độc tính cực mạnh, ngang hàng thập đại tuyệt độc truyền thuyết. Nó có khả năng ngụy trang thành ngọc giản, một khi cắn trúng thì ngay cả tu sĩ Nguyên Anh kỳ cũng không thể độn thoát, thi thể nạn nhân nhanh chóng tan chảy.","detail":"Song Vĩ Phỉ Thúy Xà là loài độc xà hai đuôi toàn thân bích lục, mắt xanh toát vẻ âm độc, phun nọc tím đen. Nó được kẻ ám sát sử dụng làm hung khí, ngụy trang dưới hình dạng một lục sắc ngọc giản để tiếp cận mục tiêu mà không gây nghi ngờ, sau đó biến hóa trở lại hình dạng tiểu xà để tấn công. Tại @c0732, kẻ ám sát đã dùng nó cắn chết một đại hán trọc mi tu luyện đến Nguyên Anh kỳ; nạn nhân bị cắn không còn sức độn thoát, ngay cả nguyên anh cũng bất lực, và thi thể sau đó bắt đầu tan chảy. Kẻ ám sát từng tiếc rằng Song Vĩ Phỉ Thúy Xà không có cánh để bay, nếu có thì nó sẽ trở thành sát thủ tu sĩ cực kỳ sắc bén.","congNang":["Ngụy trang thành vật phẩm — có thể biến thành lục sắc ngọc giản để che giấu bản thể @c0732","Cắn độc giết tu sĩ Nguyên Anh kỳ, khiến nguyên anh cũng không có lực độn thoát @c0732","Nọc độc khiến thi thể nạn nhân tan chảy @c0732"],"chuSoHuu":[{"ten":"Kẻ ám sát đại điện","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"dùng","importance":"major","giaiDoan":"Ám sát đại hán trọc mi","text":"Kẻ ám sát dùng Song Vĩ Phỉ Thúy Xà ngụy trang thành lục sắc ngọc giản, biến thành tiểu xà cắn chết đại hán trọc mi Nguyên Anh kỳ tại đại điện Hoàng Long Sơn.","anchor":"lục quang ngọc giản chợt lóe, đột nhiên hóa thành một con tiểu xà màu xanh, thế như sét đánh cắn ngay cổ tay của đại hán","phamCap":"Ngang thập đại tuyệt độc"}]},"nguon":["@c0732"],"uyLuc":"Một nhát cắn giết chết tu sĩ Nguyên Anh kỳ, nguyên anh không thể độn thoát, thi thể tan chảy; độc tính được đánh giá ngang hàng thập đại tuyệt độc truyền thuyết.","dacDiem":"Rắn hai đuôi toàn thân bích lục, mắt xanh âm độc, phun nọc tím đen; có khả năng biến hóa ngụy trang thành ngọc giản."},{"id":"tui-tru-vat-thien-khoc","name":"Túi trữ vật màu đen (của Thiên Khốc)","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đổi chủ","blurb":"Túi trữ vật màu đen của hắc bào nhân Thiên Khốc, Hàn Lập thu được sau khi diệt sát Thiên Khốc.","detail":"Túi trữ vật màu đen thuộc về hắc bào nhân Thiên Khốc (đến từ Bàng Đại đế quốc). Hàn Lập thu được sau khi dùng Ích Tà Thần Lôi diệt sát Thiên Khốc, kim hồ co rút lại bao bọc túi đem về.","chuSoHuu":[{"ten":"Hắc bào nhân","tuChuong":"@c0732","denChuong":"@c0732","cachCoDuoc":"Vật sở hữu ban đầu","trangThai":"chủ chết"},{"ten":"Hàn Lập","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm sau khi diệt Thiên Khốc","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu chiến lợi phẩm","text":"Hàn Lập thu Túi trữ vật màu đen từ hắc bào nhân Thiên Khốc sau khi diệt sát.","anchor":"kim hồ co rút lại, bao bọc lấy một cái Túi trữ vật màu đen đem lại trên tay"}]},"nguon":["@c0732"]},{"id":"tui-tru-vat-dai-han-luc","name":"Túi trữ vật (của đại hán họ Lục)","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Kẻ ám sát đại điện"],"trangThai":"đổi chủ","blurb":"Túi trữ vật của đại hán trọc mi (họ Lục), bị kẻ ám sát lấy từ thi thể đang tan chảy và hạ thần thức tìm kiếm vật gì đó bên trong.","detail":"Túi trữ vật thuộc về đại hán trọc mi (họ Lục), chỉ huy phòng thủ Hoàng Long Sơn. Sau khi đại hán bị Song Vĩ Phỉ Thúy Xà cắn chết, kẻ ám sát lấy túi trữ vật từ thi thể đang tan chảy, kích động hạ thần thức tìm kiếm vật gì đó — ám chỉ bên trong có vật phẩm quan trọng.","chuSoHuu":[{"ten":"Đại hán họ Lục","tuChuong":"@c0732","denChuong":"@c0732","cachCoDuoc":"Vật sở hữu ban đầu","trangThai":"chủ chết"},{"ten":"Kẻ ám sát đại điện","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Cướp từ thi thể","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"đổi chủ","importance":"normal","giaiDoan":"Kẻ ám sát cướp lấy","text":"Kẻ ám sát lấy Túi trữ vật trên thi thể đang tan chảy của đại hán trọc mi, kích động hạ thần thức tìm kiếm vật gì đó bên trong.","anchor":"Túi trữ vật trên thi thể trực tiếp bay đến trên tay hắn"}]},"nguon":["@c0732"]},{"id":"lam-sac-phi-xoa","name":"Lam sắc phi xoa","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":null,"soHuu":["Cốc Song Bồ"],"trangThai":"đang sử dụng","blurb":"Pháp bảo màu xanh lam hình phi xoa của Cốc Song Bồ, có thể hợp nhất với độn quang tấn công hoặc xoay tròn thành màn chắn hộ thể.","detail":"Pháp bảo được Cốc Song Bồ phun ra từ miệng khi bị nhốt trong quang tráo đại trận Hoàng Long Sơn. Khi tấn công, phi xoa hợp làm một với độn quang thành lam hồng to lớn đánh mãnh liệt vào lồng ánh sáng bạc, nhưng bị bắn ngược trở lại. Khi phòng ngự, phi xoa xoay tròn biến thành màn chắn xanh lam che hộ thể chống đỡ ngân hoa hủy diệt từ cấm chế. Cả hai lần đều không đủ sức phá vỡ cấm chế trung tâm đại trận.","nguon":["@c0733"]},{"id":"huyet-nhuc-khoi-loi-the-than-luc","name":"Huyết nhục khôi lỗi thế thân (của đại hán họ Lục)","cn":null,"category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":null,"soHuu":["Đại hán họ Lục"],"trangThai":"đã sử dụng (bị hủy)","blurb":"Khôi lỗi bằng huyết nhục giống hệt đại hán họ Lục, do tu sĩ bí ẩn ở Cửu Quốc Minh luyện chế, dùng để giả chết dụ gian tế lộ mặt.","detail":"Huyết nhục khôi lỗi thế thân được một vị tu sĩ thần bí ở Cửu Quốc Minh luyện chế, giống bản thân đại hán họ Lục như đúc. Bên trong trống rỗng, sau khi bị hủy sẽ hóa thành bãi máu đen. Tinh vi đến mức tu sĩ Nguyên Anh nếu không dùng thần thức quét kỹ sẽ không nhận ra. Đại hán họ Lục đã dùng khôi lỗi này thay thế bản thân, để Cốc Song Bồ dùng song vĩ phỉ thúy xà giết chết khôi lỗi mà tưởng đã đắc thủ, từ đó lộ mặt gian tế. Bản thân đại hán họ Lục thừa nhận việc thỉnh người luyện chế khôi lỗi ban đầu chỉ là nhất thời cao hứng.","nguon":["@c0733"]},{"id":"ngoc-gian-trang","name":"Ngọc giản trắng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Ngọc giản màu trắng được đại hán trọc mi dùng bí thuật phục chế đoạn đối thoại với Cốc Song Bồ vào bên trong làm chứng cớ vụ gián điệp Mộ Lan.","detail":"Đại hán trọc mi dùng bí thuật phục chế đoạn đối thoại giữa mình với Cốc Song Bồ vào ngọc giản trắng này, dự định trình làm chứng cớ cho Ngự Linh Tông.","congNang":["Lưu trữ phục chế đối thoại làm chứng cớ"],"tabs":{"tienTrinh":[{"chuong":"@c0734","loai":"xuất hiện","importance":"normal","giaiDoan":"Được tiết lộ làm chứng cớ","text":"Đại hán trọc mi cho biết đã phục chế đối thoại vào ngọc giản trắng làm bằng chứng vụ gián điệp Cốc Song Bồ.","anchor":"trong tay đã xuất hiện một cái ngọc giản màu trắng, mặt lộ vẻ quỷ dị nói"}]},"capNhatToi":"@c0734","nguon":["@c0734"]},{"id":"lenh-bai-cam-che","name":"Lệnh bài cấm chế","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Lệnh bài phát ánh bạc dùng để điều khiển và gia cố cấm chế quang tráo giam giữ Cốc Song Bồ.","detail":"Đại hán trọc mi phun tinh khí kích hoạt lệnh bài, ném lên đỉnh đầu rồi phóng hơn mười đạo pháp quyết vào màn hào quang, khiến ngân quang dày thêm ba phần và ngân sắc lôi hoa ngưng tụ trên quang bích.","congNang":["Điều khiển cấm chế quang tráo","Gia cố ngân quang bích và triệu hoán lôi hoa"],"tabs":{"tienTrinh":[{"chuong":"@c0734","loai":"dùng","importance":"normal","giaiDoan":"Gia cố cấm chế giam Cốc Song Bồ","text":"Đại hán trọc mi dùng lệnh bài gia cố cấm chế khi quái xà phụ linh tấn công quang bích, nhưng quái xà vẫn phá được lỗ hổng thoát ra.","anchor":"quang mang chợt lóe, lệnh bài cấm chế phát ra ánh sáng màu bạc liền hiện ra trong tay"}]},"capNhatToi":"@c0734","nguon":["@c0734"]},{"id":"chien-giap-den-cu-thu","name":"Chiến giáp đen của cự thú","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Tầng chiến giáp đen thui phát sáng khoác trên cự thú khổng lồ của Nhạc thượng sư, mơ hồ có chú văn chớp động, giá trị xa xỉ.","detail":"Chiến giáp đen thui phát sáng, khoác trên thân cự thú khổng lồ (dài hai mươi trượng, cao ba mươi trượng) của Nhạc thượng sư. Bên trên mơ hồ có các loại chú văn chớp động, giá trị xa xỉ.","nguon":["@c0735"],"tabs":{"tienTrinh":[{"chuong":"@c0735","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Khoác trên cự thú khổng lồ của Nhạc thượng sư khi đại quân pháp sĩ tiến đến Hoàng Long Sơn.","anchor":"Trên thân hình to lớn kia có khoác một tầng chiến giáp đen thui phát sáng, bên trên mơ hồ có các loại chú văn chớp động"}]}},{"id":"cu-te-thu","name":"Cự Tê Thú","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Linh thú chiến đấu của Nhạc Thượng Sư, sẽ phối hợp cùng Quật Diệu phá trận Hoàng Long Sơn.","detail":"Nhạc Thượng Sư cho Cự Tê Thú phối hợp Quật Diệu phá trận, dùng trong chiến dịch tổng công kích đại trận Hoàng Long Sơn.","nguon":["@c0736"]},{"id":"nac-thien-ky","name":"Nặc Thiên Kỳ","cn":"匿天旗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-dung","blurb":"Pháp bảo của lão giả họ Mã, có thể che khuất cả nửa đỉnh núi nhưng tiêu hao đáng kể pháp lực.","detail":"Pháp bảo ẩn tàng, lão giả họ Mã dùng để che khuất nửa đỉnh núi Hỏa Long Sơn, tiêu hao đáng kể pháp lực, chỉ còn đủ sức cầm chân một Mộ Lan Đại Thượng Sư.","congNang":["Che giấu, ẩn tàng khu vực rộng lớn (nửa đỉnh núi)"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Che khuất Hỏa Long Sơn","text":"Lão giả họ Mã vận dụng Nặc Thiên Kỳ che khuất nửa đỉnh núi, tiêu hao đáng kể pháp lực.","anchor":"Mã huynh mới vừa rồi vận dụng Nặc Thiên Kỳ che khuất nửa đỉnh núi"}]},"nguon":["@c0737"]},{"id":"luc-dien-hong-cu-phien","name":"Lục diện hồng cự phiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-dung","blurb":"Sáu cái kỳ phiên lục diện màu đỏ của Quật Diệu, phối hợp linh thuật đại trận, phát quang trụ dẫn dắt hỏa cầu phá cấm chế.","detail":"Bộ sáu kỳ phiên lục diện màu đỏ, pháp bảo của Quật Diệu, vây quanh khi chủ trì linh thuật đại trận. Bắn ra sáu đạo quang trụ đỏ dẫn dắt hỏa cầu lao vào phá tan cấm chế vụ hải.","congNang":["Phối hợp linh thuật đại trận, phát sáu đạo quang trụ đỏ dẫn dắt hỏa cầu phá cấm chế"],"chuSoHuu":[{"ten":"Quật Diệu","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Phá cấm chế vụ hải","text":"Quật Diệu dùng sáu lục diện hồng cự phiên bắn ra sáu đạo quang trụ đỏ dẫn hỏa cầu phá cấm chế vụ hải Hỏa Long Sơn.","anchor":"sáu đạo quang trụ màu đỏ từ trong kỳ phiên nghiêng bắn ra"}]},"nguon":["@c0737"]},{"id":"vien-quyen-vang","name":"Viên quyển màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-dung","blurb":"Pháp bảo của nữ tử áo xanh (Nhạc Thượng Sư), ném choàng lên sừng cự tê thú phát kim quang kích thích con thú điên cuồng xông vào chiến trường.","detail":"Viên quyển kim sắc, nữ tử áo xanh ném choàng lên sừng xanh của cự tê thú, phát kim quang chói mắt khiến mắt con thú đỏ bừng, điên cuồng lao vào vụ hải.","congNang":["Kích thích, điều khiển cự thú (choàng lên sừng phát kim quang)"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Kích hoạt cự tê thú","text":"Nữ tử áo xanh ném viên quyển vàng choàng lên sừng xanh cự tê thú, phát kim quang chói mắt kích thích con thú điên cuồng lao vào vụ hải.","anchor":"kim sắc quyển chuẩn xác choàng lên sừng màu xanh của cự tê"}]},"nguon":["@c0737"]},{"id":"bach-doan-con-tu-nhi-kim-vien","name":"Bạch đoản côn (Tứ Nhĩ Kim Viên khí linh)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Khí linh chi bảo","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Bạch đoản côn là khí linh chi bảo của đại hán họ Lục, khi thi triển phun từ miệng ra rồi phát kim hoàng quang, hóa hiện bóng ảnh Tứ Nhĩ Kim Viên — vượn vàng bốn tai cao năm sáu trượng, có thể chiến đấu tự chủ. Sự xuất hiện của nó khiến Quật Diệu (Nguyên Anh Kỳ) thất thanh kinh hãi khi nhận ra đây là khí linh chi bảo.","detail":"Bạch đoản côn là pháp bảo được đại hán họ Lục nuôi dưỡng trong thân, thi triển bằng cách há mồm phun ra. Côn ban đầu phát bạch quang, sau chuyển thành kim hoàng quang rực rỡ, hiện ra bóng ảnh Tứ Nhĩ Kim Viên — cự viên bốn tai cao năm sáu trượng, tướng mạo hung ác, ôm đại côn hóa kim quang tấn công đối thủ. Đại hán họ Lục tuyên bố đây là lần đầu hiển lộ khí linh trước người khác. Quật Diệu ở cảnh giới Nguyên Anh Kỳ khi nhận ra bản chất khí linh chi bảo của vật này đã thất thanh kinh hãi, cho thấy đẳng cấp vượt trội của pháp bảo (@c0738).","congNang":["Phun từ miệng ra thi triển, phát bạch quang rồi chuyển kim hoàng quang (@c0738)","Hóa hiện bóng ảnh Tứ Nhĩ Kim Viên — vượn vàng bốn tai cao năm sáu trượng, tướng mạo hung ác, ôm đại côn chiến đấu tự chủ (@c0738)"],"chuSoHuu":[{"ten":"Đại hán họ Lục","tuChuong":"@c0738","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu hiển lộ","text":"Đại hán họ Lục há mồm phun ra bạch đoản côn, phát kim hoàng quang hóa Tứ Nhĩ Kim Viên khổng lồ tấn công Quật Diệu. Quật Diệu kinh hãi nhận ra là khí linh chi bảo.","anchor":"đây là lần đầu tiên từ khi Lục mỗ có được tứ nhĩ kim viên khí linh trước mặt người khác hiển lộ"}]},"nguon":["@c0738"],"uyLuc":"Khí linh chi bảo đẳng cấp đủ khiến tu sĩ Nguyên Anh Kỳ (Quật Diệu) thất thanh kinh hãi khi nhận ra bản chất, cự viên hóa hiện ôm đại côn kim quang tấn công đối thủ (@c0738).","dacDiem":"Khí linh chi bảo dạng bạch đoản côn, nuôi trong thân phun từ miệng ra; bạch quang chuyển kim hoàng quang khi hiển lộ khí linh; bóng ảnh hóa hiện là Tứ Nhĩ Kim Viên bốn tai, cao năm sáu trượng, tướng mạo hung ác."},{"id":"hai-thanh-ngan-qua","name":"Hai thanh ngân qua (giáo bạc lôi điện)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Hai ngọn giáo ngân quang có lôi hình quấn quanh, hỗ kích nhau tạo điện hồ cực thô. Được dùng để dụ cự tê thú tách khỏi đội hình pháp sĩ Mộ Lan.","detail":"Hai ngọn giáo ngân quang lập lòe, có lôi hình cung quấn quanh, bay ra từ sương mù. Né tránh pháp bảo của Kết Đan pháp sĩ, hai thanh ngân qua hỗ kích nhau tạo ra điện hồ cực thô đánh xuống đầu cự tê. Phá được linh quang hộ thể của cự tê nhưng không xuyên thủng chiến giáp. Mục đích chính là chọc giận dụ cự tê đuổi theo vào sương mù, tách khỏi đội hình.","congNang":["Hai giáo hỗ kích tạo lôi điện cường đại"],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"dùng","importance":"normal","giaiDoan":"Dụ cự tê tách đội hình","text":"Hai thanh ngân qua bay ra từ sương mù, hỗ kích tạo điện hồ đánh cự tê chọc giận, dụ nó đuổi theo vào sương mù tách khỏi đám pháp sĩ Mộ Lan.","anchor":"hai thanh ngân qua không có dấu hiệu đan vào nhau mà hỗ kích, nhất thời một tiếng tiếng sấm nổ truyền ra"}]},"nguon":["@c0738"]},{"id":"thanh-sac-vien-chau","name":"Thanh sắc viên châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","aliases":["Thanh châu"],"blurb":"Viên châu thanh sắc to cỡ nắm tay, bảo vật của nữ tử áo xanh (Nhạc Thượng Sư), rút ra chuẩn bị giao chiến với Hàn Lập. Công năng chưa rõ.","detail":"Viên châu thanh sắc to cỡ nắm tay, nữ tử áo xanh vỗ nhẹ Túi trữ vật rồi viên châu hiện lên trong tay, chuẩn bị đối đầu Hàn Lập. Công năng cụ thể chưa hé lộ.","chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0738","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nữ tử áo xanh rút thanh châu to cỡ nắm tay từ Túi trữ vật, chuẩn bị giao chiến với Hàn Lập.","anchor":"một khỏa thanh châu to cỡ nắm tay bỗng nhiên hiện lên ở trong tay"}]},"nguon":["@c0738"]},{"id":"tuyet-dieu-phap-bao","name":"Tuyết điêu pháp bảo","cn":"","aliases":["Bạch sắc đoạn pháp bảo","Tuyết sắc cự điêu","Cự điêu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"hong","blurb":"Tuyết điêu pháp bảo là bạch sắc đoạn mang trạng pháp bảo của Nhạc Thượng Sư, khi ném ra hóa thành cự điêu khổng lồ cánh rộng mấy trượng, mắt đỏ, móng vuốt đen, tốc độ cực nhanh. Pháp bảo từng được sử dụng để tấn công Hàn Lập nhưng bị bắt gọn và đóng băng hoàn toàn bởi Kiền Lam Băng Diễm.","detail":"Pháp bảo thuộc về nữ tử áo xanh Nhạc Thượng Sư, hình thái thường là một dải đoạn mang bạch sắc mang trên người. Khi thi triển, ném ra biến hóa thành con tuyết điêu khổng lồ, đôi cánh rộng mấy trượng, mắt đỏ rực, móng vuốt đen bóng như kim loại. Tuyết điêu di chuyển với tốc độ cực nhanh, có thể phóng phong nhận từ đôi cánh đủ sức phá vỡ kim võng. Trong trận chiến với Hàn Lập (@c0739), Nhạc Thượng Sư ném pháp bảo này ra tấn công, tuyết điêu phóng phong nhận phá được kim võng của đối phương. Tuy nhiên, Hàn Lập dùng hắc hồng cự thủ bắt gọn tuyết điêu rồi phun Kiền Lam Băng Diễm đóng băng hoàn toàn pháp bảo.","hinhDang":"Bạch sắc đoạn (dải lụa trắng), hóa thành cự điêu cánh rộng mấy trượng, mắt đỏ, móng vuốt đen","congNang":["Ném ra hóa thành tuyết điêu khổng lồ cánh rộng mấy trượng, mắt đỏ, móng vuốt đen, tốc độ cực nhanh @c0739","Phóng phong nhận từ đôi cánh, đủ uy lực phá vỡ kim võng @c0739"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0739","denChuong":"","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c0739","loai":"dùng","importance":"major","giaiDoan":"Xuất hiện và bị đóng băng","text":"Nhạc Thượng Sư ném ra tấn công Hàn Lập, tuyết điêu phóng phong nhận phá kim võng. Bị Hàn Lập dùng hắc hồng cự thủ bắt gọn và phun Kiền Lam Băng Diễm đóng băng hoàn toàn.","anchor":"bạch mang pháp bảo sau khi xoay quanh một cái thì chợt hóa thành một con chim lớn vỗ hai cánh lớn chừng mấy trượng"}]},"capNhatToi":"@c0739","nguon":["@c0739"],"uyLuc":"Phong nhận phóng từ cánh tuyết điêu đủ sức phá vỡ kim võng @c0739","dacDiem":"Hình thái thường là bạch sắc đoạn mang mang trên người; khi kích hoạt hóa thành cự điêu tuyết trắng khổng lồ với mắt đỏ rực và móng vuốt đen như kim loại, di chuyển tốc độ cực nhanh"},{"id":"thanh-dong-dang","name":"Thanh Đồng Đăng","cn":"青铜灯","aliases":["Đồng đăng Cổ Bảo","Đồng đăng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Thanh Đồng Đăng là một cổ bảo hình ngọn đèn đồng xanh cực kỳ cổ xưa, cổ đến mức bề mặt đã ngả sang màu đen. Được nữ tử áo xanh Nguyên Anh Trung Kỳ rút ra trong trận chiến với Hàn Lập, nhưng uy lực thực sự chưa được thi triển do Hàn Lập cảm nhận nguy hiểm mà lập tức bỏ chạy.","detail":"Thanh Đồng Đăng xuất hiện khi nữ tử áo xanh quyết định tổn hao nguyên khí để diệt Hàn Lập. Bảo vật có hình dạng ngọn đèn đồng xanh, cổ xưa đến mức bề mặt đã mơ hồ biến thành màu đen. Nữ tử lộ vẻ không cam lòng khi phải dùng đến, cho thấy đại giá phải trả khi sử dụng rất lớn, ngay cả đối với pháp sĩ Nguyên Anh Trung Kỳ. Hàn Lập lần đầu nhìn thấy bảo vật hình đèn này đã cảm thấy cực kỳ nguy hiểm, bèn lập tức thi triển thần thông bỏ chạy mà không dám đối đầu. Uy lực thực sự của Thanh Đồng Đăng chưa được thể hiện trong lần xuất hiện này.","nguon":["@c0740"],"hinhDang":"Ngọn đèn đồng xanh cổ xưa đến mức ngả đen","congNang":["Uy lực chưa rõ, nhưng khiến pháp sĩ Nguyên Anh Trung Kỳ cũng phải tổn hao nguyên khí cực lớn mới dùng được, bản thân sự hiện diện đã đủ khiến Hàn Lập cảm nhận nguy hiểm chí mạng mà bỏ chạy @c0740"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0740","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0740","loai":"xuất hiện","importance":"major","giaiDoan":"Nữ tử rút Cổ Bảo quyết chiến","text":"Nữ tử áo xanh quyết tổn hao nguyên khí rút Thanh Đồng Đăng dạng ngọn đèn đồng xanh cổ xưa ngả đen, lộ vẻ không cam lòng nhưng quyết diệt Hàn Lập. Hàn Lập cảm thấy nguy hiểm nên bỏ chạy, Cổ Bảo chưa kịp thi triển uy lực.","anchor":"Quang hoa thu liễm hiện lên một cái Thanh Đồng đăng trông vô cùng cổ xưa, thậm chí quá cổ xưa đến mức mơ hồ biến thành màu đen"}]},"uyLuc":"Chưa thực sự thi triển, nhưng chỉ mới rút ra đã khiến Hàn Lập cảm thấy cực kỳ nguy hiểm, lập tức bỏ chạy không dám đối đầu.","dacDiem":"Hình dạng ngọn đèn đồng xanh, cổ xưa đến mức bề mặt đã mơ hồ chuyển sang màu đen; sử dụng đòi hỏi tổn hao nguyên khí rất lớn, ngay cả pháp sĩ Nguyên Anh Trung Kỳ cũng phải lộ vẻ không cam lòng khi dùng."},{"id":"bach-lien","name":"Bạch Liên","cn":"白莲","category":"khac","categoryLabel":"Pháp lực ngưng luyện","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Hoa sen trắng do tự thân pháp lực nữ tử ngưng luyện thành, không phải bảo vật, có thể phòng ngự tạo liên ảnh và nhập thể qua thiên linh cái phản kích cận chiến cực mạnh.","detail":"Bạch Liên hoàn toàn do tự thân pháp lực ngưng luyện, tạo liên ảnh chặn được quang phiến Âm Ma Trảm. Có thể nhập vào thiên linh cái (đỉnh đầu) của nữ tử, từ trán phóng cánh hoa sen trắng vừa phòng ngự vừa phản kích, đánh bật Hàn Lập khạc máu. Liên quan phật môn bí thuật.","nguon":["@c0740","@c0741"],"congNang":["Tạo liên ảnh phòng ngự chặn quang phiến","Nhập thiên linh cái phóng cánh hoa phản kích cận chiến","Phối hợp tiểu đỉnh thi triển Phong Độn Thuật","Co rút cánh hoa tạo quang mạc phòng ngự tổng hợp","Bung cánh hoa như lưỡi dao phản công cắt phá trận pháp bên ngoài"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0740","denChuong":"","cachCoDuoc":"Tự thân pháp lực ngưng luyện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0740","loai":"dùng","importance":"normal","giaiDoan":"Phòng ngự và phản kích trong đại chiến Hàn Lập","text":"Bạch Liên tạo liên ảnh chặn Âm Ma Trảm, sau đó nhập thiên linh cái phóng cánh hoa đánh trọng thương Hàn Lập.","anchor":"Bạch Liên nọ thoạt nhìn cũng không phải do bảo vật nào đó biến thành, mà hoàn toàn do tự thân pháp lực ngưng luyện hình thành"},{"chuong":"@c0741","loai":"dùng","importance":"normal","giaiDoan":"Phòng ngự và phản công trong trận chiến","text":"Nhạc Thượng Sư dùng Bạch Liên co rút cánh hoa bảo hộ bên trong, chặn vụ giao và quang ti xanh hồng. Sau đó bung cánh hoa phá tan lục vụ và quang ti bên ngoài.","anchor":"cánh hoa Bạch Liên dần dần co rút lại, trong nháy mắt đem này nữ tử bảo hộ vào trong"}]}},{"id":"trung-giap-tam-sac","name":"Trùng giáp tam sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiến giáp ba màu Hàn Lập mặc bên trong trường bào, có khả năng hộ thể giảm thương và tự phục hồi dưới thanh quang.","detail":"Chiến giáp tam sắc quang trạch mặc trong trường bào. Bị cánh Bạch Liên đánh lõm và nứt mấy chỗ nhưng dưới thanh quang từ tay Hàn Lập tự phục hồi nguyên trạng như mới tinh trong nháy mắt, khiến nữ tử Nguyên Anh Trung Kỳ kinh ngạc tăng sát ý.","nguon":["@c0740"],"hinhDang":"Chiến giáp có tam sắc quang trạch","congNang":["Hộ thể giảm thương từ đòn cận chiến cấp Nguyên Anh","Tự phục hồi nguyên trạng dưới thanh quang"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0740","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0740","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện và tự phục hồi trong trận chiến","text":"Hàn Lập xé trường bào lộ trùng giáp tam sắc bị lõm nứt, dùng thanh quang phục hồi nguyên trạng trong nháy mắt.","anchor":"chiến giáp nguyên bổn có mấy chỗ lõm cũng nứt dưới ánh thanh quang chiếu qua, lấy mắt thường có thể thấy được tốc độ sửa chữa đột khởi"}]}},{"id":"dam-hoang-sac-ngoc-boi","name":"Đạm hoàng sắc ngọc bội","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Ngọc bội màu đạm hoàng của nữ tử họ Nhạc, phóng hoàng hà thổi tan phấn hồng sắc hương vụ của Ngân Nguyệt.","detail":"Bảo vật trang sức kiêm phòng ngự của nữ tử họ Nhạc. Khi kích hoạt phóng hoàng hà cuốn sạch hương vụ mị thuật.","nguon":["@c0742"]},{"id":"tu-thanh-dau","name":"Tử Thành Đâu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Ngân Nguyệt"],"trangThai":"Bị Trọng Thần Sư đoạt","blurb":"Pháp bảo tử sắc đại võng của Ngân Nguyệt, bị Trọng Thần Sư bắt lấy.","detail":"Ngân Nguyệt triển khai Tử Thành Đâu chắn trước người nhưng bị Trọng Thần Sư ngân sắc đại thủ bắt lấy.","chuSoHuu":[{"ten":"Ngân Nguyệt","tuChuong":"@c0743","denChuong":"@c0743","cachCoDuoc":"Pháp bảo bản thân","trangThai":"bi-cuop"}],"tabs":{"tienTrinh":[{"chuong":"@c0743","loai":"doi-chu","importance":"normal","giaiDoan":"Bị đoạt","text":"Ngân Nguyệt vung Tử Thành Đâu chắn nhưng bị Trọng Thần Sư bắt lấy.","anchor":"một tay bắt lấy Tử Thành Đâu"}]},"nguon":["@c0743"]},{"id":"thanh-dong-co-dang","name":"Thanh Đồng cổ đăng","cn":"","aliases":["Đồng đăng","Mộ Lan nguyên minh đăng","đèn bằng đồng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Truyền thừa chi bảo Mộ Lan nhân","soHuu":["Nhạc thượng sư"],"trangThai":"Nhạc thượng sư nhận lại","blurb":"Truyền thừa chi bảo của Mộ Lan nhân, còn gọi là Mộ Lan nguyên minh đăng. Bị Ngân Nguyệt nhốt rồi được Trọng Thần Sư giải cứu trả lại cho Nhạc thượng sư.","detail":"Thanh Đồng cổ đăng được Trọng Thần Sư gọi là Mộ Lan nguyên minh đăng, là truyền thừa chi bảo của Mộ Lan nhân. Bị Ngân Nguyệt nhốt trong bạch quang của Hoa Lam Cổ Bảo, sau đó được Trọng Thần Sư cướp lại trả cho Nhạc thượng sư.","nguonGoc":"Truyền thừa chi bảo Mộ Lan nhân","chuSoHuu":[{"ten":"Nhạc thượng sư","tuChuong":"@c0743","denChuong":"","cachCoDuoc":"Trọng Thần Sư trả lại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0743","loai":"doi-chu","importance":"normal","giaiDoan":"Lộ danh xưng, được trả lại","text":"Trọng Thần Sư nhận ra đây là Mộ Lan nguyên minh đăng, truyền thừa chi bảo Mộ Lan nhân, trả lại cho Nhạc thượng sư.","anchor":"vật này không phải là Mộ Lan nguyên minh đăng chúng ta hay sao"}]},"nguon":["@c0743"]},{"id":"thanh-tu-luong-sac-cu-kiem","name":"Thanh tử lưỡng sắc cự kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Cự kiếm có hai loại hỏa diễm thanh tử cùng tồn tại một cách quỷ dị, khiến Trọng Thần Sư thoáng dị sắc.","detail":"Hàn Lập một tay dẫn theo thanh tử lưỡng sắc cự kiếm khi trốn chạy. Hai loại hỏa diễm cùng tồn tại trên kiếm, Trọng Thần Sư nhìn thấy thì dị sắc hiện lên trong mắt.","congNang":["Hai loại hỏa diễm thanh tử cùng tồn tại trên kiếm"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0743","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0743","loai":"xuat hien","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Hàn Lập dẫn theo khi trốn chạy, hai loại hỏa diễm thanh tử cùng tồn tại quỷ dị khiến Trọng Thần Sư thoáng dị sắc.","anchor":"thanh tử hai loại hỏa diễm cùng tồn tại một cách quỷ dị"}]},"nguon":["@c0743"]},{"id":"thanh-sac-dang-diem","name":"Thanh sắc đăng diễm","cn":"青色灯焰","aliases":["Thanh diễm"],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Ngọn lửa đặc biệt phát ra từ đồng đăng bảo vật truyền thừa Mộ Lan, có quỷ đạo khó trừ, đã dính nhiễm lên Thanh Trúc Phong Vân Kiếm của Hàn Lập.","detail":"Thanh sắc đăng diễm là ngọn lửa từ đồng đăng bảo vật truyền thừa của Mộ Lan nhân, dính lên Thanh Trúc Phong Vân Kiếm trong trận chiến. Hàn Lập dùng Tử La Thiên Hỏa áp chế nhưng chưa trừ hết hậu hoạn, cần thời gian luyện hóa.","nguon":["@c0744"]},{"id":"hop-xuong-am-minh","name":"Hộp xương từ Âm Minh chi địa","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang mang theo","blurb":"Hộp xương Hàn Lập nhận được tại Âm Minh chi địa, bên trong ghi phương pháp luyện chế Hàng Linh phù, cần giao trả cho Thiên Phù môn.","detail":"Hàn Lập mang trên người hộp xương được nhờ vả khi ở Âm Minh chi địa. Bên trong ghi chú phương pháp luyện chế Hàng Linh phù. Nếu có dịp đi Đại Tấn quốc thì cần ghé Thiên Phù môn giao trả theo lời hứa.","congNang":["Chứa phương pháp luyện chế Hàng Linh phù"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0748","denChuong":"","cachCoDuoc":"Nhận tại Âm Minh chi địa","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0748","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập nhớ lại lời hứa giao trả","text":"Hàn Lập nhớ tới hộp xương chứa phương pháp luyện Hàng Linh phù, dự tính nếu đi Đại Tấn quốc phải ghé Thiên Phù môn giao trả.","anchor":"Trong đó ghi chú phương pháp luyện chế Hàng Linh phù"}]},"nguon":["@c0748"]},{"id":"linh-chuc-qua","name":"Linh Chúc quả","cn":"灵烛果","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thiên tài địa bảo (tuyệt tích)","soHuu":[],"trangThai":"nghi ton tai trong Truy Ma Coc","blurb":"Linh Chúc quả là thiên tài địa bảo đã tuyệt tích từ lâu, đóng vai trò chủ dược trong luyện chế Tạo Hóa đan. Theo thông tin khai thác được từ đệ tử Quỷ Linh Môn, loại quả này có khả năng còn tồn tại bên trong Trụy Ma Cốc — nơi bị phong bế từ thời man hoang.","detail":"Linh Chúc quả là một loại quả linh dị cực kỳ hiếm, ngay trong thời man hoang cũng là thứ khả ngộ bất khả cầu. Sau thượng cổ, loại quả này hoàn toàn tuyệt tích, khiến không ai còn có thể luyện chế Tạo Hóa đan do thiếu phương thuốc. Tại mốc @c0749, ba nữ tu Tử Linh, Mai Ngưng và nữ tử họ Tống dùng huyễn thuật khai thác bí mật từ đệ tử Quỷ Linh Môn, qua đó xác nhận Linh Chúc quả có khả năng còn tồn tại trong Trụy Ma Cốc. Trụy Ma Cốc là nơi bị phong bế từ thời man hoang, chỉ có Thương Khôn thượng nhân từng sống sót đi ra, nên môi trường bên trong có thể vẫn bảo tồn được loại thiên tài địa bảo này.","congNang":["Là chủ dược dùng để luyện chế Tạo Hóa đan @c0749"],"tabs":{"tienTrinh":[{"chuong":"@c0749","loai":"xuat-hien","importance":"major","giaiDoan":"Được tiết lộ tồn tại trong Trụy Ma Cốc","text":"Ba nữ tu (Tử Linh, Mai Ngưng, nữ tử họ Tống) khai thác bí mật từ đệ tử Quỷ Linh Môn bằng huyễn thuật, xác nhận Linh Chúc quả có khả năng tồn tại trong Trụy Ma Cốc. Hàn Lập ban đầu kích động, sau trầm ngâm cân nhắc và đặt điều kiện.","anchor":"Loại thiên tài địa bảo đó đã tuyệt tích từ lâu rồi mà"}]},"nguon":["@c0749"]},{"id":"tao-hoa-dan","name":"Tạo Hóa đan","cn":"造化丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thượng cổ đan dược (thất truyền)","soHuu":[],"trangThai":"thất truyền (thiếu chủ dược Linh Chúc quả)","blurb":"Tạo Hóa đan là đan dược luyện từ Linh Chúc quả, tu sĩ dưới Hóa Thần kỳ phục dụng một lần duy nhất trong đời sẽ đột phá bình cảnh rõ ràng. Phương thuốc luyện chế đã thất truyền từ sau thượng cổ vì thiếu Linh Chúc quả làm chủ dược.","detail":"Tạo Hóa đan được Tử Linh tiết lộ là đan dược lấy Linh Chúc quả làm chủ dược để luyện chế. Tu sĩ ở cảnh giới dưới Hóa Thần kỳ phục dụng sẽ được dược lực thôi thúc thần thức biến hóa lên một tầng cảnh giới khó tưởng tượng, từ đó đột phá bình cảnh; mỗi người cảm thụ khác nhau nhưng đều đạt hiệu quả. Mỗi đời chỉ có thể dùng một lần. Do Linh Chúc quả không còn, phương thuốc luyện chế đã thất truyền từ thời thượng cổ.","congNang":["Đột phá bình cảnh cho tu sĩ dưới Hóa Thần kỳ, một đời chỉ dùng được một lần @c0749","Dược lực thôi thúc thần thức biến hóa lên một tầng cảnh giới khó tưởng tượng, mỗi người cảm thụ khác nhau @c0749"],"tabs":{"tienTrinh":[{"chuong":"@c0749","loai":"xuat-hien","importance":"major","giaiDoan":"Tử Linh giảng giải công dụng cho Hàn Lập","text":"Tử Linh tiết lộ Tạo Hóa đan luyện từ Linh Chúc quả, tu sĩ dưới Hóa Thần kỳ phục dụng một lần duy nhất sẽ đột phá bình cảnh. Mai Ngưng kích động vì nếu có thì xác suất Kết Đan tăng mạnh.","anchor":"sau khi phục dụng, trong một đoạn thời gian thần thức của tu sĩ sẽ bị dược lực thôi thúc, biến hóa lên một tầng cảnh giới khó có thể tưởng tượng được"}]},"nguon":["@c0749"],"dacDiem":"Luyện từ Linh Chúc quả làm chủ dược; phương thuốc luyện chế đã thất truyền từ sau thượng cổ do thiếu chủ dược."},{"id":"co-thu-tong-gia","name":"Cổ thư Tống gia","cn":"","category":"khac","categoryLabel":"Cổ tịch","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Cổ thư Tống gia là ngọc giản bí truyền của Tống gia, chuyên ghi chép về linh đan và linh dược thời thượng cổ, chứa nhiều phương thuốc hữu dụng cho tu sĩ Nguyên Anh kỳ. Hàn Lập đổi lấy cổ thư này từ nữ tử họ Tống bằng một bình đan dược xanh biếc.","detail":"Ngọc giản bí mật truyền thừa của Tống gia, nội dung chuyên về linh đan và linh dược thời thượng cổ. Cổ thư chứa thông tin tỉ mỉ về Cửu Khúc Linh Sâm, phương thuốc liên quan đến Huyền Cốt lão ma, đồng thời xác nhận hạn chế của Linh Chúc quả. Một phần nội dung đã được sư điệt nữ tử họ Tống phục chế. Nhiều đan dược ghi chép bên trong tuy hữu dụng cho tu sĩ Nguyên Anh kỳ nhưng nguyên liệu đều thuộc loại khả ngộ bất khả cầu. Ban đầu nữ tử họ Tống định tặng ngọc giản này cho Hàn Lập làm thù lao, song Hàn Lập dùng một bình đan dược xanh biếc để đổi lấy @c0750.","nguonGoc":"Bí truyền Tống gia","dacDiem":"Chuyên về linh đan linh dược thượng cổ, một phần đã được phục chế; nguyên liệu các phương thuốc bên trong đều thuộc loại khả ngộ bất khả cầu.","congNang":["Chứa phương thuốc thượng cổ hữu dụng cho tu sĩ Nguyên Anh kỳ @c0750","Ghi chép thông tin tỉ mỉ về Cửu Khúc Linh Sâm","Chứa phương thuốc liên quan đến Huyền Cốt lão ma","Xác nhận hạn chế của Linh Chúc quả"],"chuSoHuu":[{"ten":"Nữ tử họ Tống","tuChuong":"@c0750","denChuong":"@c0750","cachCoDuoc":"truyền thừa gia tộc","trangThai":"da-doi"},{"ten":"Hàn Lập","tuChuong":"@c0750","denChuong":"","cachCoDuoc":"đổi bình đan dược","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0750","loai":"đổi chủ","importance":"major","giaiDoan":"Trao đổi","text":"Nữ tử họ Tống lấy ra ngọc giản cổ thư bí truyền Tống gia muốn tặng Hàn Lập làm thù lao, Hàn Lập đổi bình đan dược xanh biếc để lấy.","anchor":"một bản cổ thư chuyên giới thiệu với linh đan và linh dược thời thượng cổ"}]},"nguon":["@c0750"]},{"id":"binh-dan-duoc-xanh-biec","name":"Bình đan dược xanh biếc","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Nữ tử họ Tống"],"trangThai":"đã đổi chủ","blurb":"Bình đan dược tinh tiến tu vi do Hàn Lập đổi cho nữ tử họ Tống, hơn phân nửa dùng yêu đan cao cấp luyện thành.","detail":"Bình đan dược màu xanh biếc dùng để tinh tiến tu vi, phù hợp cảnh giới nữ tử họ Tống. Tử Linh xác nhận trong bình hơn phân nửa là linh đan dùng yêu đan cao cấp luyện thành. Hàn Lập dùng để đổi lấy cổ thư Tống gia.","congNang":["Tinh tiến tu vi"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0750","denChuong":"@c0750","cachCoDuoc":"sở hữu sẵn","trangThai":"da-doi"},{"ten":"Nữ tử họ Tống","tuChuong":"@c0750","denChuong":"","cachCoDuoc":"đổi cổ thư","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0750","loai":"đổi chủ","importance":"normal","giaiDoan":"Trao đổi","text":"Hàn Lập lấy ra đổi cho nữ tử họ Tống để lấy cổ thư bí truyền Tống gia.","anchor":"trong bình hơn phân nửa là linh đan dùng yêu đan cao cấp luyện thành"}]},"nguon":["@c0750"]},{"id":"loi-chau-thanh-diem","name":"Lôi châu (từ thanh diễm)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"đang sở hữu","blurb":"Bảy tám viên lôi châu được Hàn Lập luyện chế từ thanh diễm hỗn tạp Thanh Nguyên kiếm khí bằng Ích Tà Thần Lôi, phần thất bại tự tan mất.","detail":"Hàn Lập dùng Ích Tà Thần Lôi luyện chế thanh diễm (vốn bị hỗn tạp thêm Thanh Nguyên kiếm khí) thành bảy tám viên lôi châu. Phần luyện chế thất bại tự tan mất. Phương pháp này là cách diệt trừ thanh sắc đăng diễm tuyệt diệu.","congNang":["Lưu giữ uy lực thanh diễm kết hợp kiếm khí dưới dạng lôi châu"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0753","denChuong":"","cachCoDuoc":"Tự luyện chế từ thanh diễm bằng Ích Tà Thần Lôi","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0753","loai":"xuất hiện","importance":"normal","giaiDoan":"Được luyện chế trong bế quan","text":"Hàn Lập luyện chế thanh diễm hỗn tạp Thanh Nguyên kiếm khí bằng Ích Tà Thần Lôi, thu được bảy tám viên lôi châu.","anchor":"vận dụng Ích Tà Thần Lôi đem thanh diễm bị hỗn tạp thêm Thanh Nguyên kiếm khí cùng luyện chế được bảy, tám viên lôi châu"}]},"nguon":["@c0753"]},{"id":"thanh-vuong-tam","name":"Thanh Vương tằm","cn":"青王蚕","aliases":["Băng Tuyết tằm cực phẩm"],"category":"khac","categoryLabel":"Linh trùng","phamCap":"Cực phẩm Băng Tuyết tằm","soHuu":["Bạch phu nhân"],"trangThai":"dang-co","blurb":"Đôi nhộng tằm bán trong suốt, cực phẩm của loài Băng Tuyết tằm nằm cuối Kỳ trùng bảng, phát hiện ở tầng băng sâu trăm trượng dưới hàn băng động.","detail":"Đôi nhộng tằm bán trong suốt, tản bạch khí, khiến nhiệt độ đại sảnh giảm mạnh khi lấy ra. Thuộc cuối Kỳ trùng bảng, uy lực không lớn nhưng có thần thông đặc biệt. Chí Dương thượng nhân trao cho Bạch phu nhân để chiêu mộ bà tham gia đổ chiến.","congNang":["Thần thông đặc biệt (chưa rõ cụ thể)","Nằm cuối Kỳ trùng bảng"],"chuSoHuu":[{"ten":"Chí Dương thượng nhân","tuChuong":"@c0757","denChuong":"@c0757","cachCoDuoc":"Phát hiện ở hàn băng động","trangThai":"da-trao"},{"ten":"Bạch phu nhân","tuChuong":"@c0757","denChuong":"","cachCoDuoc":"Nhận từ Chí Dương thượng nhân để đổi lấy tham gia đổ chiến","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0757","loai":"đổi chủ","importance":"normal","giaiDoan":"Chí Dương trao cho Bạch phu nhân","text":"Chí Dương thượng nhân lấy đôi Thanh Vương tằm từ hộp ngọc trao cho Bạch phu nhân để chiêu mộ bà tham gia đổ chiến. Bạch phu nhân kiểm tra thần thức rồi hài lòng thu nhận.","anchor":"Nó không phải là loại bình thường mà chính là cực phẩm Thanh Vương tằm"}]},"nguon":["@c0757"]},{"id":"lan-phien-doc-giao-cap-tam","name":"Lân phiến Độc Giao cấp tám","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu yêu thú cấp tám","soHuu":["Ngụy Vô Nhai"],"trangThai":"dang-co","blurb":"Vảy sừng từ yêu thú Độc Giao cấp tám, cực hiếm, rất hữu dụng cho người tu độc công.","detail":"Vảy sừng màu đỏ tươi từ yêu thú Độc Giao cấp tám. Hàn Lập dùng trao đổi Canh Tinh với Ngụy Vô Nhai. Ngụy Vô Nhai tu độc công nên vui mừng thất thanh khi nhận được.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0757","denChuong":"@c0757","cachCoDuoc":"Từ Độc Giao","trangThai":"da-trao"},{"ten":"Ngụy Vô Nhai","tuChuong":"@c0757","denChuong":"","cachCoDuoc":"Đổi Canh Tinh với Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0757","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập trao cho Ngụy Vô Nhai","text":"Hàn Lập trao lân phiến Độc Giao cấp tám cho Ngụy Vô Nhai để đổi lấy Canh Tinh. Ngụy Vô Nhai tu độc công nên vui mừng thất thanh.","anchor":"Lân phiến của Độc Giao cấp tám?!"}]},"nguon":["@c0757"]},{"id":"xac-quy-yeu-cap-tam","name":"Xác quy yêu cấp tám","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu yêu thú cấp tám","soHuu":["Chí Dương thượng nhân"],"trangThai":"dang-co","blurb":"Xác rùa yêu thú cấp tám, có thể dùng luyện chế chiến giáp hoặc thuẫn bài.","detail":"Xác rùa màu đen từ yêu thú cấp tám. Hàn Lập dùng trao đổi Canh Tinh với Chí Dương thượng nhân. Chí Dương đánh giá có thể luyện chiến giáp hoặc thuẫn bài, bán tín bán nghi kiểm tra thật giả vì kinh ngạc tu sĩ Nguyên Anh Sơ Kỳ lại sở hữu tài liệu quý hiếm như vậy.","congNang":["Luyện chế chiến giáp","Luyện chế thuẫn bài"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0757","denChuong":"@c0757","cachCoDuoc":"Từ quy yêu cấp tám","trangThai":"da-trao"},{"ten":"Chí Dương thượng nhân","tuChuong":"@c0757","denChuong":"","cachCoDuoc":"Đổi Canh Tinh với Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0757","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập trao cho Chí Dương thượng nhân","text":"Hàn Lập trao xác quy yêu cấp tám cho Chí Dương thượng nhân để đổi Canh Tinh. Chí Dương đánh giá có thể luyện chiến giáp hoặc thuẫn bài.","anchor":"rất tuyệt khi dùng để luyện chế chiến giáp hoặc thuẫn bài"}]},"nguon":["@c0757"]},{"id":"huyen-thien-tien-dang-re","name":"Huyền Thiên Tiên Đằng (đoạn rễ)","cn":"玄天仙藤","aliases":["Tiên đằng thượng cổ"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu đỉnh cấp thượng cổ","soHuu":["Hàn Lập"],"trangThai":"Chết héo, Hàn Lập dự tính dùng lục dịch tiểu bình thử cứu sống","blurb":"Đoạn rễ Huyền Thiên Tiên Đằng là một phần tư rễ cây đằng mạn thượng cổ có nguồn gốc từ thời hỗn độn khai thiên lập địa, loại tiên đằng khai hoa kết quả có thần thông nghịch thiên. Cây tiên đằng chết héo trong động quật, chính ma lưỡng đạo đều bất lực cứu sống, cuối cùng phải chia nhỏ thành mấy chục đoạn phân chia; Chí Dương thượng nhân dùng một đoạn rễ này đổi quy xác với Hàn Lập.","detail":"Huyền Thiên Tiên Đằng là loại đằng mạn xa xưa từ thời hỗn độn, chỉ một số ít loại mới đủ tư cách mang hai chữ \"huyền thiên\". Cây tiên đằng chết héo trong động quật được cả chính đạo và ma đạo coi là chí bảo, hai bên từng đánh nhau long trời lở đất để tranh đoạt, rồi cùng cố cứu sống bằng mọi cách — kỳ công bí thuật, linh thủy linh dịch, thậm chí thuần dịch thánh thụ Lạc Vân Tông — nhưng đều thất bại. Cuối cùng di hài tiên đằng được chia thành mấy chục đoạn phân chia đồng đều cho các bên. Chí Dương thượng nhân được tu sĩ hiến dâng một đoạn rễ chiếm một phần tư tổng phần rễ, sau đó lấy ra đổi quy xác với Hàn Lập. Đoạn rễ này thuộc Mộc thuộc tính, có thể dùng để dưỡng dục Mộc linh khí hoặc luyện chế pháp bảo Mộc thuộc tính.","phanLoaiPhu":"Linh căn thượng cổ / rễ cây","hinhDang":"Đoạn rễ cây tiên đằng khô héo","nguonGoc":"Loại đằng mạn thượng cổ từ thời hỗn độn khai thiên lập địa, chết héo trong động quật rồi bị chính ma lưỡng đạo chia nhỏ","dacDiem":"Mộc thuộc tính, nguồn gốc thượng cổ từ thời hỗn độn khai thiên lập địa; nếu còn sống, khai hoa kết quả có thần thông nghịch thiên.","congNang":["Dưỡng dục Mộc linh khí @c0758","Luyện chế pháp bảo Mộc thuộc tính @c0758"],"chuSoHuu":[{"ten":"Chí Dương thượng nhân","tuChuong":"@c0758","denChuong":"@c0758","cachCoDuoc":"Được tu sĩ hiến dâng","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0758","denChuong":"","cachCoDuoc":"Được Chí Dương thượng nhân tặng để đổi quy xác","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0758","loai":"xuat-hien","importance":"major","giaiDoan":"Chí Dương thượng nhân tặng cho Hàn Lập","text":"Chí Dương thượng nhân đưa ra một phần tư rễ cây Huyền Thiên Tiên Đằng thượng cổ cho Hàn Lập để đổi quy xác. Hàn Lập nảy ý định dùng lục dịch tiểu bình thử cứu sống tiên đằng.","anchor":"Chỉ có một số ít ỏi loại đằng mạn rất xa xưa mới có tư cách thêm hai chữ huyền thiên ở phía trước"}]},"capNhatToi":"@c0758","nguon":["@c0758"]},{"id":"linh-phu-but-mau-lam","name":"Linh phù bút màu lam","category":"linh-khi","categoryLabel":"Linh khí","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Cây bút dài khoảng sáu bảy tấc, khéo léo tinh xảo, dùng để vẽ phù văn lên da linh thú khi luyện chế Hàng Linh Phù.","detail":"Dụng cụ chế phù chuyên dụng. Hàn Lập chấm bút vào các loại linh dịch nhiều màu rồi vẽ phù văn lên tấm da linh thú. Bút phối hợp cùng Minh Thanh Linh Nhãn trong quá trình chế phù.","congNang":["Viết/vẽ phù văn lên da linh thú khi luyện chế linh phù"],"phanLoaiPhu":"dụng cụ chế phù","hinhDang":"Dài khoảng sáu bảy tấc, khéo léo tinh xảo, màu lam","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0760","denChuong":"","cachCoDuoc":"sở hữu sẵn","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0760","loai":"dùng","importance":"normal","giaiDoan":"Dùng luyện Hàng Linh Phù","text":"Hàn Lập dùng linh phù bút màu lam vẽ phù văn màu vàng lên da linh thú chứa giao hồn khi luyện Hàng Linh Phù lần đầu.","anchor":"một cây linh phù bút màu lam, dài khoảng sáu, bảy tấc, khéo léo tinh xảo"}]},"nguon":["@c0760"]},{"id":"quy-la-phien","name":"Quỷ La Phiên","cn":"鬼罗幡","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Trấn tông chi bảo","soHuu":["Âm La Tông","Hắc bào thanh niên"],"trangThai":"hu-ton","blurb":"Quỷ La Phiên là trấn tông chi bảo của Âm La Tông, một trong mười đại Ma Tông ở Đại Tấn, đã bị chính đạo phá hủy. Việc phục hồi pháp bảo này đòi hỏi đại lượng sinh hồn, trở thành nguyên nhân chính khiến Âm La Tông tham gia liên minh đánh Thiên Nam để thu thập sinh hồn từ chiến trường.","detail":"Quỷ La Phiên là bảo vật trấn tông của Âm La Tông, một trong mười đại Ma Tông tại Đại Tấn. Pháp bảo này đã bị chính đạo Đại Tấn phá hủy, và việc chữa trị phục hồi cần tiêu hao đại lượng sinh hồn. Do thu thập sinh hồn ở Đại Tấn sẽ bị chính đạo cản trở, Âm La Tông buộc phải tham gia liên minh với Mộ Lan tộc tấn công Thiên Nam để lấy sinh hồn từ chiến trường (@c0762). Trong chiến đấu, hắc bào thanh niên sử dụng Quỷ La Phiên mở rộng tấn công Hàn Lập; chủ ma đầu trên phiên ngưu giác hóa ác quỷ cao hai trượng, miễn cưỡng chống được Thần Lôi (@c0787). Pháp bảo sở hữu nhiều ma đầu là âm quỷ chi thân vô hình, khiến đao kiếm thông thường vô hiệu; đồng thời có thể phun bích lân quỷ hỏa để tấn công. Chủ nhân còn có thể hợp nhất với phiên, hóa âm vụ để thoát thân.","congNang":["Trấn tông chi bảo của Âm La Tông, công năng cụ thể ngoài chiến đấu chưa rõ (@c0762)","Phun bích lân quỷ hỏa tấn công đối thủ","Ma đầu trên phiên là âm quỷ chi thân vô hình, đao kiếm thông thường không có tác dụng","Chủ ma đầu ngưu giác hóa thành ác quỷ cao hai trượng, có thể chống đỡ Thần Lôi (@c0787)","Chủ nhân có thể hợp nhất với phiên, hóa thành âm vụ để thoát thân"],"chuSoHuu":[{"ten":"Âm La Tông","tuChuong":"@c0762","denChuong":"","cachCoDuoc":"Bảo vật truyền thừa tông môn","trangThai":"bi-pha-huy-can-chua-tri"},{"ten":"Hắc bào thanh niên","tuChuong":"@c0787","denChuong":"","cachCoDuoc":"Pháp bảo Âm La Tông","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0762","loai":"xuat-hien","importance":"major","giaiDoan":"Hội nghị Mộ Lan – Âm La Tông","text":"Phòng tông chủ tiết lộ trấn tông chi bảo Quỷ La Phiên bị chính đạo phá hủy, cần đại lượng sinh hồn chữa trị, đây là lý do Âm La Tông tham gia đại chiến Thiên Nam.","anchor":"trấn tông chi bảo Quỷ La Phiên của Âm La Tông chúng ta bị đám gia hỏa chính đạo phá hủy, cần đại lượng sinh hồn đến chữa trị"},{"chuong":"@c0787","loai":"dùng","importance":"major","giaiDoan":"Toàn bộ ma đầu bị Đề Hồn Thú nuốt sạch","text":"Hắc bào thanh niên thúc Quỷ La phiên mở rộng tấn công Hàn Lập, chủ ma đầu miễn cưỡng chống được Ích Tà Thần Lôi. Tuy nhiên Đề Hồn Thú phun hoàng hà nuốt sạch toàn bộ ma đầu kể cả chủ ma đầu ngưu giác. Thanh niên hợp nhất với phiên hóa âm vụ thoát thân nhưng thất bại, phiên mất toàn bộ ma đầu bên trong.","anchor":"Quỷ la phiên này được xưng là trấn tông chi bảo của Âm La Tông, thật đúng không phải là chuyện thổi phồng"}]},"nguon":["@c0762","@c0787"],"uyLuc":"Chủ ma đầu ngưu giác hóa ác quỷ hai trượng, miễn cưỡng chống được Thần Lôi cấp uy lực (@c0787).","dacDiem":"Pháp bảo mang hình phiên (cờ), mang nhiều ma đầu âm quỷ vô hình; đã bị chính đạo phá hủy và cần đại lượng sinh hồn để phục hồi."},{"id":"thuong-co-ngoc-phu","name":"Thượng cổ Ngọc phù","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng cổ bảo vật","soHuu":["Loan Minh Tông"],"trangThai":"dang-co","blurb":"Bảo vật thượng cổ cất giấu lâu năm của Loan Minh Tông, thần thông to lớn nhưng dùng xong có thể thành phế.","detail":"Loan Minh Tông lấy ra bảo vật cất giấu bấy lâu để dùng trong đại chiến Thiên Nam, uy lực tuyệt đối khiến pháp sĩ Mộ Lan mở rộng nhãn giới. Tuy nhiên sau chiến đấu có khả năng trở thành phế phẩm.","congNang":["Thần thông to lớn, uy lực cực mạnh khiến đối phương kinh hãi"],"tabs":{"tienTrinh":[{"chuong":"@c0763","loai":"xuat-hien","importance":"normal","giaiDoan":"Được lấy ra chuẩn bị đại chiến","text":"Loan Minh Tông lấy ra thượng cổ Ngọc phù cất giấu lâu năm để chuẩn bị đại chiến, uy lực tuyệt đối nhưng dùng xong có thể thành phế.","anchor":"thượng cổ Ngọc phù cất dấu bấy lâu, thần thông to lớn tuyệt đối làm cho Mộ Lan pháp sĩ mở rộng nhãn giới"}]},"nguon":["@c0763"]},{"id":"thuong-co-ky-bao-chanh-dao-minh","name":"Thượng cổ kỳ bảo (Chánh Đạo Minh)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng cổ bảo vật","soHuu":["Chánh Đạo Minh"],"trangThai":"dang-co","blurb":"Mười mấy loại thượng cổ kỳ bảo uy lực lớn, được Chánh Đạo Minh lấy ra từ tổ sư đường các tông phái.","detail":"Các tông phái Chánh Đạo Minh mở tổ sư đường, đem mười mấy loại thượng cổ kỳ bảo có uy lực lớn lấy ra chuẩn bị cho đại chiến Thiên Nam.","tabs":{"tienTrinh":[{"chuong":"@c0763","loai":"xuat-hien","importance":"normal","giaiDoan":"Được lấy ra từ tổ sư đường","text":"Chánh Đạo Minh mở tổ sư đường các tông phái, lấy ra mười mấy loại thượng cổ kỳ bảo uy lực lớn chuẩn bị đại chiến.","anchor":"đều do các tông phái phân biệt mở ra tổ sư đường, đem mười mấy loại thượng cổ kỳ bảo có uy lực lớn lấy ra"}]},"nguon":["@c0763"]},{"id":"tran-tong-tam-thu","name":"Trấn tông tam thú","category":"khac","categoryLabel":"Linh thú trấn tông","soHuu":["Ngự Linh Tông"],"trangThai":"dang-co","blurb":"Ba linh thú trấn tông của Ngự Linh Tông, được mang theo tham gia đại chiến Thiên Nam.","detail":"Ngự Linh Tông đem trấn tông tam thú mang đến chiến trường, là một trong các sát chiêu của Ma Đạo Lục Tông trong đại chiến với pháp sĩ Mộ Lan.","tabs":{"tienTrinh":[{"chuong":"@c0763","loai":"xuat-hien","importance":"normal","giaiDoan":"Được mang ra chiến trường","text":"Ngự Linh Tông đem trấn tông tam thú mang đến chuẩn bị đại chiến.","anchor":"Ngự Linh Tông đem trấn tông tam thú mang đến"}]},"nguon":["@c0763"]},{"id":"pha-cam-chau","name":"Phá Cấm Châu","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Cấp thấp","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí cấp thấp có công năng bài trừ cấm chế, được Chí Dương thượng nhân đề cập để đối phó cấm chế pháp sĩ Mộ Lan.","detail":"Pháp khí bài trừ cấm chế, bị Long Hàm hoài nghi vì phẩm cấp thấp chỉ hữu dụng với cấm chế cấp thấp. Chí Dương thượng nhân tỏ ra tự tin khi nhắc đến, gợi ý có điều đặc biệt hơn bề ngoài.","congNang":["Bài trừ cấm chế"],"tabs":{"tienTrinh":[{"chuong":"@c0763","loai":"nhac-toi","importance":"normal","giaiDoan":"Được đề cập trong cuộc họp","text":"Chí Dương thượng nhân nhắc đến Phá Cấm Châu để đối phó cấm chế của pháp sĩ Mộ Lan, Long Hàm hoài nghi vì là pháp khí cấp thấp.","anchor":"Phá Cấm Châu! Là loại pháp khí bài trừ cấm chế"}]},"nguon":["@c0763"]},{"id":"bi-che-dan-duoc-thien-sat-tong","name":"Bí chế đan dược Thiên Sát Tông","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đan dược bí chế của Thiên Sát Tông, uống vào kích thích chân nguyên khôi phục hơn phân nửa pháp lực và tạm tăng tu vi, nhưng sau đó tổn thương nguyên khí.","detail":"Đan dược màu lửa đỏ cỡ hạt hạnh nhân, do Hợp Hoan lão ma cung cấp cho liên quân tu sĩ trước đại chiến biên giới. Tác dụng kích thích chân nguyên trong cơ thể, giúp pháp lực tiêu hao gần hết lập tức khôi phục hơn phân nửa, đồng thời tạm thời tăng tu vi. Đại giá: sau khi dược lực hết sẽ tổn thương nguyên khí. Mỗi tu sĩ tham chiến được phát một viên.","congNang":["Kích thích chân nguyên, khôi phục hơn phân nửa pháp lực đã tiêu hao","Tạm thời tăng tu vi"],"dacDiem":"Sau khi dược lực hết sẽ tổn thương nguyên khí","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0764","denChuong":"","cachCoDuoc":"Được Chí Dương thượng nhân phái người phát trước đại chiến","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0764","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát cho liên quân trước đại chiến biên giới","text":"Hợp Hoan lão ma tiết lộ Thiên Sát Tông có bí chế đan dược kích thích chân nguyên, khôi phục hơn phân nửa pháp lực, tạm tăng tu vi nhưng tổn thương nguyên khí. Mỗi tu sĩ tham chiến được phát một viên.","anchor":"dùng có thể kích thích chân nguyên trong cơ thể, làm cho tiêu hao không còn pháp lực lập tức khôi phục hơn phân nửa"}]},"nguon":["@c0764"]},{"id":"hai-co-quan-tai-den-trang","name":"Hai cỗ quan tài đen trắng","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hợp Hoan Tông"],"trangThai":"dang-co","blurb":"Hai cỗ quan tài một đen một trắng dán đầy phù chú, bí bảo của Hợp Hoan Tông, có cấm chế cực kỳ lợi hại mà thần thức không xuyên thấu.","detail":"Mười sáu đệ tử Hợp Hoan Tông mặc trang phục hồng lục nâng hai cỗ quan tài này vào chiến trường đại chiến biên giới. Bề mặt dán đầy phù chú, có cấm chế cực kỳ lợi hại, thần thức Hàn Lập không xuyên thấu. Công năng chưa hé lộ.","dacDiem":"Có cấm chế cực kỳ lợi hại, thần thức không thể xuyên thấu","chuSoHuu":[{"ten":"Hợp Hoan Tông","tuChuong":"@c0764","denChuong":"","cachCoDuoc":"Bí bảo tông môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0764","loai":"xuất hiện","importance":"normal","giaiDoan":"Triển khai vào đại chiến biên giới","text":"Mười sáu đệ tử Hợp Hoan Tông nâng hai cỗ quan tài đen trắng dán đầy phù chú ra chiến trường. Thần thức Hàn Lập không xuyên thấu cấm chế.","anchor":"hai chiếc quan tài dường như có cấm chế cực kỳ lợi hại, căn bản không cách nào xuyên thấu"}]},"nguon":["@c0764"]},{"id":"dong-la-khong-lo","name":"Đồng la khổng lồ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Đồng la thật lớn đường kính khoảng mười trượng, đặt trên đài cao sáu bảy trượng, mặt ngoài kim quang chói mắt với phù văn trắng di động. Bí bảo phe chánh đạo tông môn.","detail":"Đặt trên đài cao sáu bảy trượng bên phía chánh đạo, đường kính khoảng mười trượng, mặt ngoài phát kim quang chói mắt, thỉnh thoảng có phù văn trắng di động trên bề mặt. Bên cạnh có cự hán lưng trần ngồi xếp bằng canh giữ. Công năng chưa hé lộ.","dacDiem":"Kim quang chói mắt, phù văn trắng di động, đường kính khoảng mười trượng","tabs":{"tienTrinh":[{"chuong":"@c0764","loai":"xuất hiện","importance":"normal","giaiDoan":"Triển khai trước đại chiến biên giới","text":"Đồng la khổng lồ đặt trên đài cao, kim quang chói mắt với phù văn trắng di động, có cự hán lưng trần canh giữ.","anchor":"trên đài có một đồng la thật lớn, đường kính khoảng mười trượng"}]},"nguon":["@c0764"]},{"id":"that-tam-dan","name":"Thất Tâm đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":[],"trangThai":"Chưa sử dụng (bỏ lỡ cơ hội)","blurb":"Đan dược phe Mộ Lan dự định dùng cho tù binh trước khi thả nhằm cài gian tế, nhưng không kịp sử dụng.","detail":"Ải Tử tiếc nuối vì không cho tù binh uống Thất Tâm đan trước khi thả. Ngụ ý loại đan dược này có thể khống chế hoặc mê hoặc người uống, dùng để cài gian tế vào hàng ngũ đối phương. Phe Thiên Nam kiểm tra kỹ tù binh nên không bị mắc thủ đoạn này.","congNang":["Khống chế/mê hoặc người uống, dùng cài gian tế"],"tabs":{"tienTrinh":[{"chuong":"@c0765","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Ải Tử tiếc nuối vì bỏ lỡ","text":"Ải Tử tiếc nuối vì không dùng Thất Tâm đan cho tù binh trước khi thả, nếu không sẽ qua mắt được phe Thiên Nam.","anchor":"May mắn lúc đầu không khiến cho đám tu sĩ kia dùng Thất Tâm đan, nếu không thì khó mà qua được cửa này"}]},"nguon":["@c0765"]},{"id":"cam-che-chau","name":"Cấm chế châu","loai":"phap-bao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Châu cấm chế tiêu hao dùng một lần, Hàn Lập ném vào vách quang tráo xanh, tiếp xúc thì hóa tối đen bạo liệt suýt phá vỡ vách tráo nhưng bị huyết vụ vô hiệu hóa.","detail":"Lấy từ Túi Trữ Vật, ném vào vách quang tráo màu xanh. Châu tiếp xúc thì trong nháy mắt hóa thành tối đen như mực bạo liệt, suýt phá vỡ vách tráo nhưng huyết vụ bao trùm toàn bộ quang tráo trước khi phá xong, khiến nỗ lực vô hiệu.","congNang":["Phá vỡ cấm chế, quang tráo"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0766","denChuong":"","cachCoDuoc":"Có sẵn trong Túi Trữ Vật","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0766","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng tại chiến trường biên giới","text":"Hàn Lập ném Cấm chế châu vào vách quang tráo, châu hóa tối đen bạo liệt suýt phá vỡ nhưng huyết vụ Huyết La Quang Tráo bao trùm vô hiệu hóa.","anchor":"Cấm chế châu sau khi tiếp xúc với quang tráo màu xanh thì trong nháy mắt hóa thành tối đen như mực bạo liệt ra"}]},"nguon":["@c0766"]},{"id":"ma-linh-dan","name":"Ma linh đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Phòng tông chủ"],"trangThai":"da-dung","blurb":"Đan dược cho huyết thi dùng trước khi tự bạo, phục vụ thi triển Huyết La Quang Tráo.","detail":"Một trong các điều kiện cần thiết để thi triển Huyết La Quang Tráo. Huyết thi phải dùng ma linh đan trước khi chủ nhân dùng phân thức khống chế để tự bạo.","congNang":["Chuẩn bị cho huyết thi tự bạo thi triển Huyết La Quang Tráo"],"tabs":{"tienTrinh":[{"chuong":"@c0766","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng cho mười huyết thi trước khi thi triển bí thuật","text":"Mười huyết thi dùng ma linh đan trước khi Phòng tông chủ dùng phân thức khống chế để tự bạo thi triển Huyết La Quang Tráo.","anchor":"phải cho huyết thi dùng ma linh đan, sau đó Bổn tông chủ dùng phân thức khống chế"}]},"nguon":["@c0766"]},{"id":"co-den-giao-long-ky","name":"Cờ đen hình tam giác (giao long kỳ)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo viễn trình","soHuu":["Thiên Nam tu sĩ liên minh"],"trangThai":"dang-co","blurb":"Cờ đen cao năm sáu trượng, thêu hình giao long đen, hai tu sĩ cuồng phất triệu ra giao long đen phun thanh hắc yêu phong hóa thành lốc xoáy mịt mờ.","detail":"Dị bảo viễn trình công kích của phe tu sĩ Thiên Nam. Cờ đen cao năm sáu trượng, nửa trên ô quang lập lòe, thêu hình giao long đen. Hai tu sĩ cuồng phất, triệu ra giao long đen phun thanh hắc yêu phong hóa thành lốc xoáy mịt mờ tấn công đối phương diện rộng.","congNang":["Triệu giao long phun hắc phong diện rộng"],"tabs":{"tienTrinh":[{"chuong":"@c0767","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng trong đợt công kích đầu tiên đại chiến biên giới","text":"Hai tu sĩ cuồng phất cờ đen, triệu ra giao long đen phun hắc phong tấn công phe pháp sĩ.","anchor":"một con giao long màu đen hiện ra từ nét mặt như có như không biến hóa ra"}]},"nguon":["@c0767"]},{"id":"co-kinh-hoa-hong","name":"Cổ kính hỏa hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo viễn trình","soHuu":["Thiên Nam tu sĩ liên minh"],"trangThai":"dang-co","blurb":"Chín đồng phiến tụ lại quay tròn thành cổ kính hỏa hồng vài thước, mặt kính phun ra vô số Hỏa Điểu to cỡ nắm tay miệng phun hỏa diễm.","detail":"Dị bảo viễn trình. Chín hồng y thiếu nữ bưng mâm đỏ xếp trận thế, chín đồng phiến bay ra tụ lại quay tròn thành cổ kính hỏa hồng vài thước. Mặt kính phun ra vô số Hỏa Điểu to cỡ nắm tay người, miệng phun hỏa diễm công kích diện rộng.","congNang":["Phun vô số Hỏa Điểu miệng phun hỏa diễm công kích diện rộng"],"tabs":{"tienTrinh":[{"chuong":"@c0767","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng trong đợt công kích đầu tiên đại chiến biên giới","text":"Chín hồng y thiếu nữ bưng mâm đỏ xếp trận, chín đồng phiến tụ thành cổ kính phun Hỏa Điểu tấn công pháp sĩ.","anchor":"từ trung tâm kính phun ra vô số Hỏa Điểu to cỡ nắm tay người"}]},"nguon":["@c0767"]},{"id":"ho-lo-han-khi","name":"Hồ lô (hàn khí)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo viễn trình","soHuu":["Thiên Nam tu sĩ liên minh"],"trangThai":"dang-co","blurb":"Ba cẩm y lão giả đứng hình tam giác tế khởi hồ lô phun hàn khí trắng băng hàn, tạo mưa tuyết mưa đá biến khu vực trước mặt thành trời tuyết.","detail":"Dị bảo viễn trình. Ba cẩm y lão giả đứng hình tam giác, tế khởi hồ lô sau lưng phun ra hàn khí màu trắng băng hàn lạnh thấu xương, tạo vùng mưa tuyết mưa đá biến khu vực trước mặt thành trời tuyết công kích đối phương diện rộng.","congNang":["Phun hàn khí tạo mưa tuyết mưa đá diện rộng"],"tabs":{"tienTrinh":[{"chuong":"@c0767","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng trong đợt công kích đầu tiên đại chiến biên giới","text":"Ba cẩm y lão giả tế khởi hồ lô phun hàn khí tạo mưa tuyết mưa đá tấn công pháp sĩ.","anchor":"một cỗ hàn khí màu trắng băng hàn lạnh thấu xương thổi ra"}]},"nguon":["@c0767"]},{"id":"dan-hoan-trieu-hoi-yeu-thu","name":"Đạn hoàn triệu hồi yêu thú","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Mộ Lan pháp sĩ"],"trangThai":"dang-co","blurb":"Đạn hoàn nhiều màu sắc của cao giai pháp sĩ Mộ Lan, ném xuống đất niệm chú biến hóa ra các loại yêu thú chiến đấu, bị đánh tan thì có thể tung đạn hoàn mới tái tạo.","detail":"Đạn hoàn nhiều màu sắc của cao giai pháp sĩ Mộ Lan. Ném xuống đất, niệm chú biến hóa ra các loại yêu thú (thổ mãng dài hơn mười trượng, hỏa lang cao bảy tám trượng, thanh quái điểu, lam sắc yêu quy). Yêu thú do pháp thuật sinh ra yếu hơn cự thú thật nhưng có thể tung đạn hoàn mới tái tạo không ngừng, gây áp lực tiêu hao liên tục lên đối phương.","congNang":["Triệu hồi yêu thú chiến đấu (thổ mãng, hỏa lang, quái điểu, yêu quy)","Có thể tái sử dụng bằng đạn hoàn mới"],"tabs":{"tienTrinh":[{"chuong":"@c0767","loai":"dùng","importance":"normal","giaiDoan":"Pháp sĩ phản công trong đại chiến biên giới","text":"Mười mấy cao giai pháp sĩ ném đạn hoàn xuống đất niệm chú biến hóa ra nhiều loại yêu thú buộc tu sĩ phân tán hỏa lực.","anchor":"Số đạn hoàn này rơi thẳng xuống mặt đất rồi thấy đâu nữa"}]},"nguon":["@c0767"]},{"id":"bay-dao-bach-ngoc-phu","name":"Bảy đạo bạch ngọc phù","cn":"","category":"phap-bao","categoryLabel":"Thượng cổ phù","phamCap":"Thượng cổ","soHuu":["Bảy lão giả Loan Minh Tông"],"trangThai":"da-dung","blurb":"Bảy đạo bạch ngọc phù là thượng cổ ngọc phù do bảy lão giả Loan Minh Tông đồng loạt tế ra trong trận chiến, hóa thành bảy mặt trời bạch sắc rồi bạo liệt biến thành bảy điện võng khổng lồ trùm xuống đại quân pháp sĩ Mộ Lan. Ngọc phù thuộc loại dùng một lần, toái liệt sau khi kích hoạt, uy lực kinh thiên động địa.","detail":"Bảy đạo bạch ngọc phù được bảy lão giả Loan Minh Tông cùng lúc tế xuất trong trận đại chiến. Khi kích hoạt, ngọc phù hóa bạch hồng hiện nguyên hình, sau đó toái liệt thành bảy điện cầu bạch sắc chói mắt, tiếp tục biến lớn thành bảy mặt trời đường kính hơn mười trượng. Cuối cùng bảy mặt trời bạo liệt hóa thành bảy điện võng khổng lồ trùm xuống đại quân pháp sĩ Mộ Lan. Đây là pháp bảo dùng một lần, phù toái liệt hoàn toàn sau khi giải phóng toàn bộ uy năng. Uy lực của bảy đạo ngọc phù khiến chỉ huy pháp sĩ đối phương hoảng sợ.","congNang":["Hóa bạch hồng hiện nguyên hình, toái liệt thành bảy điện cầu bạch sắc chói mắt, biến lớn thành bảy mặt trời đường kính hơn mười trượng, sau đó bạo liệt hóa bảy điện võng khổng lồ trùm diện rộng xuống đại quân đối phương @c0768"],"chuSoHuu":[{"ten":"Bảy lão giả Loan Minh Tông","tuChuong":"@c0768","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0768","loai":"dùng","importance":"major","giaiDoan":"Trận chiến biên giới Thiên Nam","text":"Bảy lão giả Loan Minh Tông tế ra bảy đạo bạch ngọc phù, hóa bảy mặt trời bạch sắc bạo liệt thành bảy điện võng khổng lồ trùm xuống đại quân pháp sĩ, khiến chỉ huy hoảng sợ.","anchor":"Sau một trận lúc co lúc trướng rồi phát ra một tiếng sét đánh kinh thiên động địa từ trong ngọc phù truyền ra","phamCap":"Thượng cổ"}]},"nguon":["@c0768"],"uyLuc":"Uy lực kinh thiên động địa, bảy mặt trời bạch sắc đường kính hơn mười trượng bạo liệt thành bảy điện võng khổng lồ trùm xuống đại quân pháp sĩ, khiến chỉ huy đối phương hoảng sợ.","dacDiem":"Thuộc loại ngọc phù dùng một lần, toái liệt sau khi kích hoạt; cần bảy lão giả đồng loạt tế xuất; quá trình kích hoạt trải qua nhiều giai đoạn biến hóa từ bạch hồng sang điện cầu, mặt trời rồi điện võng."},{"id":"loi-chau-thanh-sac","name":"Lôi châu thanh sắc","cn":"","aliases":["Lôi châu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đã sử dụng","blurb":"Lôi châu thanh sắc là viên lôi châu hỏa thuộc tính do Hàn Lập tự luyện chế bằng Tử La Thiên Hỏa cùng cấp thanh sắc đăng diễm. Uy lực vượt xa dự đoán, dễ dàng phá thủng huyết quang tráo — cấm chế đủ sức vây khốn nguyên anh tu sĩ bình thường — trong khi Tử La Thiên Hỏa đơn thuần không làm nổi.","detail":"Lôi châu thanh sắc là pháp bảo nhất dụng do Hàn Lập luyện chế, hình dáng tròn bóng loáng cỡ ngón tay cái. Nguyên liệu cốt lõi gồm Tử La Thiên Hỏa kết hợp với cấp thanh sắc đăng diễm, khiến viên lôi châu mang hỏa thuộc tính thật sự từ đăng diễm chứ không đơn thuần là lôi hỏa. Chính nhờ thuộc tính này mà nó tương khắc mạnh mẽ với huyết quang tráo. Khi kích phát, lôi châu tạo ra tiếng sấm ì ùng cùng quang mang kim thanh sắc cỡ đầu người. Lần đầu tiên sử dụng tại @c0769, Hàn Lập bắn viên lôi châu vào vách huyết quang tráo và uy lực vượt xa dự đoán, phá ra thông đạo trên vách cấm chế — điều mà Tử La Thiên Hỏa tự thân không thể làm được, dù huyết quang tráo là cấm chế đủ sức vây khốn nguyên anh tu sĩ bình thường.","congNang":["Bạo phá cấm chế huyết quang tráo, tạo thông đạo trên vách tráo @c0769"],"phanLoaiPhu":"Pháp bảo tiêu hao","nguonGoc":"Hàn Lập tự luyện chế bằng Tử La Thiên Hỏa cùng cấp thanh sắc đăng diễm","uyLuc":"Phá thủng huyết quang tráo — cấm chế đủ sức vây khốn nguyên anh tu sĩ bình thường — trong khi Tử La Thiên Hỏa đơn thuần không phá nổi.","dacDiem":"Hỏa thuộc tính thật sự có nguồn gốc từ đăng diễm, tương khắc huyết tráo; khi kích phát tạo tiếng sấm ì ùng cùng quang mang kim thanh sắc cỡ đầu người.","chuHienThoi":"Hàn Lập","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0769","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0769","loai":"dung","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Hàn Lập bắn viên lôi châu thanh sắc mới luyện vào vách huyết quang tráo, uy lực vượt dự đoán, tạo thông đạo trên vách tráo, Hàn Lập thoát ra ngoài trước khi nó thu nhỏ.","anchor":"Dùng Tử la thiên hỏa uy lực cùng cấp với thanh sắc đăng diễm luyện chế lôi châu, dĩ nhiên dễ dàng bài trừ cấm chế này"}]},"capNhatToi":"@c0769","nguon":["@c0769"]},{"id":"phap-bao-hinh-khoi-tu-phuong","name":"Pháp bảo hình khối tứ phương","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng sam lão giả"],"trangThai":"đang sử dụng","blurb":"Pháp bảo của Đại Thượng Sư Mộ Lan, hóa thành cự chuyên hơn mười trượng, hoàng quang chói mắt, gió rít ào ào, thanh thế cực kỳ kinh người.","detail":"Vừa rời tay hoàng quang đại phóng, trong nháy mắt hóa thành một khối cự chuyên hơn mười trượng, tiếng gió rít ào ào truyền ra, dùng đánh về phía Hàn Lập.","nguon":["@c0769"]},{"id":"tu-sac-tieu-ky-co-bao","name":"Tử sắc tiểu kỳ (Cổ Bảo)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo","soHuu":["Hoàng sam lão giả"],"trangThai":"hong","blurb":"Cổ Bảo của Hoàng sam lão giả, phóng ra hóa tử vân bảo vệ toàn thân nhưng bị Ngân Nguyệt và Kiềm Lam Băng Diễm phá hủy.","detail":"Lá cờ nhỏ màu tử phóng ra hóa thành tử vân hộ thể toàn thân, uy lực không nhỏ. Bị thanh sắc viên châu của Ngân Nguyệt phá vỡ, sau đó thâm lam hỏa diễm của Kiềm Lam Băng Diễm thiêu hủy nhục thân lão giả.","congNang":["Hóa tử vân hộ thể toàn thân"],"chuSoHuu":[{"ten":"Hoàng sam lão giả","tuChuong":"@c0770","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c0770","loai":"dung","importance":"normal","giaiDoan":"Thi triển trong trận chiến","text":"Hoàng sam lão giả phóng tử sắc tiểu kỳ hóa tử vân hộ thể. Bị Ngân Nguyệt bắn thanh sắc viên châu phá vỡ, nhục thân lão giả bị hủy.","anchor":"Cái Cổ Bảo này biến thành tử vân. Uy lực không nhỏ"}]},"nguon":["@c0770"]},{"id":"kim-vong","name":"Kim võng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp bảo hình lưới vàng của Hàn Lập, giương lên kèm tiếng sét để chụp Nguyên Anh nhưng bị ngân bát tự hủy rung động, Nguyên Anh thoát.","detail":"Hàn Lập giương kim võng chụp xuống Nguyên Anh Hoàng sam lão giả kèm theo tiếng sét. Nguyên Anh phun ngân sắc viên bát tự hủy bạo liệt làm rung kim võng, tạo cơ hội thoát đi.","congNang":["Chụp bắt Nguyên Anh"],"nguon":["@c0770"]},{"id":"hoa-linh-binh","name":"Hỏa Linh Bình","cn":"火灵瓶","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Phượng Băng"],"trangThai":"dang-co","blurb":"Bình nhỏ trong suốt màu lửa đỏ của Phượng phu nhân, tự bốc hồng quang liệt hỏa, phun lửa hóa thành cự xà đỏ sậm giao chiến, khiến Điền Chung Nguyên Anh Hậu Kỳ phải cẩn trọng.","detail":"Phượng phu nhân lấy ra trên chiến trường biên giới để đối phó bản thể Điền Chung. Bình tự bốc hồng quang liệt hỏa, phun lửa hóa hình cự xà đỏ sậm tấn công. Điền Chung nhận ra bảo vật, tỏ vẻ cẩn trọng.","congNang":["Phun liệt hỏa hóa hình cự xà tấn công"],"hinhDang":"Bình nhỏ trong suốt màu lửa đỏ","chuSoHuu":[{"ten":"Phượng Băng","tuChuong":"@c0771","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0771","loai":"dùng","importance":"normal","giaiDoan":"Giao chiến Điền Chung","text":"Phượng phu nhân dùng Hỏa Linh Bình phun liệt hỏa hóa cự xà đỏ sậm giao chiến bản thể Điền Chung, khiến hắn tỏ vẻ cẩn trọng.","anchor":"Hỏa linh bình! trên mặt Cẩm bào đại hán hiện ra vẻ cẩn trọng"}]},"capNhatToi":"@c0771","nguon":["@c0771"]},{"id":"ngu-sac-thai-luan","name":"Ngũ sắc thải luân","cn":"五色彩轮","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Điền Chung"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo của Điền Chung, phun từ miệng hóa thành mảnh sáng mờ trong suốt phóng tấn công đối phương.","detail":"Điền Chung phun ngũ sắc thải luân từ miệng tấn công Phượng phu nhân trong trận chiến biên giới.","congNang":["Tấn công tầm xa dạng luân xoay trong suốt","Vũ khí tấn công uy lực lớn @c0773"],"chuSoHuu":[{"ten":"Điền Chung","tuChuong":"@c0771","denChuong":"","cachCoDuoc":"","trangThai":"Đang sử dụng"}],"tabs":{"tienTrinh":[{"chuong":"@c0771","loai":"dùng","importance":"normal","giaiDoan":"Giao chiến Phượng phu nhân","text":"Điền Chung bản thể phun ngũ sắc thải luân trong suốt tấn công Phượng phu nhân.","anchor":"phun ra một kiện ngũ sắc thải luân trong suốt"},{"chuong":"@c0773","loai":"dùng","importance":"normal","giaiDoan":"Điền Chung dùng tấn công Phượng Băng","text":"Điền Chung huy động ngũ sắc thái luân điên cuồng tấn công Phượng Băng vài lần rồi bỏ qua chuyển hướng sang Hàn Lập.","anchor":"huy động ngũ sắc thái luân điên cuồng tấn công mỹ phụ phía đối diện vài lần"}]},"capNhatToi":"@c0771","nguon":["@c0771","@c0773"]},{"id":"co-dang-bang-dong-xanh","name":"Cổ đăng bằng đồng xanh","cn":"","aliases":["Cổ đăng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhạc thượng sư"],"trangThai":"dang-co","blurb":"Đèn cổ bằng đồng xanh, được Nhạc thượng sư lấy ra theo lệnh pháp sĩ khô gầy cuối chương 771, chưa rõ công năng cụ thể.","detail":"Nữ tử họ Nhạc lấy ra từ túi trữ vật theo lệnh pháp sĩ khô gầy, nắm trên tay chuẩn bị tham chiến. Công năng chưa được hé lộ.","hinhDang":"Đèn cổ bằng đồng xanh","chuSoHuu":[{"ten":"Nhạc thượng sư","tuChuong":"@c0771","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0771","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nhạc thượng sư lấy Cổ đăng bằng đồng xanh từ túi trữ vật theo lệnh pháp sĩ khô gầy, chuẩn bị tham chiến.","anchor":"trong túi trữ vật lấy ra một cái Cổ đăng bằng đồng xanh ra nắm ở trên tay"}]},"capNhatToi":"@c0771","nguon":["@c0771"]},{"id":"thai-chan-that-bao","name":"Thái Chân Thất Bảo","cn":"太真七宝","category":"phap-bao","categoryLabel":"Bộ cổ bảo","phamCap":"Cổ bảo","soHuu":["Hôi bào lão giả","Trường mi lão giả","Lão giả thân hình to lớn"],"trangThai":"dang-dung","laBo":true,"blurb":"Bộ bảy kiện cổ bảo do bảy lão giả Thiên Nam sử dụng, hợp lực thi triển Khốn ma đại trận. Được xem là đòn sát thủ cuối cùng của Thiên Nam trong trận chiến biên giới, từng dùng để vây khốn phân thân Thánh cầm.","detail":"Thái Chân Thất Bảo gồm bảy kiện: cổ kính trắng (phát ánh sáng bạc tạo bức tường phòng ngự), hồng xích, hoàng qua, lệnh bài, tiểu đỉnh, ngọc phiến và như ý. Bảy kiện do bảy lão giả Thiên Nam mỗi người nắm giữ một kiện, khi hợp lực tế xuất sẽ thi triển Khốn ma đại trận — tạo bảy lồng bảy sắc vây khốn đối thủ. Khô gầy lão giả (Chúc thần sư) nhận xét đây là đòn sát thủ cuối cùng của Thiên Nam. Trong trận chiến biên giới, bảy lão giả đã dùng bộ bảo vật này để vây khốn phân thân Thánh cầm.","congNang":["Bảy kiện hợp lực thi triển Khốn ma đại trận — tạo bảy lồng bảy sắc vây khốn đối thủ @c0772","Cổ kính trắng phát ánh sáng bạc tạo bức tường phòng ngự hỏa diễm"],"thanhVien":[{"ten":"Cổ kính trắng","moTa":"Phát ánh sáng bạc tạo bức tường phòng ngự"},{"ten":"Hồng xích","moTa":""},{"ten":"Hoàng qua","moTa":""},{"ten":"Lệnh bài","moTa":"Suýt bị tiêm chùy Thánh cầm đánh nát"},{"ten":"Tiểu đỉnh","moTa":""},{"ten":"Ngọc phiến","moTa":""},{"ten":"Như ý","moTa":""}],"chuSoHuu":[{"ten":"Hôi bào lão giả","tuChuong":"@c0772","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"},{"ten":"Trường mi lão giả","tuChuong":"@c0772","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"},{"ten":"Lão giả thân hình to lớn","tuChuong":"@c0772","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0772","loai":"dùng","importance":"major","giaiDoan":"Thi triển trên chiến trường biên giới","phamCap":"Cổ bảo","text":"Bảy lão giả Thiên Nam tế xuất bảy kiện cổ bảo, hợp lực thi triển Khốn ma đại trận vây khốn phân thân Thánh cầm. Tuy vây được nhưng ở thế hạ phong — băng võng bị thiêu, lệnh bài suýt bị đánh nát. Được nhận xét là đòn sát thủ cuối cùng của Thiên Nam.","anchor":"Vậy còn chần chừ gì nữa chứ hãy nhanh sử dụng 'thái chân thất bảo' tiêu diệt yêu cầm này ngay"}]},"capNhatToi":"@c0772","nguon":["@c0772"],"uyLuc":"Được nhận xét là đòn sát thủ cuối cùng của Thiên Nam, đủ sức vây khốn phân thân Thánh cầm trong trận chiến biên giới.","dacDiem":"Bộ bảo vật gồm bảy kiện riêng biệt (cổ kính trắng, hồng xích, hoàng qua, lệnh bài, tiểu đỉnh, ngọc phiến, như ý), mỗi kiện do một lão giả nắm giữ, cần bảy người hợp lực mới phát huy trọn vẹn uy năng."},{"id":"phe-linh-tuong-thu","name":"Phê Linh Tượng Thú","cn":"","category":"phap-bao","categoryLabel":"Bảo vật chiến tranh","phamCap":"Không rõ","soHuu":["Long Hàm"],"trangThai":"dang-dung","blurb":"Hơn mười con Thú Điểu Ô quang, được tu sĩ Thiên Nam kích hoạt bằng linh phù để tự động tấn công pháp sĩ Mộ Lan. Tu sĩ điều khiển ngồi bất động sau khi truyền linh phù.","detail":"Bảo vật chiến tranh dạng thú cơ giới hình chim, được Long Hàm ra lệnh thả ra trên chiến trường. Cần tu sĩ phóng linh phù vào để kích hoạt, sau đó tự động chiến đấu. Tu sĩ điều khiển bất động trong suốt quá trình.","congNang":["Tự động tấn công pháp sĩ đối phương sau khi kích hoạt bằng linh phù"],"chuSoHuu":[{"ten":"Long Hàm","tuChuong":"@c0772","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0772","loai":"dùng","importance":"normal","giaiDoan":"Thả ra trên chiến trường chống Mộ Lan","text":"Long Hàm ra lệnh thả hơn mười con Phê Linh Tượng Thú. Tu sĩ phóng linh phù kích hoạt, Thú Điểu Ô quang tự động tấn công pháp sĩ Mộ Lan.","anchor":"Thú Điểu Ô quang chợt chớp động, tiếp theo hai mắt bắn ra lam quang âm hàn"}]},"capNhatToi":"@c0772","nguon":["@c0772"]},{"id":"dong-giap-thi-am-la-tong","name":"Đồng giáp thi","cn":"铜甲尸","category":"phap-bao","categoryLabel":"Binh khí chiến tranh","phamCap":"Tương đương Trúc Cơ Kỳ (đại bộ phận)","soHuu":["Lục phu nhân"],"trangThai":"chua-dung","blurb":"Đội quân đồng giáp thi của Âm La tông, đại bộ phận tu vi chỉ tương đương Trúc Cơ Kỳ. Lục phu nhân chưa phóng ra, chờ thời cơ tu sĩ Thiên Nam tiêu hao pháp lực.","detail":"Binh khí chiến tranh đặc trưng của Âm La tông. Lục phu nhân tiết lộ đại bộ phận đồng giáp thi có tu vi pháp lực chỉ tương đương Trúc Cơ Kỳ, nên cần chờ thời cơ đối phương tiêu hao thêm mới phóng ra để đạt hiệu quả cao nhất.","congNang":["Đội quân tự chiến đấu do Âm La tông điều khiển"],"chuSoHuu":[{"ten":"Lục phu nhân","tuChuong":"@c0772","denChuong":"","cachCoDuoc":"Âm La tông sở hữu","trangThai":"chua-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0772","loai":"nhắc tới","importance":"normal","giaiDoan":"Được đề cập nhưng chưa sử dụng","text":"Chúc thần sư thúc giục Lục phu nhân phóng đồng giáp thi giáng đòn trí mạng. Lục phu nhân bình tĩnh từ chối, tiết lộ đại bộ phận tu vi chỉ tương đương Trúc Cơ Kỳ, cần chờ thời cơ.","anchor":"đại bộ phận đồng giáp thi của Bổn tông tu vi pháp lực chỉ tương đương với Trúc Cơ Kỳ"}]},"capNhatToi":"@c0772","nguon":["@c0772"]},{"id":"vien-chau-xanh","name":"Viên châu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Quái ảnh xanh biếc"],"trangThai":"Đang sử dụng","blurb":"Viên châu màu xanh to bằng cái bát do thanh ảnh phun ra, có khả năng hấp thu Kiền Lam Băng Diễm.","detail":"Thanh ảnh há miệng bắn ra viên châu màu xanh to bằng cái bát, hấp thu Kiền Lam Băng Diễm của Hàn Lập, buộc hắn phải dùng thần thức thúc dục mới kéo thoát ra.","congNang":["Hấp thu dị hỏa/băng diễm @c0773"],"tabs":{"tienTrinh":[{"chuong":"@c0773","loai":"dùng","importance":"normal","giaiDoan":"Thanh ảnh dùng hấp thu Kiền Lam Băng Diễm","text":"Thanh ảnh há miệng bắn ra viên châu xanh hấp thu Kiền Lam Băng Diễm của Hàn Lập.","anchor":"thanh ảnh lại há miệng bắn ra một viên châu màu xanh to bằng cái bát"}]},"capNhatToi":"@c0773","nguon":["@c0773"]},{"id":"ngan-chung","name":"Ngân Chung","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo của Hàn Lập, sử dụng nhưng không có tác dụng với thanh ảnh thuần mộc linh khí.","detail":"Được Hàn Lập sử dụng trong trận chiến nhưng không có tác dụng với thanh ảnh.","nguon":["@c0773"]},{"id":"dong-bai-xanh-luc","name":"Hai đồng bài xanh lục","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phi phát lão giả"],"trangThai":"dang-su-dung","blurb":"Một cặp đồng bài đầy ký hiệu màu xanh lục, dùng để phát quang mang xám vào trán Âm Dương Song Ma nhằm kiểm soát hành động của chúng.","detail":"Pháp khí chuyên dụng điều khiển Âm Dương Song Ma. Phi phát lão giả đánh pháp quyết vào đồng bài, phát ra quang mang xám nhập vào trán Song Ma. Sau khi kiểm soát thành công, Song Ma ngừng hành vi bản năng và tuân theo mệnh lệnh.","congNang":["Phát quang mang xám kiểm soát hành vi Âm Dương Song Ma"],"chuSoHuu":[{"ten":"Phi phát lão giả","tuChuong":"@c0774","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0774","loai":"dùng","importance":"normal","giaiDoan":"Điều khiển Song Ma","text":"Phi phát lão giả dùng hai đồng bài đánh pháp quyết, phát quang mang xám vào trán Song Ma để kiểm soát, ra lệnh tấn công Khổng Tước.","anchor":"xuất hiện ra hai khối đồng bài đầy ký hiệu màu xanh lục"}]},"nguon":["@c0774"]},{"id":"quan-tai-den-trang","name":"Hai quan tài gỗ đen-trắng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hợp Hoan Tông"],"trangThai":"bi-pha-huy","blurb":"Một cặp quan tài gỗ một đen một trắng dùng để phong ấn Âm Dương Song Ma, dán phù phong ấn, cần 32 đệ tử đọc chú giải ấn.","detail":"Hai quan tài bằng gỗ màu đen và trắng, dán phù phong ấn bên ngoài. Cần 16 nam đệ tử và 16 nữ đệ tử Hợp Hoan Tông ngồi vây quanh đọc chú quyết để giải phong ấn. Bị Âm Dương Song Ma phá nát khi thoát ra.","congNang":["Phong ấn Âm Dương Song Ma"],"chuSoHuu":[{"ten":"Hợp Hoan Tông","tuChuong":"@c0774","denChuong":"@c0774","cachCoDuoc":"Sở hữu sẵn","trangThai":"bi-pha-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0774","loai":"dùng","importance":"normal","giaiDoan":"Giải phong ấn và bị phá hủy","text":"32 đệ tử Hợp Hoan Tông giải phong ấn, Song Ma phá nát quan tài phóng ra.","anchor":"hai cái quan tài bằng gỗ màu đen và trắng cùng xuất hiện"}]},"nguon":["@c0774"]},{"id":"tieu-phien-den","name":"Tiểu phiên đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hắc bào nữ tử"],"trangThai":"dang-co","blurb":"Pháp bảo của Hắc bào nữ tử, dài hai tấc, đón gió biến lớn thành một trượng, hóa ô quang gọi mây đen che nửa mặt trời, tạo môi trường âm u cho đồng giáp thi.","detail":"Tiểu phiên tinh sảo dị thường, bề mặt hắc quang lấp loé. Khi phun ra, phóng lên không đón gió đại trướng thành một trượng rồi hóa ô quang bay đi. Mây đen kéo tới che nửa mặt trời, chiến trường trở nên âm u lạnh lẽo, tạo điều kiện tối ưu cho đồng giáp thi hoạt động.","congNang":["Triệu hồi mây đen che trời tạo môi trường âm u"],"hinhDang":"Tiểu phiên dài hai tấc, bề mặt hắc quang lấp loé, tinh sảo dị thường","chuSoHuu":[{"ten":"Hắc bào nữ tử","tuChuong":"@c0775","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"dùng","importance":"normal","giaiDoan":"Triệu hồi mây đen che trời cho đồng giáp thi","text":"Hắc bào nữ tử phun ra tiểu phiên đen, phóng lên không đón gió biến lớn thành một trượng, hóa ô quang gọi mây đen che nửa mặt trời tạo môi trường âm u cho hàng ngàn đồng giáp thi xuất hiện.","anchor":"cái tiểu phiên này chỉ dài có hai tấc, bề mặt hắc quang lấp loé"}]},"nguon":["@c0775"]},{"id":"cu-nhan-tu-quang","name":"Cự nhận tử quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hắc bào nữ tử"],"trangThai":"dang-co","blurb":"Pháp bảo của Hắc bào nữ tử, khoát tay hóa ra thanh cự nhận phát tử quang chém tới cự viên, bị lam quang thuẫn của Hàn Lập đánh lùi.","detail":"Khi Hắc bào nữ tử khoát tay, xuất hiện một đạo tử quang biến thành thanh cự nhận chém tới cự viên. Bị lam quang thuẫn của Hàn Lập chặn đứng, va chạm rồi cả hai bay ngược về.","congNang":["Tấn công bằng cự nhận phát tử quang"],"chuSoHuu":[{"ten":"Hắc bào nữ tử","tuChuong":"@c0775","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"dùng","importance":"normal","giaiDoan":"Tấn công cự viên của Hàn Lập","text":"Hắc bào nữ tử khoát tay hóa ra thanh cự nhận tử quang chém tới cự viên nhưng bị lam quang thuẫn của Hàn Lập chặn đứng.","anchor":"xuất hiện ra một đạo tử quang. Sau đó nó liền biến thành một thanh cự nhận"}]},"nguon":["@c0775"]},{"id":"bay-loai-co-bao-lien-hop","name":"Bảy loại cổ bảo liên hợp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thái Chân Thất tu sĩ"],"trangThai":"dang-co","blurb":"Bảy loại cổ bảo liên hợp của Thái Chân Thất tu sĩ, phát huy uy lực khi kết hợp nhưng bị cự điểu Hóa Thần Kỳ phá khốn.","detail":"Thái Chân Thất tu sĩ tung ra bảy loại cổ bảo liên hợp với nhau phát huy uy lực, nhưng vẫn bị cự điểu xanh Hóa Thần Kỳ dùng yêu hỏa ép tới đường cùng.","congNang":["Liên hợp bảy bảo thành trận phát huy uy lực"],"chuSoHuu":[{"ten":"Thái Chân Thất tu sĩ","tuChuong":"@c0775","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"dùng","importance":"normal","giaiDoan":"Giao chiến cự điểu Hóa Thần Kỳ","text":"Thái Chân Thất tu sĩ tung ra bảy loại cổ bảo liên hợp phát huy uy lực nhưng bị cự điểu xanh phá khốn ma trận.","anchor":"một lần nữa tung ra bảy loại cổ bảo liên hợp với nhau phát huy ra uy lực"}]},"nguon":["@c0775"]},{"id":"cu-vien-co-quai","name":"Cự viên cổ quái","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Cự viên cổ quái là linh thú của Hàn Lập, cao hơn hai mươi trượng, toàn thân đen nhánh, mắt đỏ hồng. Xuất hiện lần đầu tại chiến trường Thiên Nam, hít sạch thi khí và phun ánh sáng vàng tiêu diệt hàng trăm luyện thi, khiến Ba Thi vương Kết Đan kỳ hoảng sợ.","detail":"Cự viên cổ quái bất ngờ xuất hiện giữa ngân quang trên chiến trường Thiên Nam. Thân hình cao hơn hai mươi trượng, toàn thân đen nhánh, bộ lông dường như mới phát triển, đôi mắt đỏ hồng. Hàn Lập đứng trên vai cự viên điều khiển. Cự viên dùng chiếc mũi to lớn hít nhẹ một cái đã hấp thu toàn bộ thi khí hắc vụ của hàng ngàn đồng giáp thi, sau đó phun ra ánh sáng vàng cuốn sạch thi khí trên thân luyện thi, khiến hàng trăm con hóa thành tro bụi. Sự xuất hiện của cự viên khiến Ba Thi vương Kết Đan kỳ hoảng sợ.","congNang":["Hít hấp thu toàn bộ thi khí hắc vụ của hàng ngàn đồng giáp thi chỉ bằng một hơi hít nhẹ @c0775","Phun ánh sáng vàng cuốn sạch thi khí trên thân luyện thi, khiến hàng trăm con hóa tro bụi @c0775"],"hinhDang":"Cao hơn hai mươi trượng, toàn thân đen nhánh, bộ lông mới phát triển, mắt đỏ hồng","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0775","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0775","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện trên chiến trường Thiên Nam","text":"Cự viên cổ quái bất ngờ xuất hiện giữa ngân quang, hít sạch thi khí hàng ngàn đồng giáp thi rồi phun ánh sáng vàng quét sạch hàng trăm luyện thi hóa tro bụi, đảo ngược cục diện chiến trường. Hàn Lập đứng trên vai cự viên.","anchor":"một con cự viên, cao hơn hai mươi trượng, toàn thân đen nhánh, bộ lông dường như mới phát triển"}]},"nguon":["@c0775"],"uyLuc":"Chỉ một hơi hít và một lần phun ánh sáng vàng đã hấp thu toàn bộ thi khí hàng ngàn đồng giáp thi và tiêu diệt hàng trăm luyện thi, khiến Ba Thi vương Kết Đan kỳ hoảng sợ.","dacDiem":"Cao hơn hai mươi trượng, toàn thân đen nhánh, bộ lông dường như mới phát triển, mắt đỏ hồng."},{"id":"cuu-tran-co-dang","name":"Cửu trản cổ đăng","aliases":["Nguyên Minh Đăng","chủ đăng","cửu trản cổ đăng"],"cn":"九盞古燈","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nữ tử họ Nhạc","Hàn Lập","Mộ Lan tộc"],"trangThai":"đã trả lại Mộ Lan tộc","blurb":"Cửu trản cổ đăng là truyền thừa chi bảo của bộ tộc Mộ Lan, do nữ tử họ Nhạc canh giữ trên chiến trường. Cổ đăng chín ngọn có thể phóng đăng diễm thiêu hủy mục tiêu tức thì trong phạm vi hơn ba mươi trượng, đồng thời phá được ẩn nặc thần thông, phát hiện người tàng hình. Sau khi Hàn Lập đoạt được, đã đàm phán đổi lấy trân hi tài liệu rồi trả lại cho Mộ Lan thần sư.","detail":"Cửu trản cổ đăng là pháp bảo cổ đăng chín ngọn, được xác nhận là truyền thừa chi bảo của thần sư bộ tộc Mộ Lan. Mỡ đèn hữu hạn, tại thời điểm giao chiến còn khoảng một nửa. Trên chiến trường Mộ Lan, nữ tử họ Nhạc canh giữ pháp bảo này đã phát hiện Hàn Lập đang tàng hình tiếp cận, bắt đăng diễm từ cổ đăng ném ra xa hơn ba mươi trượng để thiêu hủy mục tiêu (@c0777). Hàn Lập sau đó dùng Khôi Lỗi nghi binh đánh lừa nữ tử họ Nhạc, thừa lúc phân tâm thi triển Lôi Độn Thuật lẻn tới sát và đoạt lấy cổ đăng (@c0778). Về sau, Mộ Lan thần sư đòi lại truyền thừa chi bảo; Hàn Lập đàm phán đổi lấy trân hi tài liệu rồi trả lại, nhận định giá trị pháp bảo này đáng kể (@c0780).","congNang":["Phóng đăng diễm thiêu hủy mục tiêu tức thì trong phạm vi hơn ba mươi trượng @c0777","Phát hiện người tàng hình, phá ẩn nặc thần thông trong phạm vi hơn mười trượng @c0777","Triệu hồi yêu cầm (thanh điểu)","Phát đăng diễm thiêu đốt"],"dacDiem":"Mỡ đèn hữu hạn","chuSoHuu":[{"ten":"Nữ tử họ Nhạc","tuChuong":"@c0777","denChuong":"","cachCoDuoc":"Canh giữ trên chiến trường","trangThai":"dang-dung"},{"ten":"Mộ Lan tộc","tuChuong":"@c0774","denChuong":"@c0778","cachCoDuoc":"Đàm phán lấy lại từ Hàn Lập bằng trân hi tài liệu","trangThai":"dang-co"},{"ten":"Hàn Lập","tuChuong":"@c0778","denChuong":"@c0780","cachCoDuoc":"Cướp được trong trận chiến","trangThai":"da-tra-lai"}],"tabs":{"tienTrinh":[{"chuong":"@c0777","loai":"dùng","importance":"major","giaiDoan":"Thiêu hủy Hàn Lập tàng hình","text":"Nữ tử họ Nhạc phát hiện Hàn Lập tàng hình tiếp cận, bắt đăng diễm từ cổ đăng ném ra hơn ba mươi trượng, thiêu hủy đối phương thành tro bụi trong nháy mắt.","anchor":"một tay nhanh như chớp từ một trản cổ đăng bắt ra một đóa đăng diễm"},{"chuong":"@c0778","loai":"đổi chủ","importance":"major","giaiDoan":"Bị Hàn Lập đoạt","text":"Hàn Lập dùng Khôi Lỗi nghi binh đánh lừa nữ tử họ Nhạc, thừa lúc phân tâm dùng Lôi Độn Thuật lẻn tới sát, phóng bàn tay hắc hồng đoạt chủ đăng và dùng âm hỏa diệt đăng diễm. Tám trản còn lại tắt ngấm hóa linh khí, thanh điểu mất nguồn lực biến mất.","anchor":"cửu trản cổ đăng vẫn bất diệt, cho dù bất kỳ người nào vừa nhìn đều biết trong đó có chỗ quỷ dị"},{"chuong":"@c0780","loai":"doi-chu","importance":"major","giaiDoan":"Trả lại Mộ Lan tộc","text":"Mộ Lan thần sư đòi lại truyền thừa chi bảo. Hàn Lập đàm phán đổi lấy trân hi tài liệu rồi trả lại, nhận định giữ vật này chỉ mang họa.","anchor":"nhất kiện truyền thừa chi bảo của Mộ Lan tộc “Nguyên minh đăng”"}]},"nguon":["@c0777","@c0778","@c0780"],"uyLuc":"Đăng diễm bắt ra ném xa hơn ba mươi trượng, thiêu hủy mục tiêu thành tro bụi trong nháy mắt, kể cả người đang thi triển tàng hình thuật @c0777"},{"id":"phu-nhat-phi-nhin-thien","name":"Phù Nhất Phi Nhìn Thiên","category":"khac","categoryLabel":"Phù lục","soHuu":["Long Hàm"],"trangThai":"da-dung","blurb":"Phù lục do Long Hàm phóng ra, hóa kim sắc quang cầu nổ trên không, dùng làm tín hiệu ngừng chiến.","detail":"Long Hàm phóng phù này sau khi quyết định ngưng chiến, hóa thành kim sắc quang cầu nổ trên không trung làm tín hiệu cho toàn quân dừng tay.","nguon":["@c0779"]},{"id":"thien-am-lo","name":"Thiên Âm Lộ","cn":"天陰露","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Chất liệu mà Nam Cung Uyển thường xuyên thu thập tại tiểu sơn gần động phủ để tu luyện Luân Hồi Quyết.","detail":"Thiên Âm Lộ là nguyên liệu cần thiết cho việc tu luyện Luân Hồi Quyết. Nam Cung Uyển thường xuyên đi tới tiểu sơn gần động phủ Lạc Vân Tông để thu thập, và chính trong một lần như vậy đã bị hắc bào nam tử phục kích.","nguon":["@c0781"]},{"id":"ngoc-gian-do-mau","name":"Ngọc giản đỏ như máu","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hắc bào nam tử"],"trangThai":"da-huy","blurb":"Ngọc giản do hắc bào nam tử ném lại sau khi tấn công Nam Cung Uyển, chứa nội dung yêu cầu Hàn Lập mang Kim Lôi Trúc tới Huyền Thiên phong. Đã bị Hàn Lập đốt bằng tử hỏa.","detail":"Ngọc giản đỏ như máu, không quá chú tâm luyện chế. Nội dung yêu cầu Hàn Lập mang Kim Lôi Trúc pháp bảo đi Huyền Thiên phong gặp hắc bào nam tử. Hàn Lập xem xong tức giận phát tử hỏa đốt tan thành khói.","nguon":["@c0781"]},{"id":"ngoc-gian-nam-cung-uyen","name":"Ngọc giản của Nam Cung Uyển","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Ngọc giản do Nam Cung Uyển trước khi tự phong ấn lưu lại, chỉ đích danh giao cho Hàn Lập. Nội dung chưa tiết lộ nhưng khiến Hàn Lập vừa lo vừa mừng.","detail":"Ngọc giản do Nam Cung Uyển để lại cho Hàn Lập trước khi tự phong ấn bằng Luân Hồi Quyết. Trình sư huynh không dám xem vì trên ngọc giản có thể phát hiện dấu vết bị người khác xem qua. Nội dung khiến Hàn Lập biểu hiện vừa lo lắng vừa vui mừng.","nguon":["@c0781"]},{"id":"ba-muoi-sau-phi-kiem","name":"Ba mươi sáu khẩu phi kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"đang luyện chế","blurb":"Ba mươi sáu khẩu phi kiếm là thành phần cốt lõi của Tiểu Canh Kiếm Trận. Hàn Lập bế quan luyện Canh Tinh vào ba mươi sáu khẩu phi kiếm này nhằm hoàn thiện kiếm trận có uy lực đối phó tu sĩ Nguyên Anh Hậu Kỳ.","detail":"Trong quá trình bế quan, Hàn Lập dùng nguyên anh chi hỏa nung chảy Canh Tinh nguyên thạch thành bán thấu minh dịch thể, loại bỏ tạp chất, sau đó trộn bột phấn ngân xám phụ trợ và đánh pháp quyết để luyện hóa Canh Tinh vào ba mươi sáu khẩu phi kiếm. Đây là bước then chốt để hoàn thành Tiểu Canh Kiếm Trận — đòn sát thủ tối hậu có thể đấu ngang tu sĩ Nguyên Anh Hậu Kỳ. Ba mươi sáu khẩu phi kiếm đóng vai trò trận cơ của kiếm trận, chỉ khi được dung hợp Canh Tinh mới phát huy toàn bộ uy lực.","congNang":["Thành phần cốt lõi cấu thành Tiểu Canh Kiếm Trận, đòn sát thủ tối hậu có thể đấu ngang tu sĩ Nguyên Anh Hậu Kỳ @c0782"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0782","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"đang luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c0782","loai":"dùng","importance":"major","giaiDoan":"Bắt đầu luyện Canh Tinh vào phi kiếm","text":"Hàn Lập bế quan dùng nguyên anh chi hỏa nung chảy Canh Tinh nguyên thạch, loại tạp chất, trộn bột phấn ngân xám rồi đánh pháp quyết luyện vào ba mươi sáu khẩu phi kiếm để hoàn thành Tiểu Canh Kiếm Trận.","anchor":"số phi đao trước người hơn ba thước đang trôi nổi bất động"}]},"nguon":["@c0782"],"uyLuc":"Khi được luyện hóa Canh Tinh và triển khai thành Tiểu Canh Kiếm Trận, có uy lực đối phó tu sĩ Nguyên Anh Hậu Kỳ.","dacDiem":"Cần trải qua quá trình luyện hóa Canh Tinh nguyên thạch bằng nguyên anh chi hỏa, loại tạp chất, trộn bột phấn ngân xám phụ trợ rồi dung nhập vào phi kiếm mới phát huy được uy lực kiếm trận."},{"id":"van-nam-linh-dich","name":"Vạn năm linh dịch","cn":"万年灵液","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Cực phẩm","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Linh dược quý hiếm vạn năm, có công năng hồi phục pháp lực trong thời gian ngắn.","detail":"Hàn Lập dùng vạn năm linh dịch để kịp thời hồi phục pháp lực tiêu hao khi luyện chế 36 thanh Thanh Trúc Phong Vân Kiếm trộn Canh Tinh liên tục nhiều ngày không nghỉ. Nếu không có vạn năm linh dịch, không thể kiên trì nổi quá trình luyện chế cường độ cao này.","congNang":["Hồi phục pháp lực nhanh chóng trong thời gian ngắn"],"nguon":["@c0783"]},{"id":"tam-lua-ho-than-nam-cung-uyen","name":"Tấm lụa hộ thân (Nam Cung Uyển tặng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Hộ thân chi bảo mỏng bóng loáng do Nam Cung Uyển tặng Hàn Lập, phát bạch quang khi kích hoạt, được dùng dựng thêm tầng bảo hộ trước khi vào trận nguy hiểm.","detail":"Tấm lụa mỏng bóng loáng phảng phất như khăn, là hộ thân chi bảo do Nam Cung Uyển tặng Hàn Lập ngày trước. Khi lấy ra bạch quang hiện lên. Hàn Lập dùng nó dựng thêm một tầng bảo hộ trước khi bước vào Truyền Tống Trận đến tiểu đảo đối mặt hắc bào thanh niên. Trước khi kích hoạt, Hàn Lập lặng lẽ vuốt ve tấm lụa, thể hiện tình cảm sâu nặng với người tặng.","congNang":["Hộ thân phòng hộ, tạo thêm tầng bảo vệ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0784","denChuong":"","cachCoDuoc":"Nam Cung Uyển tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0784","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu sử dụng trong truyện","text":"Hàn Lập lấy ra dựng thêm tầng bảo hộ trước khi bước vào Truyền Tống Trận đến tiểu đảo đối mặt hắc bào thanh niên.","anchor":"Cái khăn này đúng là hộ thân chi bảo ngày đó Nam Cung Uyển tặng hắn"}]},"nguon":["@c0784"]},{"id":"that-long-thung","name":"Thất long thung","cn":"七龙桶","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Phỏng chế phẩm (không bằng nửa chính phẩm)","soHuu":["Hắc bào thanh niên"],"trangThai":"bi-huy","blurb":"Thất long thung là một pháp bảo tấn công gồm bảy quang trụ, mỗi trụ mang một ngân giao có thể đồng loạt phun ra bảy đạo ngân quang cực mạnh. Đây là phỏng chế phẩm, uy lực không bằng một nửa chính phẩm, bị Ngân Nguyệt dùng Yêu Đan phản chế và hủy diệt hoàn toàn.","detail":"Thất long thung được hắc bào thanh niên sử dụng trong chiến đấu. Khi phát động, bảy con ngân giao trên bảy quang trụ đồng loạt phun ra bảy đạo ngân quang tấn công, uy lực đủ mạnh để đánh thủng tử hỏa võng của Tử Vân Đâu và áp đảo sương mù cẩm mạt. Tuy nhiên, Ngân Nguyệt nhận ra đây chỉ là phỏng chế phẩm, không bằng nửa chính phẩm Thất long thung, bèn dùng Yêu Đan bạo liệt thành bột phấn thấm vào thủy mạc của Bạch Lân Thuẫn; thủy mạc phản xạ toàn bộ ngân quang theo đường cũ với tốc độ gấp ba, hủy diệt cả bảy quang trụ cùng ngân giao, khiến pháp bảo bị tiêu diệt hoàn toàn.","congNang":["Bảy ngân giao trên bảy quang trụ đồng loạt phun ra bảy đạo ngân quang tấn công cực mạnh, có thể đánh thủng tử hỏa võng và áp đảo sương mù cẩm mạt @c0785"],"dacDiem":"Phỏng chế phẩm, không bằng nửa chính phẩm Thất long thung.","chuSoHuu":[{"ten":"Hắc bào thanh niên","tuChuong":"@c0785","denChuong":"","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0785","loai":"dùng","importance":"major","giaiDoan":"Phát động và bị phản chế","text":"Hắc bào thanh niên phát động Thất long thung, bảy ngân giao phun ngân quang đánh thủng tử hỏa võng và sương mù. Ngân Nguyệt nhận ra là phỏng chế phẩm, dùng Yêu Đan phản xạ ngân quang ngược lại hủy diệt toàn bộ.","anchor":"Bảy cái quang trụ và ngân giao trong nháy mắt đã bị ngân quang bao phủ, hóa thành hư không"}]},"nguon":["@c0785"],"uyLuc":"Bảy đạo ngân quang đồng loạt phóng ra đủ sức đánh thủng tử hỏa võng của Tử Vân Đâu và áp đảo sương mù phòng ngự."},{"id":"cam-mat-co-bao","name":"Cẩm mạt Cổ Bảo","category":"phap-bao","categoryLabel":"Pháp bảo (Cổ Bảo)","phamCap":"Cổ Bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Tấm khăn Cổ Bảo của Hàn Lập, ném ra hóa thành sương mù trắng mịt mờ dùng làm tầng phòng hộ thứ hai. Bị ngân quang Thất long thung áp đảo.","detail":"Hàn Lập ném tấm cẩm mạt ra ngoài, hóa thành một mảnh sương mù trắng mịt mờ bao bọc phòng hộ. Là tầng phòng hộ giữa, bên ngoài Bạch Lân Thuẫn thủy mạc. Bị ngân quang áp đảo.","congNang":["Tạo sương mù trắng phòng hộ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0785","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0785","loai":"dùng","importance":"normal","giaiDoan":"Phòng hộ trong trận chiến","text":"Hàn Lập ném cẩm mạt ra hóa sương mù trắng làm tầng phòng hộ thứ hai, bị ngân quang áp đảo.","anchor":"Tay kia thì cầm tấm khăn nó ném ra ngoài hóa thành một mảnh sương mù màu trắng mịt mờ"}]},"nguon":["@c0785"]},{"id":"hac-phu","name":"Hắc phủ","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Hắc bào thanh niên"],"trangThai":"bi-huy","blurb":"Búa đen của hắc bào thanh niên, có phù văn ẩn hiện và mặt quỷ điêu khắc trên cán. Phóng to sáu bảy trượng chém vào hư không nhưng bị kim ti Đại Canh Kiếm Trận chém đôi.","detail":"Hắc bào thanh niên tế xuất hắc phủ, búa phóng to sáu bảy trượng chém vào hư không cố phá kiếm trận. Tuy nhiên bị một đạo kim ti vô hình chém thành hai đoạn rơi xuống.","congNang":["Phóng to tấn công diện rộng"],"chuSoHuu":[{"ten":"Hắc bào thanh niên","tuChuong":"@c0785","denChuong":"","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0785","loai":"dùng","importance":"normal","giaiDoan":"Bị kiếm trận chém đôi","text":"Hắc bào thanh niên tế xuất hắc phủ phóng to sáu bảy trượng chém vào hư không, bị kim ti Đại Canh Kiếm Trận chém thành hai đoạn.","anchor":"Ầm một tiếng, cái búa lớn bị chém thành hai đoạn, từ không trung rơi xuống"}]},"nguon":["@c0785"]},{"id":"huyet-loi-tu","name":"Huyết Lôi Tử","cn":"血雷子","category":"khac","categoryLabel":"Vật phẩm ma đạo","phamCap":"Hiếm (Ma Môn)","soHuu":["Hắc bào thanh niên"],"trangThai":"Đã bị tiêu diệt","blurb":"Vật phẩm ma đạo cực hiếm, luyện từ tài liệu ô uế, chuyên dùng ô nhiễm pháp bảo chánh đạo khiến linh tính tổn thất.","detail":"Hắc bào thanh niên ném hơn mười viên Huyết Lôi Tử tích lũy gần trăm năm. Khi bị phá vỡ tỏa ra huyết vụ hắc hồng sắc ô uế, pháp bảo chánh đạo trúng phải cần dùng anh hỏa bồi luyện mấy ngày mới khôi phục. Tại Ma Môn cũng rất hiếm, nguyên liệu thưa thớt, xác suất luyện chế thấp hơn lôi châu, thường dùng trong đối kháng đại quy mô chống kiếm trận. Toàn bộ bị Ích Tà Thần Lôi triệt tiêu sạch sẽ.","congNang":["Ô nhiễm pháp bảo chánh đạo, làm linh tính tổn thất, cần anh hỏa bồi luyện mấy ngày mới khôi phục"],"dacDiem":"Luyện từ tài liệu cực kỳ ô uế dơ bẩn, hiếm hơn lôi châu, xác suất luyện chế rất thấp","tabs":{"tienTrinh":[{"chuong":"@c0786","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng và bị tiêu diệt","text":"Hắc bào thanh niên ném hơn mười viên nhằm ô nhiễm phi kiếm Kim Lôi Trúc của Hàn Lập, nhưng huyết vụ bị Ích Tà Thần Lôi tự động kích phát triệt tiêu hoàn toàn.","anchor":"dùng mấy cái tài liệu cực kỳ ô uế dơ bẩn gì đó luyện chế thành"}]},"nguon":["@c0786"]},{"id":"me-tien-chung","name":"Mê Tiên Chung","cn":"迷仙鐘","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo tông môn","soHuu":["Lão giả họ Vưu"],"trangThai":"nguyên vẹn","blurb":"Tông môn chí bảo hình hoàng tiểu chung, có thể bảo đảm thoát thân trước đối thủ mạnh hơn cả cảnh giới.","detail":"Chí bảo tông môn do lão giả họ Vưu mang theo khi tới cứu viện truy kích ma tu. Hình dáng hoàng tiểu chung. Được coi là bảo đảm để nhóm Nguyên Anh Sơ Kỳ dám đối đầu ma tu Nguyên Anh Trung Kỳ, chủ yếu dùng phòng thủ và thoát thân.","congNang":["Phòng thủ, bảo đảm thoát thân trước đối thủ cấp cao hơn"],"chuSoHuu":[{"ten":"Lão giả họ Vưu","tuChuong":"@c0788","denChuong":"","cachCoDuoc":"Chí bảo tông môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0788","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Lão giả họ Vưu mang theo tông môn chí bảo Mê Tiên Chung trong đoàn sáu tu sĩ truy kích ma tu, rút ra chuẩn bị chiến đấu nhưng không cần dùng.","anchor":"Vưu huynh đem theo tông môn chí bảo Mê Tiên Chung"}]},"nguon":["@c0788"]},{"id":"am-la-tong-truong-lao-lenh-bai","name":"Âm La Tông trưởng lão lệnh bài","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Cổ bảo","phamCap":"Cổ bảo","soHuu":["Ngân phát lão giả"],"trangThai":"nguyên vẹn","blurb":"Lệnh bài đen thui cực kỳ âm hàn, trên mặt có phù chú văn mật và cổ văn chữ La, cũng là cổ bảo có uy lực.","detail":"Lệnh bài trưởng lão Âm La Tông, đen thui tỏa khí âm hàn, nhiều phù chú văn mật, chính giữa có cổ văn chữ La. Do ma tu hắc bào lưu lại sau khi bị tiêu diệt. Hàn Lập ném cho Trình đạo hữu làm chứng cứ đã diệt trưởng lão Âm La Tông. Bản thân cũng là một kiện cổ bảo có uy lực.","congNang":["Lệnh bài thân phận trưởng lão Âm La Tông","Cổ bảo có uy lực (chưa rõ cụ thể)"],"hinhDang":"Lệnh bài đen thui, phù chú văn mật trên mặt, cổ văn chữ La ở giữa","chuSoHuu":[{"ten":"Hắc bào thanh niên","tuChuong":"@c0788","denChuong":"@c0788","cachCoDuoc":"Lệnh bài trưởng lão","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0788","denChuong":"@c0788","cachCoDuoc":"Thu từ ma tu bị diệt","trangThai":"da-cho"},{"ten":"Ngân phát lão giả","tuChuong":"@c0788","denChuong":"","cachCoDuoc":"Hàn Lập ném cho làm chứng cứ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0788","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập ném cho Trình đạo hữu","text":"Hàn Lập ném lệnh bài đen cho Trình đạo hữu làm chứng cứ đã diệt trưởng lão Âm La Tông.","anchor":"Âm La Tông trưởng lão lệnh bài. Cũng là nhất kiện Cổ Bảo hơi có chút uy lực"}]},"nguon":["@c0788"]},{"id":"thuong-co-hoa-thiem-yeu-dan","name":"Thượng cổ hỏa thiềm yêu đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược / Nội đan","phamCap":"Không rõ","soHuu":[],"trangThai":"chua-co","blurb":"Nội đan của Thượng cổ hỏa thiềm thú sinh sống trong Trụy Ma Cốc, được Hàn Lập nhắm đến như ngoại vật dễ đắc thủ nhất có khả năng hóa giải Phong Hồn Ấn trên người Nam Cung Uyển, với xác suất thành công khoảng 50%.","detail":"Thượng cổ hỏa thiềm yêu đan là nội đan của Thượng cổ hỏa thiềm thú, một loài yêu thú cư ngụ trong Trụy Ma Cốc. Trong số các loại ngoại vật có thể hóa giải Phong Hồn Ấn, đan dược này được Hàn Lập đánh giá là dễ đắc thủ nhất. Hàn Lập quyết định thâm nhập Trụy Ma Cốc để thu lấy nội đan này nhằm giải trừ Phong Hồn Ấn cho Nam Cung Uyển (@c0789). Xác suất phá ấn thành công vào khoảng 50%; ngay cả khi thất bại, nội đan vẫn có thể giảm bớt tác dụng của độc chú, giúp tranh thủ thêm thời gian.","congNang":["Hóa giải Phong Hồn Ấn với khoảng 50% khả năng thành công (@c0789)","Nếu phá ấn thất bại, vẫn có thể giảm bớt tác dụng độc chú của Phong Hồn Ấn, tranh thủ thêm thời gian (@c0789)"],"nguon":["@c0789"],"tabs":{"tienTrinh":[{"chuong":"@c0789","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập xác định mục tiêu","text":"Hàn Lập quyết định vào Trụy Ma Cốc lấy nội đan Thượng cổ hỏa thiềm thú để giải Phong Hồn Ấn cho Nam Cung Uyển, với 50% khả năng thành công.","anchor":"loại phương pháp lợi dụng ngoại vật này chỉ có phân nửa khả năng có thể hóa giải phong hồn ấn"}]}},{"id":"cu-dinh-phap-khi","name":"Cự đinh pháp khí","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Pháp khí tự luyện","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Mười mấy cái cự đinh pháp khí lớn nhỏ do Hàn Lập tự luyện, có thể tùy ý biến ảo.","detail":"Hàn Lập ra phường thị mua tài liệu luyện khí, luyện trong luyện khí thất hơn nửa tháng tạo ra mười mấy cái cự đinh pháp khí lớn nhỏ có thể tùy ý biến ảo. Mang đến thạch thất nơi Thi Tiêu nằm để chuẩn bị thao tác.","congNang":["Biến ảo linh hoạt theo ý muốn"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0790","denChuong":"","cachCoDuoc":"Tự luyện","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0790","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tự luyện và mang đến chỗ Thi Tiêu","text":"Hàn Lập luyện hơn nửa tháng tạo mười mấy cái cự đinh pháp khí biến ảo, mang đến thạch thất nơi Thi Tiêu cùng kim phù ngọc hạp.","anchor":"trong tay lại có mười mấy cái cự đinh pháp khí lớn nhỏ, tùy ý biến ảo"}]},"capNhatToi":"@c0790","nguon":["@c0790"]},{"id":"ngan-lien","name":"Ngân Liên","cn":"银链","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực kiên cố)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Sợi dây bạc cực kỳ kiên cố từng quấn kín Thi Tiêu, linh hoạt như rắn sống, bề mặt khắc vô số phù văn bí ẩn nhỏ bé khó phát hiện.","detail":"Ngân Liên quấn kín thân xác Thi Tiêu trong thạch thất. Cực kỳ kiên cố — ngay cả Thanh Trúc Phong Vân Kiếm đã trộn Canh Tinh chém vào cũng chỉ tạo lỗ bằng hạt gạo, phải chém liên tục lâu mới chặt đứt được. Khi bị chặt đứt, linh hoạt như rắn sống, hóa ngân quang rơi vào tay Hàn Lập. Bề mặt trơn bóng nhưng khắc rất nhiều phù văn nhỏ bé, nhìn bình thường không thể phát hiện, khiến Hàn Lập khiếp sợ.","congNang":["Trói chặt thi thể, chịu được Thanh Trúc Phong Vân Kiếm trộn Canh Tinh @c0791"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0791","denChuong":"","cachCoDuoc":"Chặt từ thân Thi Tiêu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0791","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập chặt đứt và thu về","text":"Hàn Lập dùng Thanh Trúc Phong Vân Kiếm đã trộn Canh Tinh chém Ngân Liên quấn quanh Thi Tiêu, cực khó cắt, chém lâu mới chặt đứt. Thu về tay phát hiện bề mặt khắc vô số phù văn bí ẩn.","anchor":"Nhìn bình thường thì không thể nào phát hiện ra được"}]},"capNhatToi":"@c0791","nguon":["@c0791"]},{"id":"co-sac-ngoc-ky-luyen-thi","name":"Cổ sắc ngọc ký (ngọc giản luyện thi)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản cổ sắc thu từ thần thức hắc bào thanh niên Âm La Tông, ghi hơn mười phương pháp luyện thi cùng phương pháp Thiên Tuyệt Ma Thi.","detail":"Ngọc giản có được từ thần thức hắc bào thanh niên (trưởng lão Âm La Tông). Bên trong ghi hơn mười loại phương pháp luyện thi do hắc bào thanh niên minh tranh ám đoạt rồi phục chế, kèm chú giải cải tiến. Đặc biệt ghi phương pháp Thiên Tuyệt Ma Thi — đỉnh cao luyện thi.","congNang":["Lưu trữ hơn mười phương pháp luyện thi và phương pháp Thiên Tuyệt Ma Thi @c0791"],"tabs":{"tienTrinh":[{"chuong":"@c0791","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lấy ra nghiên cứu","text":"Hàn Lập lấy ngọc giản ra nghiên cứu, phát hiện hơn mười phương pháp luyện thi và phương pháp Thiên Tuyệt Ma Thi.","anchor":"Bên trong ghi lại hơn mười loại phương pháp luyện thi"}]},"capNhatToi":"@c0791","nguon":["@c0791"]},{"id":"dinh-bac-kim-ho","name":"Đinh bạc to lớn và kim hồ","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Cây đinh bạc to lớn kết hợp kim hồ dùng để ghim trấn áp thi thể, kim hồ có thể biến thành lưới vàng ngăn nguyên thần nhập xác.","detail":"Hàn Lập dùng cây đinh bạc to lớn, thi triển chú ngữ phát hào quang bạc, hai tay phóng hơn mười đạo kim hồ bắn vào đinh. Sau đó hóa đinh thành ngân quang ghim vào tứ chi và chỗ yếu hại của Thi Tiêu. Kim hồ biến thành lưới vàng bao bọc Thi Tiêu, đánh bật nguyên thần ra khi nó định nhập xác.","nguon":["@c0791"]}]};
